'use client'

import { useEffect, useState } from 'react'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'

export type CatalogSearchOption = {
  id: string
  primary: string
  secondary?: string | null
  meta?: Record<string, string | null>
}

type CatalogSearchProps = {
  label: string
  placeholder: string
  emptyHint: string
  selected: CatalogSearchOption | null
  onSelect: (option: CatalogSearchOption | null) => void
  onSearch: (query: string) => Promise<CatalogSearchOption[]>
  allowCustom?: boolean
  customLabel?: string
  customValue?: string
  onCustomChange?: (value: string) => void
}

export function CatalogSearch({
  label,
  placeholder,
  emptyHint,
  selected,
  onSelect,
  onSearch,
  allowCustom = false,
  customLabel = 'Or enter custom',
  customValue = '',
  onCustomChange,
}: CatalogSearchProps) {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<CatalogSearchOption[]>([])
  const [searching, setSearching] = useState(false)
  const [open, setOpen] = useState(false)

  useEffect(() => {
    if (selected) {
      setQuery(selected.primary)
      return
    }
    if (!query.trim()) {
      setResults([])
      return
    }

    const handle = window.setTimeout(async () => {
      setSearching(true)
      try {
        const hits = await onSearch(query)
        setResults(hits)
        setOpen(true)
      } finally {
        setSearching(false)
      }
    }, 250)

    return () => window.clearTimeout(handle)
  }, [query, onSearch, selected])

  function pick(option: CatalogSearchOption) {
    onSelect(option)
    onCustomChange?.('')
    setQuery(option.primary)
    setOpen(false)
  }

  function clearSelection() {
    onSelect(null)
    setQuery('')
    setResults([])
  }

  return (
    <div className="space-y-2">
      <Label>{label}</Label>
      <div className="relative">
        <Input
          value={selected ? selected.primary : query}
          placeholder={placeholder}
          onChange={(e) => {
            if (selected) clearSelection()
            setQuery(e.target.value)
          }}
          onFocus={() => {
            if (!selected && results.length) setOpen(true)
          }}
          autoComplete="off"
        />
        {selected ? (
          <button
            type="button"
            className="absolute top-1/2 right-2 -translate-y-1/2 text-xs text-muted-foreground hover:text-foreground"
            onClick={clearSelection}
          >
            Clear
          </button>
        ) : null}
        {open && !selected && results.length > 0 ? (
          <ul
            className="absolute z-20 mt-1 max-h-48 w-full overflow-auto rounded-md border bg-background shadow-md"
            role="listbox"
          >
            {results.map((option) => (
              <li key={option.id}>
                <button
                  type="button"
                  className="w-full px-3 py-2 text-left text-sm hover:bg-muted"
                  onClick={() => pick(option)}
                >
                  <span className="font-medium">{option.primary}</span>
                  {option.secondary ? (
                    <span className="mt-0.5 block text-xs text-muted-foreground">
                      {option.secondary}
                    </span>
                  ) : null}
                </button>
              </li>
            ))}
          </ul>
        ) : null}
      </div>
      <p className="text-xs text-muted-foreground">
        {searching ? 'Searching catalog…' : emptyHint}
      </p>
      {allowCustom && onCustomChange ? (
        <div className="space-y-1">
          <Label className="text-xs text-muted-foreground">{customLabel}</Label>
          <Input
            value={customValue}
            placeholder="Free-text if not in catalog"
            onChange={(e) => {
              if (selected) clearSelection()
              onCustomChange(e.target.value)
            }}
            disabled={Boolean(selected)}
          />
        </div>
      ) : null}
    </div>
  )
}

// components/subject/clinical-profile/LibrarySearchCombobox.tsx
// Reusable combobox for searching Phase 6B.1 pathology or medication libraries.
// Calls server actions directly via useTransition — no API route needed.
// Pattern: debounced input → server search → dropdown list → onSelect callback.

'use client'

import { useState, useTransition, useCallback, useRef, useEffect, type ReactNode } from 'react'
import { Search, Loader2, X } from 'lucide-react'
import {
  searchPathologyLibrary,
  searchMedicationLibrary,
  searchAllergenLibrary,
  type PathologyResult,
  type MedicationResult,
  type AllergenResult,
} from '@/lib/subject/clinical-profile/library-search'

// ---------------------------------------------------------------------------
// Pathology combobox
// ---------------------------------------------------------------------------

type PathologyComboboxProps = {
  value: { id: string; label: string } | null
  onSelect: (result: PathologyResult | null) => void
  placeholder?: string
  disabled?: boolean
}

export function PathologyCombobox({
  value,
  onSelect,
  placeholder = 'Search pathology library…',
  disabled,
}: PathologyComboboxProps) {
  return (
    <LibraryCombobox
      value={value}
      onSelect={onSelect}
      searchFn={searchPathologyLibrary}
      renderResult={(r: PathologyResult) => ({
        id: r.pathology_id,
        label: r.common_name,
        sublabel: [r.medical_name, r.icd10_code].filter(Boolean).join(' · '),
        badge: r.system,
      })}
      placeholder={placeholder}
      disabled={disabled}
    />
  )
}

// ---------------------------------------------------------------------------
// Medication combobox
// ---------------------------------------------------------------------------

type MedicationComboboxProps = {
  value: { id: string; label: string } | null
  onSelect: (result: MedicationResult | null) => void
  placeholder?: string
  disabled?: boolean
}

export function MedicationCombobox({
  value,
  onSelect,
  placeholder = 'Search medication library…',
  disabled,
}: MedicationComboboxProps) {
  const [searchNotice, setSearchNotice] = useState<string | null>(null)

  const searchMedications = useCallback(async (q: string) => {
    try {
      const { results, error } = await searchMedicationLibrary(q)
      setSearchNotice(error ?? null)
      return results
    } catch (err) {
      console.error('[MedicationCombobox] search failed', err)
      setSearchNotice('Medication library search failed.')
      return []
    }
  }, [])

  return (
    <div className="space-y-1">
      <LibraryCombobox
        value={value}
        onSelect={onSelect}
        searchFn={searchMedications}
        renderResult={(r: MedicationResult) => ({
          id: r.medication_id,
          label: r.medication_name,
          sublabel: [r.brand_name, r.drug_class].filter(Boolean).join(' · '),
          badge: r.route ?? undefined,
        })}
        placeholder={placeholder}
        disabled={disabled}
        emptyHint="No matches found. Enter a custom medication name below."
      />
      {searchNotice ? (
        <p className="text-xs text-amber-700 dark:text-amber-400" role="status">
          {searchNotice}
        </p>
      ) : null}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Allergen combobox (free text + vocabulary suggestions)
// ---------------------------------------------------------------------------

type AllergenComboboxProps = {
  allergen: string
  onAllergenChange: (value: string) => void
  onPick?: (result: AllergenResult) => void
  placeholder?: string
  disabled?: boolean
}

export function AllergenCombobox({
  allergen,
  onAllergenChange,
  onPick,
  placeholder = 'Search or type allergen…',
  disabled,
}: AllergenComboboxProps) {
  return (
    <FreeTextLibraryCombobox<AllergenResult>
      textValue={allergen}
      onTextChange={onAllergenChange}
      searchFn={searchAllergenLibrary}
      renderResult={(r) => ({
        id: r.vocabulary_id,
        label: r.display_name,
        sublabel: [r.category, r.allergen_type].filter(Boolean).join(' · '),
        badge: r.allergen_type ?? undefined,
      })}
      onPick={(result) => {
        onAllergenChange(result.display_name)
        onPick?.(result)
      }}
      placeholder={placeholder}
      disabled={disabled}
      emptyHint="No library match. Keep typing to use a custom allergen name."
    />
  )
}

// ---------------------------------------------------------------------------
// Generic combobox implementation
// ---------------------------------------------------------------------------

type RenderedResult = {
  id: string
  label: string
  sublabel?: string | null
  badge?: string
}

type LibraryComboboxProps<T> = {
  value: { id: string; label: string } | null
  onSelect: (result: T | null) => void
  searchFn: (query: string) => Promise<T[]>
  renderResult: (result: T) => RenderedResult
  placeholder: string
  disabled?: boolean
  emptyHint?: ReactNode
}

function LibraryCombobox<T>({
  value,
  onSelect,
  searchFn,
  renderResult,
  placeholder,
  disabled,
  emptyHint = 'No results found. You can enter a custom name below.',
}: LibraryComboboxProps<T>) {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<T[]>([])
  const [open, setOpen] = useState(false)
  const [isPending, startTransition] = useTransition()
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const containerRef = useRef<HTMLDivElement>(null)

  const runSearch = useCallback(
    (q: string) => {
      if (q.trim().length < 2) {
        setResults([])
        setOpen(false)
        return
      }
      startTransition(async () => {
        try {
          const data = await searchFn(q)
          setResults(Array.isArray(data) ? data : [])
          setOpen(true)
        } catch (err) {
          console.error('[LibraryCombobox] search failed', err)
          setResults([])
          setOpen(true)
        }
      })
    },
    [searchFn],
  )

  function handleInput(e: React.ChangeEvent<HTMLInputElement>) {
    const q = e.target.value
    setQuery(q)
    if (debounceRef.current) clearTimeout(debounceRef.current)
    debounceRef.current = setTimeout(() => runSearch(q), 280)
  }

  function handleSelect(result: T) {
    let rendered: RenderedResult
    try {
      rendered = renderResult(result)
    } catch (err) {
      console.error('[LibraryCombobox] renderResult failed', err)
      return
    }
    setQuery(rendered.label)
    setOpen(false)
    setResults([])
    onSelect(result)
  }

  function handleClear() {
    setQuery('')
    setResults([])
    setOpen(false)
    onSelect(null)
  }

  // Close dropdown on outside click
  useEffect(() => {
    function handler(e: MouseEvent) {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setOpen(false)
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [])

  // Show selected value label if no active query
  const displayValue = value && !query ? value.label : query

  return (
    <div ref={containerRef} className="relative">
      <div className="relative flex items-center">
        <Search className="pointer-events-none absolute left-2.5 h-3.5 w-3.5 text-muted-foreground" />
        <input
          type="text"
          value={displayValue}
          onChange={handleInput}
          onFocus={() => { if (results.length > 0) setOpen(true) }}
          placeholder={placeholder}
          disabled={disabled}
          className={[
            'w-full rounded-md border bg-background py-2 pl-8 pr-8 text-sm',
            'focus:outline-none focus:ring-2 focus:ring-ring/50',
            'disabled:cursor-not-allowed disabled:opacity-50',
          ].join(' ')}
        />
        {isPending && (
          <Loader2 className="absolute right-2.5 h-3.5 w-3.5 animate-spin text-muted-foreground" />
        )}
        {(value || query) && !isPending && (
          <button
            type="button"
            onClick={handleClear}
            className="absolute right-2.5 text-muted-foreground hover:text-foreground"
          >
            <X className="h-3.5 w-3.5" />
          </button>
        )}
      </div>

      {open && results.length > 0 && (
        <div className="absolute z-50 mt-1 w-full rounded-md border bg-background shadow-lg">
          <ul className="max-h-60 overflow-auto py-1">
            {results.map((result, index) => {
              let rendered: RenderedResult
              try {
                rendered = renderResult(result)
              } catch (err) {
                console.error('[LibraryCombobox] renderResult failed', err)
                return null
              }
              const rowKey = rendered.id || `row-${index}`
              return (
                <li key={rowKey}>
                  <button
                    type="button"
                    onClick={() => handleSelect(result)}
                    className="w-full px-3 py-2 text-left text-sm hover:bg-muted/50 focus:bg-muted/50 focus:outline-none"
                  >
                    <div className="flex items-start justify-between gap-2">
                      <div className="min-w-0">
                        <span className="font-medium">{rendered.label}</span>
                        {rendered.sublabel && (
                          <p className="mt-0.5 text-xs text-muted-foreground truncate">
                            {rendered.sublabel}
                          </p>
                        )}
                      </div>
                      {rendered.badge && (
                        <span className="shrink-0 rounded-full bg-muted px-1.5 py-0 text-[10px] text-muted-foreground capitalize">
                          {rendered.badge}
                        </span>
                      )}
                    </div>
                  </button>
                </li>
              )
            })}
          </ul>
        </div>
      )}

      {open && !isPending && results.length === 0 && query.trim().length >= 2 && (
        <div className="absolute z-50 mt-1 w-full rounded-md border bg-background px-3 py-2 text-xs text-muted-foreground shadow-lg">
          {emptyHint}
        </div>
      )}
    </div>
  )
}

type FreeTextLibraryComboboxProps<T> = {
  textValue: string
  onTextChange: (value: string) => void
  onPick: (result: T) => void
  searchFn: (query: string) => Promise<T[]>
  renderResult: (result: T) => RenderedResult
  placeholder: string
  disabled?: boolean
  emptyHint?: string
}

/** Library suggestions while keeping typed free text in sync (allergen field). */
function FreeTextLibraryCombobox<T>({
  textValue,
  onTextChange,
  onPick,
  searchFn,
  renderResult,
  placeholder,
  disabled,
  emptyHint = 'No results found. You can enter a custom name.',
}: FreeTextLibraryComboboxProps<T>) {
  const [query, setQuery] = useState(textValue)
  const [results, setResults] = useState<T[]>([])
  const [open, setOpen] = useState(false)
  const [isPending, startTransition] = useTransition()
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    setQuery(textValue)
  }, [textValue])

  const runSearch = useCallback(
    (q: string) => {
      if (q.trim().length < 2) {
        setResults([])
        setOpen(false)
        return
      }
      startTransition(async () => {
        const data = await searchFn(q)
        setResults(data)
        setOpen(true)
      })
    },
    [searchFn],
  )

  function handleInput(e: React.ChangeEvent<HTMLInputElement>) {
    const q = e.target.value
    setQuery(q)
    onTextChange(q)
    if (debounceRef.current) clearTimeout(debounceRef.current)
    debounceRef.current = setTimeout(() => runSearch(q), 280)
  }

  function handleSelect(result: T) {
    const rendered = renderResult(result)
    setQuery(rendered.label)
    setOpen(false)
    setResults([])
    onPick(result)
  }

  function handleClear() {
    setQuery('')
    onTextChange('')
    setResults([])
    setOpen(false)
  }

  useEffect(() => {
    function handler(e: MouseEvent) {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setOpen(false)
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [])

  return (
    <div ref={containerRef} className="relative">
      <div className="relative flex items-center">
        <Search className="pointer-events-none absolute left-2.5 h-3.5 w-3.5 text-muted-foreground" />
        <input
          type="text"
          value={query}
          onChange={handleInput}
          onFocus={() => {
            if (results.length > 0) setOpen(true)
          }}
          placeholder={placeholder}
          disabled={disabled}
          className={[
            'w-full rounded-md border bg-background py-2 pl-8 pr-8 text-sm',
            'focus:outline-none focus:ring-2 focus:ring-ring/50',
            'disabled:cursor-not-allowed disabled:opacity-50',
          ].join(' ')}
        />
        {isPending && (
          <Loader2 className="absolute right-2.5 h-3.5 w-3.5 animate-spin text-muted-foreground" />
        )}
        {query && !isPending && (
          <button
            type="button"
            onClick={handleClear}
            className="absolute right-2.5 text-muted-foreground hover:text-foreground"
          >
            <X className="h-3.5 w-3.5" />
          </button>
        )}
      </div>

      {open && results.length > 0 && (
        <div className="absolute z-50 mt-1 w-full rounded-md border bg-background shadow-lg">
          <ul className="max-h-60 overflow-auto py-1">
            {results.map((result) => {
              const rendered = renderResult(result)
              return (
                <li key={rendered.id}>
                  <button
                    type="button"
                    onClick={() => handleSelect(result)}
                    className="w-full px-3 py-2 text-left text-sm hover:bg-muted/50 focus:bg-muted/50 focus:outline-none"
                  >
                    <div className="flex items-start justify-between gap-2">
                      <div className="min-w-0">
                        <span className="font-medium">{rendered.label}</span>
                        {rendered.sublabel && (
                          <p className="mt-0.5 text-xs text-muted-foreground truncate">
                            {rendered.sublabel}
                          </p>
                        )}
                      </div>
                      {rendered.badge && (
                        <span className="shrink-0 rounded-full bg-muted px-1.5 py-0 text-[10px] text-muted-foreground capitalize">
                          {rendered.badge}
                        </span>
                      )}
                    </div>
                  </button>
                </li>
              )
            })}
          </ul>
        </div>
      )}

      {open && !isPending && results.length === 0 && query.trim().length >= 2 && (
        <div className="absolute z-50 mt-1 w-full rounded-md border bg-background px-3 py-2 text-xs text-muted-foreground shadow-lg">
          {emptyHint}
        </div>
      )}
    </div>
  )
}

'use server'

import { revalidatePath } from 'next/cache'
import { createServerClient } from '@/lib/supabase/server'
import { logAuditEvent } from '@/lib/audit/log'
import type { VisitLifecycleResult, VisitLifecycleRpcPayload } from '@/lib/actions/visit-lifecycle.types'

const UUID_REGEX = /^[\da-f]{8}(?:-[\da-f]{4}){3}-[\da-f]{12}$/i

/**
 * F-01 fix — transitions a visit from scheduled → checked_in.
 * Only applies to visits in 'scheduled' status; idempotent for already-active visits.
 */
export async function checkInVisit(input: {
  visitId: string
  visitPath: string
  studyPath: string
  subjectPath: string
}): Promise<VisitLifecycleResult> {
  const { visitId, visitPath, studyPath, subjectPath } = input

  if (!UUID_REGEX.test(visitId)) {
    return { ok: false, message: 'Invalid visit id.' }
  }

  const supabase = await createServerClient()
  const {
    data: { user },
    error: userErr,
  } = await supabase.auth.getUser()
  if (userErr || !user?.id) {
    return { ok: false, message: 'Authentication required.' }
  }

  // Read current status — idempotent guard
  const { data: visit, error: visitErr } = await supabase
    .from('visits')
    .select('id, organization_id, study_id, visit_status')
    .eq('id', visitId)
    .maybeSingle()

  if (visitErr) return { ok: false, message: visitErr.message }
  if (!visit) return { ok: false, message: 'Visit not found.' }

  const currentStatus = visit.visit_status as string | null

  // Already in an active or terminal state — idempotent
  if (
    currentStatus === 'checked_in' ||
    currentStatus === 'in_progress' ||
    currentStatus === 'completed' ||
    currentStatus === 'locked'
  ) {
    return { ok: true, idempotent: true }
  }

  if (currentStatus !== 'scheduled') {
    return {
      ok: false,
      message: `Visit cannot be checked in from status «${currentStatus ?? 'unknown'}».`,
    }
  }

  const now = new Date().toISOString()
  const { data: updated, error: updateErr } = await supabase
    .from('visits')
    .update({
      visit_status: 'checked_in',
      checked_in_at: now,
    })
    .eq('id', visitId)
    .eq('organization_id', visit.organization_id as string)
    .eq('visit_status', 'scheduled')
    .select('id')
    .maybeSingle()

  if (updateErr) {
    // Column may not exist yet on older schemas — fall back gracefully
    if (/checked_in_at/i.test(updateErr.message)) {
      const { data: fallbackRow, error: fallbackErr } = await supabase
        .from('visits')
        .update({ visit_status: 'checked_in' })
        .eq('id', visitId)
        .eq('organization_id', visit.organization_id as string)
        .eq('visit_status', 'scheduled')
        .select('id')
        .maybeSingle()
      if (fallbackErr) return { ok: false, message: fallbackErr.message }
      if (!fallbackRow) {
        return {
          ok: false,
          message: 'Visit status changed — refresh the page before checking in.',
        }
      }
    } else {
      return { ok: false, message: updateErr.message }
    }
  } else if (!updated) {
    return {
      ok: false,
      message: 'Visit status changed — refresh the page before checking in.',
    }
  }

  void logAuditEvent({
    organizationId: visit.organization_id as string,
    actorUserId: user.id,
    action: 'VISIT_CHECKED_IN',
    target: visitId,
    metadata: { study_id: visit.study_id },
  })

  revalidatePath(visitPath)
  revalidatePath(studyPath)
  revalidatePath(subjectPath)
  revalidatePath('/studies')

  return { ok: true }
}

/**
 * Phase 12C addendum — hybrid retrieval (keyword + lightweight semantic + section/table aware).
 * No external embeddings API — deterministic TF overlap for semantic channel.
 */
import type { NormalizedSegment, EnrichedIntakeCorpus, ContentKind } from '@/lib/protocol-intake/normalization/enrich-corpus'
import { evidenceRef } from '@/lib/protocol-intake/evidence'
import type { EvidenceRef } from '@/lib/protocol-intake/types'

export type RetrievalChannel = 'keyword' | 'semantic' | 'table' | 'section'

export type RetrievalHit = {
  segment: NormalizedSegment
  score: number
  channel: RetrievalChannel
}

export type RetrievalQuery = {
  query: string
  section_hint?: string
  prefer_tables?: boolean
  content_kinds?: ContentKind[]
  limit?: number
}

function tokenize(text: string): string[] {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter((t) => t.length > 2)
}

function keywordScore(queryTokens: string[], segmentText: string): number {
  const segTokens = new Set(tokenize(segmentText))
  if (!queryTokens.length) return 0
  let hits = 0
  for (const t of queryTokens) {
    if (segTokens.has(t)) hits++
  }
  return hits / queryTokens.length
}

function semanticScore(queryTokens: string[], segmentText: string): number {
  const segTokens = tokenize(segmentText)
  const segSet = new Set(segTokens)
  const qSet = new Set(queryTokens)
  const intersection = queryTokens.filter((t) => segSet.has(t)).length
  const union = new Set([...queryTokens, ...segTokens]).size
  return union === 0 ? 0 : intersection / union
}

export function retrieveSegments(
  corpus: EnrichedIntakeCorpus,
  query: RetrievalQuery,
): RetrievalHit[] {
  const queryTokens = tokenize(query.query)
  const limit = query.limit ?? 5
  const hits: RetrievalHit[] = []

  for (const segment of corpus.segments) {
    if (query.content_kinds?.length && !query.content_kinds.includes(segment.content_kind)) {
      continue
    }
    if (query.prefer_tables && segment.content_kind !== 'table') {
      continue
    }
    if (
      query.section_hint
      && segment.section_reference
      && !segment.section_reference.toLowerCase().includes(query.section_hint.toLowerCase())
    ) {
      continue
    }

    const kw = keywordScore(queryTokens, segment.text)
    const sem = semanticScore(queryTokens, segment.text)
    const tableBoost = segment.content_kind === 'table' && query.prefer_tables ? 0.25 : 0
    const sectionBoost =
      query.section_hint
      && segment.section_reference?.toLowerCase().includes(query.section_hint.toLowerCase())
        ? 0.15
        : 0

    const score = Math.min(1, kw * 0.55 + sem * 0.35 + tableBoost + sectionBoost)
    if (score <= 0.08) continue

    hits.push({
      segment,
      score,
      channel: segment.content_kind === 'table' ? 'table' : kw >= sem ? 'keyword' : 'semantic',
    })
  }

  return hits
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
}

export function hitsToEvidence(hits: RetrievalHit[]): EvidenceRef[] {
  return hits.map((hit) =>
    evidenceRef({
      file_name: hit.segment.file_name,
      page_or_sheet: hit.segment.page_or_sheet,
      section_reference:
        hit.segment.table_coordinates
          ? `Table ${hit.segment.table_coordinates.sheet_name ?? hit.segment.page_or_sheet}`
          : hit.segment.section_reference,
      source_snippet: hit.segment.text.slice(0, 500),
    }),
  )
}

export function retrieveEvidence(
  corpus: EnrichedIntakeCorpus,
  query: RetrievalQuery,
): EvidenceRef[] {
  return hitsToEvidence(retrieveSegments(corpus, query))
}

import { getCanonicalLibraryFields } from '@/lib/source-engine/canonical-clinical-library'
import { evidenceRef } from '@/lib/protocol-intake/evidence'
import type { ExtractedProcedure } from '@/lib/protocol-intake/types'
import type { SourceCompositionRecommendation } from '@/lib/protocol-intake/types'

const CATEGORY_MAP: Record<
  string,
  { libraries: string[]; overlays: string[]; optionalFields?: string[]; excludeFields?: string[] }
> = {
  vitals: { libraries: ['VITALS_CORE_V1'], overlays: [] },
  adverse_events: { libraries: ['AE_CORE_V1'], overlays: [] },
  concomitant_medications: { libraries: ['CONMED_CORE_V1'], overlays: [] },
  ip_administration: { libraries: ['VITALS_CORE_V1', 'IP_ADMIN_CORE_V1'], overlays: [] },
  labs: { libraries: ['LAB_CORE_V1'], overlays: [] },
  ecg: { libraries: ['ECG_CORE_V1'], overlays: [] },
  physical_exam: { libraries: ['PHYSICAL_EXAM_CORE_V1'], overlays: [] },
  adrenal: {
    libraries: ['PHYSICAL_EXAM_CORE_V1'],
    overlays: ['PARA_ADRENAL_OVERLAY_V1'],
  },
  hit: { libraries: ['LAB_CORE_V1'], overlays: ['PARA_HIT_OVERLAY_V1'] },
  symptoms: { libraries: [], overlays: ['MV_HOUSEHOLD_SYMPTOM_OVERLAY_V1'] },
  swab: { libraries: ['LAB_CORE_V1'], overlays: ['MV_HOUSEHOLD_SYMPTOM_OVERLAY_V1'] },
}

function refineByProcedureName(
  name: string,
  category: string,
): { libraries: string[]; overlays: string[] } {
  const base = CATEGORY_MAP[category] ?? { libraries: ['VITALS_CORE_V1'], overlays: [] }
  const libraries = [...base.libraries]
  const overlays = [...base.overlays]

  if (/ACTH|adrenal|cortisol/i.test(name)) {
    if (!libraries.includes('LAB_CORE_V1')) libraries.push('LAB_CORE_V1')
    if (!overlays.includes('PARA_ADRENAL_OVERLAY_V1')) overlays.push('PARA_ADRENAL_OVERLAY_V1')
    if (!libraries.includes('PHYSICAL_EXAM_CORE_V1')) libraries.push('PHYSICAL_EXAM_CORE_V1')
  }
  if (/HIT|platelet|PF4|4T/i.test(name)) {
    if (!libraries.includes('LAB_CORE_V1')) libraries.push('LAB_CORE_V1')
    if (!overlays.includes('PARA_HIT_OVERLAY_V1')) overlays.push('PARA_HIT_OVERLAY_V1')
  }
  if (/symptom|sick|household|cough|COVID|influenza/i.test(name)) {
    if (!overlays.includes('MV_HOUSEHOLD_SYMPTOM_OVERLAY_V1')) {
      overlays.push('MV_HOUSEHOLD_SYMPTOM_OVERLAY_V1')
    }
  }
  if (/swab/i.test(name)) {
    if (!libraries.includes('LAB_CORE_V1')) libraries.push('LAB_CORE_V1')
  }

  return { libraries: [...new Set(libraries)], overlays: [...new Set(overlays)] }
}

export function recommendSourceComposition(
  procedures: ExtractedProcedure[],
): SourceCompositionRecommendation[] {
  return procedures.map((proc) => {
    const code = proc.procedure_code.value
    const name = proc.procedure_name.value
    const category = proc.procedure_category.value
    const map = refineByProcedureName(name, category)

    const include_fields: string[] = []
    const optional_fields: string[] = []
    const excluded_fields: string[] = ['linked_ae_id']
    const omission_reasons: Array<{ field_key: string; reason: string }> = []

    for (const lib of map.libraries) {
      for (const field of getCanonicalLibraryFields(lib)) {
        if (field.required_default) include_fields.push(field.field_key)
        else optional_fields.push(field.field_key)
      }
    }
    for (const overlay of map.overlays) {
      for (const field of getCanonicalLibraryFields(overlay)) {
        optional_fields.push(field.field_key)
      }
    }

    if (proc.conditional.value) {
      omission_reasons.push({
        field_key: '_procedure',
        reason: `Conditional procedure — instantiate when: ${proc.condition_text.value ?? 'coordinator confirms'}`,
      })
    }

    const confidence = proc.confidence
    const requires_human_review =
      proc.requires_human_review || map.libraries.length === 0

    return {
      procedure_code: code,
      recommended_library_blocks: map.libraries,
      recommended_overlays: map.overlays,
      include_fields: [...new Set(include_fields)],
      optional_fields: [...new Set(optional_fields)],
      excluded_fields,
      omission_reasons,
      evidence_refs: proc.source_evidence,
      confidence,
      requires_human_review,
    }
  })
}

/**
 * Phase 12B — deterministic canonical library composition resolver.
 */

import { createHash } from 'node:crypto'
import { CANONICAL_CLINICAL_LIBRARY_VERSION } from '@/lib/source-engine/canonical-clinical-library'
import {
  canonicalFieldsToFieldDefinitions,
  getCanonicalLibraryBlock,
  getCanonicalLibraryFields,
} from '@/lib/source-engine/canonical-clinical-library'
import type { CanonicalClinicalField } from '@/lib/source-engine/canonical-clinical-library.types'
import type {
  ResolvedCompositionFieldMeta,
  ResolvedCompositionSection,
  ResolvedSourceComposition,
  SourceCompositionManifest,
  SourceCompositionSection,
} from '@/lib/source-engine/source-composition.types'
import type { FieldDefinition } from '@/lib/source-engine/types'

export class SourceCompositionResolveError extends Error {
  constructor(message: string) {
    super(message)
    this.name = 'SourceCompositionResolveError'
  }
}

function stableSerialize(value: unknown): string {
  if (value === null || typeof value !== 'object') return JSON.stringify(value)
  if (Array.isArray(value)) return `[${value.map(stableSerialize).join(',')}]`
  const obj = value as Record<string, unknown>
  const keys = Object.keys(obj).sort()
  return `{${keys.map((k) => `${JSON.stringify(k)}:${stableSerialize(obj[k])}`).join(',')}}`
}

function fingerprintResolved(fields: FieldDefinition[], meta: ResolvedCompositionFieldMeta[], manifest: SourceCompositionManifest) {
  const payload = {
    template_key: manifest.template_key,
    library_version: manifest.library_version,
    manifest_version: manifest.manifest_version,
    sections: manifest.sections.map((s) => ({
      section_key: s.section_key,
      library: s.library ?? null,
      overlay: s.overlay ?? null,
      include: s.include ?? null,
      exclude: s.exclude ?? null,
      required_overrides: s.required_overrides ?? null,
      hidden_fields: s.hidden_fields ?? null,
      omissions: s.omissions ?? null,
      aliases: s.aliases ?? null,
    })),
    fields: fields.map((f) => ({
      key: f.key,
      label: f.label,
      type: f.type,
      domain: f.domain,
      unit: f.unit ?? null,
      validation: f.validation ?? [],
    })),
    meta: meta
      .filter((m) => !m.omitted)
      .map((m) => ({
        runtime_key: m.runtime_key,
        logical_key: m.logical_key,
        section_key: m.section_key,
        library_code: m.library_code,
        required: m.required,
        hidden: m.hidden,
      })),
  }
  return createHash('sha256').update(stableSerialize(payload)).digest('hex')
}

function libraryCodeForSection(section: SourceCompositionSection): string {
  const code = section.library ?? section.overlay
  if (!code) {
    throw new SourceCompositionResolveError(
      `Section ${section.section_key} must specify library or overlay.`,
    )
  }
  if (section.library && section.overlay) {
    throw new SourceCompositionResolveError(
      `Section ${section.section_key} cannot specify both library and overlay.`,
    )
  }
  return code
}

function selectLogicalKeys(
  section: SourceCompositionSection,
  blockFields: CanonicalClinicalField[],
): string[] {
  const allKeys = blockFields.map((f) => f.field_key)
  const includeSet = section.include ? new Set(section.include) : null
  const excludeSet = new Set(section.exclude ?? [])
  const omissionSet = new Set((section.omissions ?? []).map((o) => o.field_key))

  let keys: string[]
  if (includeSet) {
    const unknown = section.include!.filter((k) => !allKeys.includes(k))
    if (unknown.length) {
      throw new SourceCompositionResolveError(
        `Section ${section.section_key} include references unknown field(s): ${unknown.join(', ')}`,
      )
    }
    keys = allKeys.filter((k) => includeSet.has(k))
  } else {
    keys = [...allKeys]
  }

  keys = keys.filter((k) => !excludeSet.has(k) && !omissionSet.has(k))

  for (const row of section.omissions ?? []) {
    if (!allKeys.includes(row.field_key)) {
      throw new SourceCompositionResolveError(
        `Section ${section.section_key} omission references unknown field: ${row.field_key}`,
      )
    }
  }

  for (const hidden of section.hidden_fields ?? []) {
    if (!allKeys.includes(hidden)) {
      throw new SourceCompositionResolveError(
        `Section ${section.section_key} hidden_fields references unknown field: ${hidden}`,
      )
    }
  }

  return keys
}

function assertRequiredFieldsNotDropped(
  section: SourceCompositionSection,
  blockFields: CanonicalClinicalField[],
  selectedKeys: string[],
) {
  const selected = new Set(selectedKeys)
  const overrides = section.required_overrides ?? {}
  for (const row of blockFields) {
    if (!row.required_default) continue
    if (overrides[row.field_key] === false) continue
    if (!selected.has(row.field_key)) {
      throw new SourceCompositionResolveError(
        `Section ${section.section_key} cannot drop required field ${row.field_key} without required_overrides.${row.field_key}=false and an explicit omission.`,
      )
    }
  }
}

function runtimeKeyFor(sectionKey: string, logicalKey: string, alias?: string) {
  const suffix = alias ?? logicalKey
  if (!/^[a-zA-Z0-9_]+$/.test(suffix)) {
    throw new SourceCompositionResolveError(`Invalid runtime key suffix: ${suffix}`)
  }
  return `${sectionKey}__${suffix}`
}

export function resolveSourceCompositionManifest(
  manifest: SourceCompositionManifest,
): ResolvedSourceComposition {
  if (manifest.library_version !== CANONICAL_CLINICAL_LIBRARY_VERSION) {
    throw new SourceCompositionResolveError(
      `Manifest library_version ${manifest.library_version} does not match loaded canonical library ${CANONICAL_CLINICAL_LIBRARY_VERSION}.`,
    )
  }

  const sectionKeys = new Set<string>()
  const runtimeKeys = new Set<string>()
  const fields: FieldDefinition[] = []
  const field_meta: ResolvedCompositionFieldMeta[] = []
  const sections: ResolvedCompositionSection[] = []

  for (const section of manifest.sections) {
    if (!section.section_key?.trim()) {
      throw new SourceCompositionResolveError('Every section requires a non-empty section_key.')
    }
    if (sectionKeys.has(section.section_key)) {
      throw new SourceCompositionResolveError(`Duplicate section_key: ${section.section_key}`)
    }
    sectionKeys.add(section.section_key)

    const libraryCode = libraryCodeForSection(section)
    const block = getCanonicalLibraryBlock(libraryCode)
    if (!block) {
      throw new SourceCompositionResolveError(`Unknown library/overlay: ${libraryCode}`)
    }

    const blockFields = getCanonicalLibraryFields(libraryCode)
    const logicalKeys = selectLogicalKeys(section, blockFields)
    assertRequiredFieldsNotDropped(section, blockFields, logicalKeys)
    for (const omission of section.omissions ?? []) {
      const row = blockFields.find((f) => f.field_key === omission.field_key)
      if (row?.required_default && section.required_overrides?.[omission.field_key] !== false) {
        throw new SourceCompositionResolveError(
          `Section ${section.section_key} cannot omit required field ${omission.field_key}.`,
        )
      }
    }

    const hiddenSet = new Set(section.hidden_fields ?? [])
    const omissionByKey = new Map((section.omissions ?? []).map((o) => [o.field_key, o.omission_reason]))
    const defs = canonicalFieldsToFieldDefinitions(libraryCode, logicalKeys)
    const defByKey = new Map(defs.map((d) => [d.key, d]))
    const rowByKey = new Map(blockFields.map((r) => [r.field_key, r]))

    let hiddenCount = 0
    let omittedCount = 0

    for (const logicalKey of logicalKeys) {
      const row = rowByKey.get(logicalKey)
      const base = defByKey.get(logicalKey)
      if (!row || !base) continue

      const alias = section.aliases?.[logicalKey]
      const runtime_key = runtimeKeyFor(section.section_key, logicalKey, alias)
      if (runtimeKeys.has(runtime_key)) {
        throw new SourceCompositionResolveError(
          `Collision: runtime key ${runtime_key} already composed (section ${section.section_key}, field ${logicalKey}). Provide aliases to disambiguate.`,
        )
      }
      runtimeKeys.add(runtime_key)

      const requiredOverride = section.required_overrides?.[logicalKey]
      const required =
        requiredOverride !== undefined ? requiredOverride : row.required_default
      const hidden = hiddenSet.has(logicalKey)
      if (hidden) hiddenCount++

      const validation = [...(base.validation ?? [])]
      if (required) {
        if (!validation.some((v) => v.kind === 'required')) {
          validation.unshift({
            kind: 'required',
            message: `${row.display_label} is required.`,
          })
        }
      } else {
        const idx = validation.findIndex((v) => v.kind === 'required')
        if (idx >= 0) validation.splice(idx, 1)
      }

      const resolved: FieldDefinition = {
        ...base,
        key: runtime_key,
        validation,
        instructions: [base.instructions, section.protocol_notes, row.protocol_notes]
          .filter(Boolean)
          .join(' ')
          .trim() || undefined,
      }

      fields.push(resolved)
      field_meta.push({
        runtime_key,
        logical_key: logicalKey,
        section_key: section.section_key,
        library_code: libraryCode,
        hidden,
        omitted: false,
        required,
        audit_relevance: row.audit_relevance,
        protocol_notes: row.protocol_notes || section.protocol_notes,
      })
    }

    for (const omission of section.omissions ?? []) {
      omittedCount++
      const row = rowByKey.get(omission.field_key)
      field_meta.push({
        runtime_key: runtimeKeyFor(section.section_key, omission.field_key, section.aliases?.[omission.field_key]),
        logical_key: omission.field_key,
        section_key: section.section_key,
        library_code: libraryCode,
        hidden: false,
        omitted: true,
        omission_reason: omission.omission_reason,
        required: false,
        audit_relevance: row?.audit_relevance,
        protocol_notes: row?.protocol_notes,
      })
    }

    sections.push({
      section_key: section.section_key,
      library_code: libraryCode,
      library_kind: block.library_kind,
      protocol_notes: section.protocol_notes,
      field_count: logicalKeys.length,
      hidden_count: hiddenCount,
      omitted_count: omittedCount,
    })
  }

  const fingerprint = fingerprintResolved(fields, field_meta, manifest)

  return {
    template_key: manifest.template_key,
    manifest_version: manifest.manifest_version,
    library_version: manifest.library_version,
    label: manifest.label,
    fingerprint,
    sections,
    fields,
    field_meta,
  }
}

export function buildCompositionPublishSnapshot(
  manifest: SourceCompositionManifest,
  frozenAt = new Date().toISOString(),
): import('@/lib/source-engine/source-composition.types').CompositionPublishSnapshot {
  const resolved = resolveSourceCompositionManifest(manifest)
  const composition_manifest = structuredClone(manifest)
  return {
    template_key: manifest.template_key,
    composition_fingerprint: resolved.fingerprint,
    library_version: manifest.library_version,
    manifest_version: manifest.manifest_version,
    composition_manifest,
    resolved_field_keys: resolved.fields.map((f) => f.key),
    provenance_json: {
      composition_manifest,
      composition_fingerprint: resolved.fingerprint,
      library_version: manifest.library_version,
      manifest_version: manifest.manifest_version,
      resolved_field_keys: resolved.fields.map((f) => f.key),
      frozen_at: frozenAt,
    },
  }
}

import {
  STUDY_PHASE_OPTIONS,
  STUDY_STATUS_VALUES,
  type CreateStudyInput,
  type CreateStudyValidationResult,
  type StudyStatusValue,
} from '@/lib/studies/types'

export function normalizeStudySlug(raw: string): string {
  return raw
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 64)
}

function clean(value: FormDataEntryValue | null): string {
  return typeof value === 'string' ? value.trim() : ''
}

export function parseCreateStudyForm(formData: FormData): CreateStudyValidationResult {
  const errors: Record<string, string> = {}

  const organizationId = clean(formData.get('organization_id'))
  const title = clean(formData.get('title'))
  const studyCode = clean(formData.get('study_code'))
  const sponsorName = clean(formData.get('sponsor_name'))
  const phase = clean(formData.get('phase'))
  const statusRaw = clean(formData.get('status'))
  const enrollmentRaw = clean(formData.get('enrollment_target'))

  if (!organizationId) errors.organization_id = 'Organization is required.'
  if (!title) errors.title = 'Study title is required.'
  else if (title.length > 240) errors.title = 'Study title must be 240 characters or fewer.'

  const slug = normalizeStudySlug(studyCode)
  if (!studyCode) errors.study_code = 'Study code is required.'
  else if (!slug) errors.study_code = 'Study code must include letters or numbers.'

  if (!sponsorName) errors.sponsor_name = 'Sponsor name is required.'
  else if (sponsorName.length > 160) errors.sponsor_name = 'Sponsor name must be 160 characters or fewer.'

  if (!phase) errors.phase = 'Phase is required.'
  else if (!STUDY_PHASE_OPTIONS.includes(phase as (typeof STUDY_PHASE_OPTIONS)[number])) {
    errors.phase = 'Select a valid phase.'
  }

  if (!statusRaw) errors.status = 'Status is required.'
  else if (!STUDY_STATUS_VALUES.includes(statusRaw as StudyStatusValue)) {
    errors.status = 'Select a valid status.'
  }

  let enrollmentTarget: number | null = null
  if (enrollmentRaw) {
    const parsed = Number(enrollmentRaw)
    if (!Number.isInteger(parsed) || parsed < 1) {
      errors.enrollment_target = 'Target enrollment must be a positive whole number.'
    } else if (parsed > 1_000_000) {
      errors.enrollment_target = 'Target enrollment is too large.'
    } else {
      enrollmentTarget = parsed
    }
  }

  if (Object.keys(errors).length > 0) {
    return { ok: false, errors }
  }

  return {
    ok: true,
    data: {
      organizationId,
      title,
      studyCode: slug,
      sponsorName,
      phase,
      status: statusRaw as StudyStatusValue,
      enrollmentTarget,
    },
  }
}

/**
 * Phase 4C.8 — Source definition publish package builder (file-based skeleton).
 *
 * Bundles approved source definitions with approval evidence and provenance.
 * Immutable handoff for future Phase 4A persistence. No DB writes.
 *
 * Run: node scripts/build-source-publish-package.mjs [--strict] [paths]
 */
import { createHash } from "node:crypto";
import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import { dirname, join, relative, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const PACKAGE_VERSION = "0.1.0";
const PUBLISH_PACKAGE_BUILDER_VERSION = "0.1.0";

const DEFAULT_SOURCE_DEFINITIONS = join(ROOT, "tmp/compiled/source-definitions.golden-basic.json");
const DEFAULT_PREVIEW = join(ROOT, "tmp/compiled/source-preview.golden-basic.md");
const DEFAULT_APPROVAL = join(ROOT, "tmp/approvals/source-preview-approval.golden-basic.json");
const DEFAULT_OUTPUT = join(ROOT, "tmp/publish/source-publish-package.golden-basic.json");

const COUNT_KEYS = [
  "source_definition_versions",
  "source_sections",
  "source_fields",
  "validation_rules",
  "conditional_rules",
  "workflow_requirements",
  "signature_requirements",
  "runtime_expectations",
  "external_source_requirements",
];

function usage() {
  console.log(`Usage: node scripts/build-source-publish-package.mjs \\
  [--source-definitions <path>] \\
  [--preview <path>] \\
  [--approval <path>] \\
  [--output <path>] \\
  [--strict]`);
}

function parseArgs(argv) {
  const args = {
    sourceDefinitions: DEFAULT_SOURCE_DEFINITIONS,
    preview: DEFAULT_PREVIEW,
    approval: DEFAULT_APPROVAL,
    output: DEFAULT_OUTPUT,
    strict: false,
  };

  for (let i = 2; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--strict") args.strict = true;
    else if (a === "--help" || a === "-h") {
      usage();
      process.exit(0);
    } else if (a === "--source-definitions") args.sourceDefinitions = resolve(argv[++i]);
    else if (a === "--preview") args.preview = resolve(argv[++i]);
    else if (a === "--approval") args.approval = resolve(argv[++i]);
    else if (a === "--output") args.output = resolve(argv[++i]);
    else {
      console.error("Unknown argument:", a);
      usage();
      process.exit(1);
    }
  }

  return args;
}

function loadJson(path) {
  return JSON.parse(readFileSync(path, "utf8"));
}

function fileSha256(path) {
  const digest = createHash("sha256").update(readFileSync(path)).digest("hex");
  return `sha256:${digest}`;
}

function shortHash(parts) {
  return createHash("sha256")
    .update(parts.filter((p) => p != null).join("|"))
    .digest("hex")
    .slice(0, 12);
}

function relPath(absPath) {
  const rel = relative(ROOT, absPath);
  return rel && !rel.startsWith("..") ? rel.replace(/\\/g, "/") : absPath;
}

function check(code, pass, message, level = "fail") {
  return {
    check_code: code,
    status: pass ? "pass" : level === "warning" ? "warning" : "fail",
    message,
  };
}

function buildPackage(args) {
  const publishChecks = [];

  const pathsPresent =
    existsSync(args.sourceDefinitions) && existsSync(args.preview) && existsSync(args.approval);
  publishChecks.push(
    check(
      "ARTIFACT_PATHS_PRESENT",
      pathsPresent,
      pathsPresent
        ? "Source definitions, preview, and approval files exist"
        : "One or more input artifact paths are missing"
    )
  );

  if (!pathsPresent) {
    const pkg = {
      package_id: `pkg_${shortHash(["missing-artifacts"])}`,
      artifact_type: "source_definition_publish_package",
      package_version: PACKAGE_VERSION,
      created_at: new Date().toISOString(),
      publish_ready: false,
      graph_id: null,
      input_hash: null,
      compiler_output_id: null,
      compiler_version: null,
      approval_id: null,
      approval_decision: null,
      reviewer_user_id: null,
      reviewer_role: null,
      source_definitions_hash: null,
      preview_hash: null,
      approval_hash: null,
      artifacts: {
        source_definitions_path: relPath(args.sourceDefinitions),
        preview_path: relPath(args.preview),
        approval_path: relPath(args.approval),
      },
      counts: {},
      validation_snapshot: {},
      publish_checks: publishChecks,
      provenance: {
        source_compiler_version: null,
        approval_gate_version: null,
        publish_package_builder_version: PUBLISH_PACKAGE_BUILDER_VERSION,
      },
    };
    return { pkg, publishReady: false, earlyExit: true };
  }

  const sourceDefinitions = loadJson(args.sourceDefinitions);
  const approval = loadJson(args.approval);

  const sourceDefinitionsHash = fileSha256(args.sourceDefinitions);
  const previewHash = fileSha256(args.preview);
  const approvalHash = fileSha256(args.approval);

  const report = sourceDefinitions.validation_report ?? { errors: [], warnings: [] };
  const errors = report.errors ?? [];
  const counts = sourceDefinitions.counts ?? {};

  publishChecks.push(
    check(
      "APPROVAL_ELIGIBLE",
      approval.publish_eligible === true,
      approval.publish_eligible === true
        ? "Approval artifact publish_eligible is true"
        : "Approval artifact publish_eligible is not true"
    )
  );

  publishChecks.push(
    check(
      "APPROVAL_DECISION_APPROVED",
      approval.decision === "approved",
      approval.decision === "approved"
        ? `Approval decision is approved`
        : `Approval decision is ${approval.decision ?? "missing"}`
    )
  );

  publishChecks.push(
    check(
      "SOURCE_HASH_MATCH",
      approval.source_definitions_hash === sourceDefinitionsHash,
      approval.source_definitions_hash === sourceDefinitionsHash
        ? "Approval source_definitions_hash matches computed hash"
        : `Hash mismatch: approval=${approval.source_definitions_hash} computed=${sourceDefinitionsHash}`
    )
  );

  publishChecks.push(
    check(
      "PREVIEW_HASH_MATCH",
      approval.preview_hash === previewHash,
      approval.preview_hash === previewHash
        ? "Approval preview_hash matches computed hash"
        : `Hash mismatch: approval=${approval.preview_hash} computed=${previewHash}`
    )
  );

  publishChecks.push(
    check(
      "GRAPH_ID_MATCH",
      approval.graph_id === sourceDefinitions.graph_id,
      approval.graph_id === sourceDefinitions.graph_id
        ? `Graph ID matches (${sourceDefinitions.graph_id})`
        : `Graph ID mismatch: approval=${approval.graph_id} source=${sourceDefinitions.graph_id}`
    )
  );

  publishChecks.push(
    check(
      "INPUT_HASH_MATCH",
      approval.input_hash === sourceDefinitions.input_hash,
      approval.input_hash === sourceDefinitions.input_hash
        ? "Input hash matches between approval and source definitions"
        : `Input hash mismatch: approval=${approval.input_hash} source=${sourceDefinitions.input_hash}`
    )
  );

  publishChecks.push(
    check(
      "NO_VALIDATION_ERRORS",
      errors.length === 0,
      errors.length === 0
        ? "Source definitions validation_report has no errors"
        : `Source definitions has ${errors.length} validation error(s)`
    )
  );

  const countsPresent =
    COUNT_KEYS.every((k) => typeof counts[k] === "number") &&
    COUNT_KEYS.every((k) => counts[k] >= 0);
  const countsNonZero = counts.source_definition_versions > 0;
  publishChecks.push(
    check(
      "COUNTS_PRESENT",
      countsPresent && countsNonZero,
      countsPresent && countsNonZero
        ? `Counts present (${counts.source_definition_versions} SDV, ${counts.source_fields} fields)`
        : "Source definitions counts missing or empty"
    )
  );

  const validationStatus = report.validation_status ?? approval.validation_snapshot?.validation_status;
  if ((report.warnings ?? []).length > 0 && validationStatus === "warning") {
    publishChecks.push(
      check(
        "VALIDATION_WARNINGS_ACKNOWLEDGED",
        approval.publish_eligible === true,
        "Validation warnings present; publish allowed only with human approval (publish_eligible)",
        "warning"
      )
    );
  }

  const publishReady = publishChecks.every((c) => c.status === "pass" || c.status === "warning");

  const packageId = `pkg_${shortHash([
    sourceDefinitions.graph_id,
    sourceDefinitions.compiler_output_id,
    approval.approval_id,
    sourceDefinitionsHash,
    approvalHash,
  ])}`;

  const createdAt =
    approval.reviewed_at ?? sourceDefinitions.compiled_at ?? new Date().toISOString();

  const pkg = {
    package_id: packageId,
    artifact_type: "source_definition_publish_package",
    package_version: PACKAGE_VERSION,
    created_at: createdAt,
    publish_ready: publishReady,
    graph_id: sourceDefinitions.graph_id,
    input_hash: sourceDefinitions.input_hash,
    compiler_output_id: sourceDefinitions.compiler_output_id,
    compiler_version: sourceDefinitions.compiler_version,
    approval_id: approval.approval_id,
    approval_decision: approval.decision,
    reviewer_user_id: approval.reviewer_user_id,
    reviewer_role: approval.reviewer_role ?? null,
    source_definitions_hash: sourceDefinitionsHash,
    preview_hash: previewHash,
    approval_hash: approvalHash,
    artifacts: {
      source_definitions_path: relPath(args.sourceDefinitions),
      preview_path: relPath(args.preview),
      approval_path: relPath(args.approval),
    },
    counts: { ...counts },
    validation_snapshot: approval.validation_snapshot ?? {
      validation_status: report.validation_status,
      errors,
      warnings: report.warnings ?? [],
    },
    publish_checks: publishChecks,
    provenance: {
      source_compiler_version: sourceDefinitions.compiler_version ?? null,
      approval_gate_version: approval.provenance?.approval_gate_version ?? null,
      publish_package_builder_version: PUBLISH_PACKAGE_BUILDER_VERSION,
    },
  };

  return { pkg, publishReady };
}

function main() {
  const args = parseArgs(process.argv);
  const { pkg, publishReady, earlyExit } = buildPackage(args);

  if (earlyExit) {
    mkdirSync(dirname(args.output), { recursive: true });
    writeFileSync(args.output, `${JSON.stringify(pkg, null, 2)}\n`, "utf8");
    console.error("Publish package build failed: missing artifact paths");
    process.exit(1);
  }

  mkdirSync(dirname(args.output), { recursive: true });
  writeFileSync(args.output, `${JSON.stringify(pkg, null, 2)}\n`, "utf8");

  const passed = pkg.publish_checks.filter((c) => c.status === "pass").length;
  const failed = pkg.publish_checks.filter((c) => c.status === "fail").length;
  const warned = pkg.publish_checks.filter((c) => c.status === "warning").length;

  console.log("Package ID:", pkg.package_id);
  console.log("Publish ready:", pkg.publish_ready);
  console.log("Checks: pass", passed, "warn", warned, "fail", failed);
  console.log("Graph ID:", pkg.graph_id);
  console.log("Approval ID:", pkg.approval_id);
  console.log("Source definitions hash:", pkg.source_definitions_hash);
  console.log("Preview hash:", pkg.preview_hash);
  console.log("Approval hash:", pkg.approval_hash);
  console.log("Output:", relative(ROOT, args.output));

  if (args.strict && !pkg.publish_ready) {
    console.error("Strict mode: publish_ready is false");
    for (const c of pkg.publish_checks.filter((x) => x.status === "fail")) {
      console.error(`  FAIL ${c.check_code}: ${c.message}`);
    }
    process.exit(1);
  }
}

main();

/**
 * Phase 4C.5 — Canonical Runtime Graph → Source Definition Compiler (skeleton).
 *
 * Run: node scripts/compile-source-definitions.mjs [--input path] [--output path] [--strict]
 */
import { createHash } from "node:crypto";
import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import { dirname, join, relative, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const DEFAULT_INPUT = join(ROOT, "tmp/compiled/cpst-runtime-graph.golden-basic.json");
const DEFAULT_OUTPUT = join(ROOT, "tmp/compiled/source-definitions.golden-basic.json");
const COMPILER_VERSION = "0.1.0";

const VISIT_PROC_EDGE_TYPES = new Set(["assigned_to_visit", "requires", "optional_for"]);
const EXTERNAL_SOURCE_TYPES = new Set(["external", "device_vendor"]);

function parseArgs(argv) {
  const args = { input: DEFAULT_INPUT, output: DEFAULT_OUTPUT, strict: false };
  for (let i = 2; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--strict") args.strict = true;
    else if (a === "--input") args.input = resolve(argv[++i]);
    else if (a === "--output") args.output = resolve(argv[++i]);
    else if (a === "--help" || a === "-h") {
      console.log(`Usage: node scripts/compile-source-definitions.mjs [--input path] [--output path] [--strict]`);
      process.exit(0);
    }
  }
  return args;
}

function loadJson(path) {
  return JSON.parse(readFileSync(path, "utf8"));
}

function shortHash(parts) {
  return createHash("sha256").update(parts.filter((p) => p != null).join("|")).digest("hex").slice(0, 12);
}

function detId(prefix, graphId, ...parts) {
  return `${prefix}_${graphId}_${shortHash(parts)}`;
}

function provFrom(nodeOrEdge, crg) {
  const p = nodeOrEdge.provenance ?? {};
  return {
    source_dictionary: p.source_dictionary ?? nodeOrEdge.source_dictionary,
    source_row_id: p.source_row_id ?? nodeOrEdge.source_row_id,
    source_field_refs: p.source_field_refs ?? nodeOrEdge.source_field_refs ?? [],
    schema_version: p.schema_version ?? crg.schema_version,
    input_hash: p.input_hash ?? crg.input_hash,
    crg_node_id: nodeOrEdge.id ?? null,
    crg_edge_id: nodeOrEdge.edge_id ?? null,
  };
}

class CrgIndex {
  constructor(crg) {
    this.crg = crg;
    this.nodesById = new Map(crg.nodes.map((n) => [n.id, n]));
    this.out = new Map();
    this.in = new Map();
    for (const e of crg.edges) {
      if (!this.out.has(e.from)) this.out.set(e.from, []);
      this.out.get(e.from).push(e);
      if (!this.in.has(e.to)) this.in.set(e.to, []);
      this.in.get(e.to).push(e);
    }
  }

  nodesOfType(type) {
    return this.crg.nodes.filter((n) => n.node_type === type).sort((a, b) => a.id.localeCompare(b.id));
  }

  node(id) {
    return this.nodesById.get(id);
  }

  outEdges(fromId, types = null) {
    const list = this.out.get(fromId) ?? [];
    if (!types) return list;
    const set = types instanceof Set ? types : new Set(types);
    return list.filter((e) => set.has(e.edge_type));
  }

  inEdges(toId, types = null) {
    const list = this.in.get(toId) ?? [];
    if (!types) return list;
    const set = types instanceof Set ? types : new Set(types);
    return list.filter((e) => set.has(e.edge_type));
  }
}

function matrixMarkerToRequiredness(marker) {
  if (marker === "required") return "required";
  if (marker === "optional") return "optional";
  if (marker === "conditional") return "conditional";
  return "not_applicable";
}

function isExternalSourceType(sourceType) {
  return EXTERNAL_SOURCE_TYPES.has(sourceType);
}

function findExpectation(index, visitId, procedureId) {
  return index.nodesOfType("RuntimeExpectationNode").find(
    (n) => n.payload.visit_id === visitId && n.payload.procedure_id === procedureId
  );
}

function fieldsForProcedure(index, procedureNode) {
  const procId = procedureNode.payload.procedure_id;
  const fields = new Map();
  for (const e of index.outEdges(procedureNode.id, ["belongs_to"])) {
    const n = index.node(e.to);
    if (n?.node_type === "FieldNode") fields.set(n.id, n);
  }
  for (const e of index.inEdges(procedureNode.id, ["belongs_to"])) {
    const n = index.node(e.from);
    if (n?.node_type === "FieldNode") fields.set(n.id, n);
  }
  for (const f of index.nodesOfType("FieldNode")) {
    if (f.payload.procedure_id === procId) fields.set(f.id, f);
  }
  return [...fields.values()].sort((a, b) =>
    String(a.payload.field_key).localeCompare(String(b.payload.field_key))
  );
}

function externalSourcesForProcedure(index, procedureNode) {
  const procId = procedureNode.payload.procedure_id;
  const found = new Map();
  for (const ext of index.nodesOfType("ExternalSourceNode")) {
    if (ext.payload.procedure_id === procId) found.set(ext.id, ext);
  }
  for (const e of index.outEdges(procedureNode.id, ["sourced_from"])) {
    const ext = index.node(e.to);
    if (ext?.node_type === "ExternalSourceNode") found.set(ext.id, ext);
  }
  return [...found.values()];
}

function signatureRequiredFor(index, procedureNode, expectation) {
  if (procedureNode.payload.signature_required === true) return true;
  if (expectation?.payload.signature_override === true) return true;
  const sigId = `${procedureNode.payload.procedure_id}:signature`;
  return index.nodesOfType("SignatureRequirementNode").some(
    (n) => n.source_row_id === procedureNode.payload.procedure_id || n.source_row_id?.startsWith(sigId)
  );
}

function signersForProcedure(index, procedureId) {
  return index.nodesOfType("RoleNode").filter(
    (r) => r.payload.scope_type === "procedure" && r.payload.scope_id === procedureId && r.payload.can_sign === true
  );
}

function validationNodeForField(index, fieldNode) {
  const key = `${fieldNode.source_row_id}:validation`;
  return index.nodesOfType("ValidationRuleNode").find((n) => n.source_row_id === fieldNode.source_row_id || n.id.includes("validation"));
}

const BIOSPECIMEN_MODULE_ID = "MOD-biospecimen_collection";
const BIOSPECIMEN_DICTIONARY = "Biospecimen_Collection_Module";

/** Compiler-level validation skeletons (module context; fields must exist in Field_Definitions). */
const BIOSPECIMEN_VALIDATION_SKELETONS = [
  { field_key: "consent_obtained", rule_type: "expression", expression: "consent_obtained == true", code: "BIO_CONSENT_BEFORE_COLLECTION", message: "Consent must be verified before specimen collection" },
  { field_key: "label_id", rule_type: "expression", expression: "label_id != null && label_id != ''", code: "BIO_LABEL_ID_PRESENT", message: "Unique label ID required for traceability" },
  { field_key: "quantity_collected", rule_type: "expression", expression: "quantity_collected > 0", code: "BIO_QTY_POSITIVE", message: "Quantity collected must be greater than zero" },
  { field_key: "processing_time", rule_type: "expression", expression: "processing_time >= collection_time", code: "BIO_PROCESS_AFTER_COLLECTION", message: "Processing time must be on or after collection time when same-day" },
  { field_key: "ship_date", rule_type: "expression", expression: "ship_date >= storage_date", code: "BIO_SHIP_AFTER_STORAGE", message: "Ship date must be on or after storage date when both present" },
  { field_key: "rejection_reason", rule_type: "expression", expression: "sample_rejected != true || (rejection_reason != null && rejection_reason != '')", code: "BIO_REJECTION_REASON", message: "Rejection reason required when sample is rejected" },
  { field_key: "deviation_description", rule_type: "expression", expression: "deviation_flag != true || (deviation_description != null && deviation_description != '')", code: "BIO_DEVIATION_DESC", message: "Deviation description required when deviation flag is set" },
  { field_key: "reviewed_by", rule_type: "expression", expression: "source_complete != true || (reviewed_by != null && reviewed_by != '')", code: "BIO_CLOSEOUT_REVIEWER", message: "Reviewed by required when source is complete" },
  { field_key: "reviewed_date", rule_type: "expression", expression: "source_complete != true || reviewed_date != null", code: "BIO_CLOSEOUT_REVIEW_DATE", message: "Reviewed date required when source is complete" },
];

function biospecimenModuleProvenance(dom, moduleFieldRef, generatedFieldKey, crg) {
  return {
    source_dictionary: BIOSPECIMEN_DICTIONARY,
    source_row_id: dom.source_row_id,
    source_field_refs: [moduleFieldRef],
    schema_version: dom.provenance?.schema_version ?? crg.schema_version,
    input_hash: dom.provenance?.input_hash ?? crg.input_hash,
    crg_node_id: dom.id,
    module_backed: true,
    module_field_name: generatedFieldKey,
  };
}

function applyBiospecimenModuleEnrichment({
  graphId,
  crg,
  sourceFields,
  validationRules,
  provenanceMap,
  trackId,
  index,
  warnings,
}) {
  const biospecimenModules = index
    .nodesOfType("DomainModuleNode")
    .filter((n) => n.payload.module_id === BIOSPECIMEN_MODULE_ID && n.payload.active_flag !== false);

  if (biospecimenModules.length === 0) return;

  const dom = biospecimenModules[0];
  const fieldByKey = new Map();
  for (const sf of sourceFields) {
    if (!fieldByKey.has(sf.field_key)) fieldByKey.set(sf.field_key, sf);
  }

  for (const skeleton of BIOSPECIMEN_VALIDATION_SKELETONS) {
    const sf = fieldByKey.get(skeleton.field_key);
    if (!sf) {
      warnings.push({
        code: "BIOSPECIMEN_VALIDATION_NO_FIELD",
        message: `Biospecimen validation skeleton references missing field_key: ${skeleton.field_key}`,
        path: dom.source_row_id,
      });
      continue;
    }
    const vrId = detId("vr", graphId, "bio", dom.source_row_id, skeleton.code);
    trackId(vrId, `validation_rules/biospecimen/${skeleton.code}`);
    const vr = {
      validation_rule_id: vrId,
      source_field_id: sf.source_field_id,
      field_name: skeleton.field_key,
      rule_type: skeleton.rule_type,
      expression: skeleton.expression,
      validation_code: skeleton.code,
      validation_message: skeleton.message,
      provenance: biospecimenModuleProvenance(dom, skeleton.code, skeleton.field_key, crg),
    };
    validationRules.push(vr);
    provenanceMap[vrId] = vr.provenance;
  }
}

function compile(crg) {
  const errors = [];
  const warnings = [];
  const provenanceMap = {};
  const seenIds = new Set();

  const trackId = (id, ctx) => {
    if (seenIds.has(id)) {
      errors.push({
        code: "DUPLICATE_GENERATED_ID",
        message: `Duplicate generated id: ${id}`,
        path: ctx,
      });
    }
    seenIds.add(id);
  };

  const index = new CrgIndex(crg);
  const graphId = crg.graph_id;
  const inputHash = crg.input_hash;
  const compiledAt = crg.compiled_at ?? new Date().toISOString();

  const studyNode = index.nodesOfType("StudyTemplateNode")[0];
  const studyTemplateId = studyNode?.payload.study_template_id ?? "ST-000";
  const protocolVersion = studyNode?.payload.protocol_version ?? null;

  const sourceDefinitionVersions = [];
  const sourceSections = [];
  const sourceFields = [];
  const validationRules = [];
  const conditionalRules = [];
  const workflowRequirements = [];
  const signatureRequirements = [];
  const runtimeExpectations = [];
  const externalSourceRequirements = [];

  if (crg.nodes.length === 0) {
    warnings.push({
      code: "EMPTY_RUNTIME_GRAPH",
      message: "Runtime graph has zero nodes",
    });
  }

  const visitNodes = index.nodesOfType("VisitNode");

  for (const visitNode of visitNodes) {
    const visitId = visitNode.payload.visit_id;
    const visitCode = visitNode.payload.visit_code ?? visitId;
    const visitLabel = visitNode.payload.visit_label ?? visitCode;

    const sdvId = detId("sdv", graphId, visitNode.id, visitId);
    trackId(sdvId, `source_definition_versions/${visitId}`);

    const sdv = {
      source_definition_version_id: sdvId,
      graph_id: graphId,
      visit_node_id: visitNode.id,
      visit_id: visitId,
      visit_code: visitCode,
      visit_name: visitLabel,
      study_template_id: studyTemplateId,
      protocol_version: protocolVersion,
      cpst_version: crg.cpst_version,
      source_status: "draft_generated",
      generated_at: compiledAt,
      compiler_version: COMPILER_VERSION,
      input_hash: inputHash,
      provenance: provFrom(visitNode, crg),
      instrument_code: visitCode,
      version_label: crg.cpst_version ?? "v1.0.0",
      status: "draft",
    };
    sourceDefinitionVersions.push(sdv);
    provenanceMap[sdvId] = sdv.provenance;

    const procLinks = [];
    for (const e of index.outEdges(visitNode.id, VISIT_PROC_EDGE_TYPES)) {
      const proc = index.node(e.to);
      if (proc?.node_type === "ProcedureNode") {
        procLinks.push({ procedure: proc, edge: e });
      }
    }
    procLinks.sort((a, b) =>
      String(a.procedure.payload.procedure_id).localeCompare(String(b.procedure.payload.procedure_id))
    );

    if (procLinks.length === 0) {
      warnings.push({
        code: "VISIT_NO_PROCEDURES",
        message: `Visit ${visitId} has no assigned procedures`,
        path: visitNode.id,
      });
    }

    for (const { procedure: procNode, edge: visitProcEdge } of procLinks) {
      const procId = procNode.payload.procedure_id;
      const expectation = findExpectation(index, visitId, procId);
      const matrixMarker = expectation?.payload.matrix_marker ?? visitProcEdge.edge_type.replace("optional_for", "optional");
      const requiredStatus = matrixMarkerToRequiredness(matrixMarker);
      const sourceType = procNode.payload.source_type;
      const sigRequired = signatureRequiredFor(index, procNode, expectation);
      const fields = fieldsForProcedure(index, procNode);
      const detailedCapture = sourceType === "internal" || !isExternalSourceType(sourceType);

      const sectionId = detId("sec", graphId, sdvId, procNode.id);
      trackId(sectionId, `source_sections/${visitId}/${procId}`);

      const section = {
        source_section_id: sectionId,
        source_definition_version_id: sdvId,
        procedure_node_id: procNode.id,
        procedure_id: procId,
        section_code: procNode.payload.procedure_code ?? procId,
        section_name: procNode.payload.procedure_label ?? procId,
        section_order: expectation?.payload.execution_order ?? 0,
        source_type: sourceType,
        required_status: requiredStatus,
        detailed_capture_required: detailedCapture,
        external_reference_required: procNode.payload.external_reference_required === true,
        owner_role: procNode.payload.owner_role ?? null,
        signature_required: sigRequired,
        provenance: provFrom(procNode, crg),
        label: procNode.payload.procedure_label,
        sort_order: expectation?.payload.execution_order ?? 0,
      };
      sourceSections.push(section);
      provenanceMap[sectionId] = section.provenance;

      if (detailedCapture && fields.length === 0) {
        warnings.push({
          code: "SECTION_NO_FIELDS",
          message: `Procedure ${procId} on visit ${visitId} has detailed_capture_required but no FieldNodes`,
          path: sectionId,
        });
      }

      if (isExternalSourceType(sourceType)) {
        const extNodes = externalSourcesForProcedure(index, procNode);
        if (extNodes.length === 0) {
          errors.push({
            code: "EXTERNAL_SOURCE_MISSING",
            message: `External procedure ${procId} missing ExternalSourceNode / requirement`,
            path: sectionId,
          });
        }
        for (const ext of extNodes) {
          const extReqId = detId("ext", graphId, sectionId, ext.id);
          trackId(extReqId, `external_source_requirements/${ext.source_row_id}`);
          const extReq = {
            external_source_requirement_id: extReqId,
            source_definition_version_id: sdvId,
            source_section_id: sectionId,
            procedure_node_id: procNode.id,
            procedure_id: procId,
            external_source_name: ext.payload.system_name,
            external_system_type: sourceType,
            ref_id_field: ext.payload.reference_required ? "external_reference_id" : null,
            status_field: ext.payload.status_required ? "external_status" : null,
            attachment_allowed: ext.payload.attachment_allowed === true,
            audit_requirement: true,
            capture_strategy: "metadata_reference_only",
            provenance: provFrom(ext, crg),
          };
          externalSourceRequirements.push(extReq);
          provenanceMap[extReqId] = extReq.provenance;
        }
      }

      for (const fieldNode of fields) {
        const p = fieldNode.payload;
        if (!p.display_label || !p.data_type) {
          errors.push({
            code: "FIELD_MISSING_META",
            message: `Field ${p.field_key} missing display_label or data_type`,
            path: fieldNode.id,
          });
        }

        const fieldId = detId("fld", graphId, sectionId, fieldNode.id);
        trackId(fieldId, `source_fields/${p.field_key}`);

        const valNode = validationNodeForField(index, fieldNode);
        let validationRuleRef = null;
        if (valNode || p.validation_expression || p.is_required) {
          const vrId = detId("vr", graphId, sectionId, fieldNode.id);
          trackId(vrId, `validation_rules/${p.field_key}`);
          const vr = {
            validation_rule_id: vrId,
            source_field_id: fieldId,
            field_name: p.field_key,
            rule_type: p.is_required ? "required" : "expression",
            expression: p.validation_expression ?? valNode?.payload.validation_expression ?? null,
            provenance: provFrom(fieldNode, crg),
          };
          validationRules.push(vr);
          provenanceMap[vrId] = vr.provenance;
          validationRuleRef = vrId;
        }

        const sf = {
          source_field_id: fieldId,
          source_section_id: sectionId,
          source_definition_version_id: sdvId,
          field_name: p.field_key,
          field_key: p.field_key,
          display_label: p.display_label,
          data_type: p.data_type,
          input_type: p.data_type,
          required: p.is_required === true,
          is_required: p.is_required === true,
          min_value: p.min_value ?? null,
          max_value: p.max_value ?? null,
          min_length: p.min_length ?? null,
          max_length: p.max_length ?? null,
          allowed_list_name: p.option_list_code ?? null,
          options_manifest_key: p.option_list_code ?? null,
          default_value: p.default_value ?? null,
          validation_rule: validationRuleRef,
          conditional_visibility: p.conditional_visibility_rule_id ?? null,
          read_only: p.read_only === true,
          repeatable: p.repeatable === true,
          export_name: p.export_name ?? null,
          source_origin_mode: p.source_origin_mode ?? null,
          procedure_id: procId,
          section_code: p.section_code,
          label: p.display_label,
          provenance: provFrom(fieldNode, crg),
        };
        sourceFields.push(sf);
        provenanceMap[fieldId] = sf.provenance;
      }

      if (sigRequired) {
        const signers = signersForProcedure(index, procId);
        if (signers.length === 0) {
          errors.push({
            code: "SIGNATURE_NO_SIGNER",
            message: `Signature required for ${procId} on visit ${visitId} but no signer role`,
            path: sectionId,
          });
        }
        for (const role of signers) {
          const sigReqId = detId("sig", graphId, sectionId, role.id);
          trackId(sigReqId, `signature_requirements/${procId}/${role.source_row_id}`);
          const sigReq = {
            signature_requirement_id: sigReqId,
            source_definition_version_id: sdvId,
            source_section_id: sectionId,
            procedure_id: procId,
            role_code: role.payload.role_code,
            signature_meaning_code: role.payload.signature_meaning_code ?? "REVIEWED",
            provenance: provFrom(role, crg),
          };
          signatureRequirements.push(sigReq);
          provenanceMap[sigReqId] = sigReq.provenance;
        }
      }

      if (expectation) {
        const rexId = detId("rex", graphId, expectation.id);
        trackId(rexId, `runtime_expectations/${expectation.source_row_id}`);
        const rex = {
          runtime_expectation_id: rexId,
          source_definition_version_id: sdvId,
          source_section_id: sectionId,
          visit_id: visitId,
          procedure_id: procId,
          requiredness: requiredStatus,
          execution_order: expectation.payload.execution_order ?? 0,
          source_type: sourceType,
          expected_section_id: sectionId,
          conditionality: expectation.payload.condition_rule_id
            ? { conditional: true, rule_id: expectation.payload.condition_rule_id }
            : { conditional: false },
          provenance: provFrom(expectation, crg),
        };
        runtimeExpectations.push(rex);
        provenanceMap[rexId] = rex.provenance;
      }
    }
  }

  applyBiospecimenModuleEnrichment({
    graphId,
    crg,
    sourceFields,
    validationRules,
    provenanceMap,
    trackId,
    index,
    warnings,
  });

  for (const ruleNode of index.nodesOfType("RuleNode")) {
    const p = ruleNode.payload;
    const crId = detId("cr", graphId, ruleNode.id);
    trackId(crId, `conditional_rules/${p.rule_id}`);

    let appliesTo = p.trigger_entity ?? "study";
    let appliesToId = p.trigger_visit_id ?? p.trigger_procedure_id ?? studyTemplateId;

    const cond = {
      conditional_rule_id: crId,
      rule_id: p.rule_id,
      rule_name: p.rule_id,
      trigger_type: p.rule_type,
      trigger_field: p.trigger_procedure_id ? `procedure:${p.trigger_procedure_id}` : null,
      operator: "expr",
      trigger_value: null,
      expression: p.expression,
      then_action: p.action,
      applies_to: appliesTo,
      applies_to_id: appliesToId,
      priority: 100,
      hard_stop: p.action === "block",
      requires_review: p.workflow_hook != null || p.rule_type === "safety",
      provenance: provFrom(ruleNode, crg),
    };
    conditionalRules.push(cond);
    provenanceMap[crId] = cond.provenance;

    if (p.workflow_hook) {
      const wfId = detId("wf", graphId, ruleNode.id, p.workflow_hook);
      trackId(wfId, `workflow_requirements/${p.rule_id}`);
      const wf = {
        workflow_requirement_id: wfId,
        rule_id: p.rule_id,
        workflow_type: p.workflow_hook,
        trigger_expression: p.expression,
        requires_review: true,
        provenance: provFrom(ruleNode, crg),
      };
      workflowRequirements.push(wf);
      provenanceMap[wfId] = wf.provenance;
    }

    if (p.trigger_visit_id && !index.nodesOfType("VisitNode").some((v) => v.payload.visit_id === p.trigger_visit_id)) {
      errors.push({
        code: "CONDITIONAL_TARGET_MISSING",
        message: `Rule ${p.rule_id} trigger visit ${p.trigger_visit_id} not found`,
        path: crId,
      });
    }
    if (p.target_procedure_id && !index.nodesOfType("ProcedureNode").some((pr) => pr.payload.procedure_id === p.target_procedure_id)) {
      warnings.push({
        code: "CONDITIONAL_TARGET_PROCEDURE",
        message: `Rule ${p.rule_id} target procedure ${p.target_procedure_id} reference only`,
        path: crId,
      });
    }
  }

  for (const dom of index.nodesOfType("DomainModuleNode")) {
    if (dom.payload.module_id === BIOSPECIMEN_MODULE_ID && dom.payload.reviewer_required === true) {
      const wfId = detId("wf", graphId, dom.id, "biospecimen_review");
      if (!seenIds.has(wfId)) {
        trackId(wfId, `workflow_requirements/domain/${dom.source_row_id}`);
        const wf = {
          workflow_requirement_id: wfId,
          module_id: dom.payload.module_id,
          workflow_type: "BIOSPECIMEN_REVIEW",
          requires_review: true,
          provenance: biospecimenModuleProvenance(dom, "reviewer_required", "source_complete", crg),
        };
        workflowRequirements.push(wf);
        provenanceMap[wfId] = wf.provenance;
      }
    }
    if (dom.payload.rescue_workflow_required || dom.payload.module_id?.includes("epro")) {
      const wfId = detId("wf", graphId, dom.id, "domain");
      if (!seenIds.has(wfId)) {
        trackId(wfId, `workflow_requirements/domain/${dom.source_row_id}`);
        const wf = {
          workflow_requirement_id: wfId,
          module_id: dom.payload.module_id,
          workflow_type: "EPRO_RESCUE",
          requires_review: dom.payload.rescue_workflow_required === true,
          provenance: provFrom(dom, crg),
        };
        workflowRequirements.push(wf);
        provenanceMap[wfId] = wf.provenance;
      }
    }
  }

  const sortById = (a, b) => {
    const ka = a.source_definition_version_id ?? a.validation_rule_id ?? a.conditional_rule_id ?? a.workflow_requirement_id ?? a.signature_requirement_id ?? a.runtime_expectation_id ?? a.external_source_requirement_id ?? a.source_field_id ?? a.source_section_id ?? "";
    const kb = b.source_definition_version_id ?? b.validation_rule_id ?? b.conditional_rule_id ?? b.workflow_requirement_id ?? b.signature_requirement_id ?? b.runtime_expectation_id ?? b.external_source_requirement_id ?? b.source_field_id ?? b.source_section_id ?? "";
    return String(ka).localeCompare(String(kb));
  };

  sourceDefinitionVersions.sort((a, b) => a.source_definition_version_id.localeCompare(b.source_definition_version_id));
  sourceSections.sort((a, b) => a.source_section_id.localeCompare(b.source_section_id));
  sourceFields.sort((a, b) => a.source_field_id.localeCompare(b.source_field_id));
  validationRules.sort((a, b) => a.validation_rule_id.localeCompare(b.validation_rule_id));
  conditionalRules.sort((a, b) => a.conditional_rule_id.localeCompare(b.conditional_rule_id));
  workflowRequirements.sort((a, b) => a.workflow_requirement_id.localeCompare(b.workflow_requirement_id));
  signatureRequirements.sort((a, b) => a.signature_requirement_id.localeCompare(b.signature_requirement_id));
  runtimeExpectations.sort((a, b) => a.runtime_expectation_id.localeCompare(b.runtime_expectation_id));
  externalSourceRequirements.sort((a, b) =>
    a.external_source_requirement_id.localeCompare(b.external_source_requirement_id)
  );

  let validation_status = "valid";
  if (warnings.length > 0 && errors.length === 0) validation_status = "warning";
  if (errors.length > 0) validation_status = "invalid";

  const compilerOutputId = detId("cout", graphId, inputHash);
  const crgHash = `sha256:${shortHash([graphId, inputHash, String(crg.nodes.length), String(crg.edges.length)])}`;

  return {
    compiler_output_id: compilerOutputId,
    graph_id: graphId,
    input_hash: inputHash,
    crg_hash: crgHash,
    compiler_version: COMPILER_VERSION,
    schema_version: crg.schema_version,
    cpst_version: crg.cpst_version,
    study_template_id: studyTemplateId,
    compiled_at: compiledAt,
    deterministic: true,
    source_definition_versions: sourceDefinitionVersions,
    source_sections: sourceSections,
    source_fields: sourceFields,
    validation_rules: validationRules,
    conditional_rules: conditionalRules,
    workflow_requirements: workflowRequirements,
    signature_requirements: signatureRequirements,
    runtime_expectations: runtimeExpectations,
    external_source_requirements: externalSourceRequirements,
    provenance_map: provenanceMap,
    validation_report: {
      validation_status,
      passed: errors.length === 0,
      errors,
      warnings,
    },
    counts: {
      source_definition_versions: sourceDefinitionVersions.length,
      source_sections: sourceSections.length,
      source_fields: sourceFields.length,
      validation_rules: validationRules.length,
      conditional_rules: conditionalRules.length,
      workflow_requirements: workflowRequirements.length,
      signature_requirements: signatureRequirements.length,
      runtime_expectations: runtimeExpectations.length,
      external_source_requirements: externalSourceRequirements.length,
    },
  };
}

function main() {
  const args = parseArgs(process.argv);
  if (!existsSync(args.input)) {
    console.error("Input CRG not found:", args.input);
    process.exit(1);
  }

  const crg = loadJson(args.input);
  const out1 = compile(crg);
  const out2 = compile(crg);

  const sig1 = JSON.stringify({
    id: out1.compiler_output_id,
    sdv: out1.source_definition_versions.map((x) => x.source_definition_version_id),
    fld: out1.source_fields.map((x) => x.source_field_id),
  });
  const sig2 = JSON.stringify({
    id: out2.compiler_output_id,
    sdv: out2.source_definition_versions.map((x) => x.source_definition_version_id),
    fld: out2.source_fields.map((x) => x.source_field_id),
  });

  if (sig1 !== sig2) {
    console.error("Determinism check failed");
    process.exit(1);
  }

  mkdirSync(dirname(args.output), { recursive: true });
  writeFileSync(args.output, `${JSON.stringify(out1, null, 2)}\n`, "utf8");

  console.log("Compiler output ID:", out1.compiler_output_id);
  console.log("Validation:", out1.validation_report.validation_status);
  console.log("SDV:", out1.counts.source_definition_versions);
  console.log("Sections:", out1.counts.source_sections);
  console.log("Fields:", out1.counts.source_fields);
  console.log("Errors:", out1.validation_report.errors.length);
  console.log("Warnings:", out1.validation_report.warnings.length);
  console.log("Output:", relative(ROOT, args.output));

  if (args.strict && out1.validation_report.validation_status === "invalid") process.exit(1);
}

main();

/**
 * Phase 4C.13 — Dry-run validator for publish_source_package artifacts (no DB by default).
 *
 * Reads golden-basic publish handoff files and validates shape/hash alignment before RPC.
 *
 * Usage:
 *   node scripts/dry-run-publish-source-package.mjs
 *   node scripts/dry-run-publish-source-package.mjs --call-rpc \
 *     --organization-id <uuid> --study-id <uuid> --study-version-id <uuid> --actor-user-id <uuid>
 *
 * --call-rpc requires DATABASE_URL_DIRECT or DATABASE_URL (see scripts/apply-migrations.mjs).
 * RPC uses auth.uid(); direct Postgres sets request.jwt.claim.sub from --actor-user-id for staging QA only.
 */
import { readFileSync, existsSync } from 'node:fs'
import { resolve, join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'
import postgres from 'postgres'
import { loadEnvFiles, projectRoot } from './lib/env.mjs'

const ROOT = projectRoot

const DEFAULT_PACKAGE = join(ROOT, 'tmp/publish/source-publish-package.golden-basic.json')
const DEFAULT_SOURCE_DEFINITIONS = join(ROOT, 'tmp/compiled/source-definitions.golden-basic.json')
const DEFAULT_APPROVAL = join(ROOT, 'tmp/approvals/source-preview-approval.golden-basic.json')

const COUNT_KEYS = [
  'source_definition_versions',
  'source_sections',
  'source_fields',
  'validation_rules',
  'conditional_rules',
  'workflow_requirements',
  'signature_requirements',
  'runtime_expectations',
  'external_source_requirements',
]

const SOURCE_ARRAY_KEYS = [
  'source_definition_versions',
  'source_sections',
  'source_fields',
  'validation_rules',
  'conditional_rules',
  'workflow_requirements',
  'signature_requirements',
  'external_source_requirements',
  'runtime_expectations',
]

const HASH_RE = /^sha256:[0-9a-f]{64}$/i

function parseArgs(argv) {
  const args = {
    packagePath: DEFAULT_PACKAGE,
    sourceDefinitionsPath: DEFAULT_SOURCE_DEFINITIONS,
    approvalPath: DEFAULT_APPROVAL,
    callRpc: false,
    organizationId: null,
    studyId: null,
    studyVersionId: null,
    actorUserId: null,
  }

  for (let i = 2; i < argv.length; i++) {
    const a = argv[i]
    if (a === '--call-rpc') args.callRpc = true
    else if (a === '--package') args.packagePath = resolve(argv[++i])
    else if (a === '--source-definitions') args.sourceDefinitionsPath = resolve(argv[++i])
    else if (a === '--approval') args.approvalPath = resolve(argv[++i])
    else if (a === '--organization-id') args.organizationId = argv[++i]
    else if (a === '--study-id') args.studyId = argv[++i]
    else if (a === '--study-version-id') args.studyVersionId = argv[++i]
    else if (a === '--actor-user-id') args.actorUserId = argv[++i]
    else if (a === '--help' || a === '-h') {
      console.log(`Usage: node scripts/dry-run-publish-source-package.mjs [options]

Options:
  --package <path>
  --source-definitions <path>
  --approval <path>
  --call-rpc
  --organization-id <uuid>
  --study-id <uuid>
  --study-version-id <uuid>
  --actor-user-id <uuid>   (required with --call-rpc for auth.uid() simulation)
`)
      process.exit(0)
    } else {
      console.error('Unknown argument:', a)
      process.exit(1)
    }
  }

  return args
}

function loadJson(path, label) {
  if (!existsSync(path)) {
    throw new Error(`Missing ${label}: ${path}`)
  }
  return JSON.parse(readFileSync(path, 'utf8'))
}

function isUuid(value) {
  return typeof value === 'string' && /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(value)
}

function check(name, pass, detail) {
  return { name, pass, detail }
}

function assertHash(label, value, results) {
  if (!value || typeof value !== 'string') {
    results.push(check(label, false, 'missing'))
    return
  }
  results.push(check(label, HASH_RE.test(value), value))
}

function arrayLen(obj, key) {
  const v = obj?.[key]
  return Array.isArray(v) ? v.length : 0
}

function validateArtifacts(pkg, defs, approval) {
  const results = []

  results.push(check('package_id', Boolean(pkg?.package_id?.trim()), pkg?.package_id ?? 'missing'))
  results.push(check('publish_ready', pkg?.publish_ready === true, String(pkg?.publish_ready)))
  results.push(check('approval_id', Boolean(pkg?.approval_id?.trim()), pkg?.approval_id ?? 'missing'))
  results.push(check('graph_id', Boolean(pkg?.graph_id?.trim()), pkg?.graph_id ?? 'missing'))
  results.push(check('compiler_output_id', Boolean(pkg?.compiler_output_id?.trim()), pkg?.compiler_output_id ?? 'missing'))

  assertHash('package.source_definitions_hash', pkg?.source_definitions_hash, results)
  assertHash('package.preview_hash', pkg?.preview_hash, results)
  assertHash('package.approval_hash', pkg?.approval_hash, results)
  assertHash('package.input_hash', pkg?.input_hash, results)

  results.push(check('approval.decision', approval?.decision === 'approved', String(approval?.decision)))
  results.push(check('approval.publish_eligible', approval?.publish_eligible === true, String(approval?.publish_eligible)))
  results.push(
    check(
      'approval_id_match',
      pkg?.approval_id === approval?.approval_id,
      `package=${pkg?.approval_id} approval=${approval?.approval_id}`,
    ),
  )

  results.push(
    check(
      'source_definitions_hash_match',
      pkg?.source_definitions_hash === approval?.source_definitions_hash,
      `${pkg?.source_definitions_hash} vs ${approval?.source_definitions_hash}`,
    ),
  )

  if (defs?.source_definitions_hash) {
    results.push(
      check(
        'defs_embedded_hash',
        pkg?.source_definitions_hash === defs.source_definitions_hash,
        `${pkg?.source_definitions_hash} vs ${defs.source_definitions_hash}`,
      ),
    )
  }

  results.push(
    check(
      'preview_hash_match',
      pkg?.preview_hash === approval?.preview_hash,
      `${pkg?.preview_hash} vs ${approval?.preview_hash}`,
    ),
  )

  results.push(
    check(
      'graph_alignment',
      pkg?.graph_id === defs?.graph_id &&
        pkg?.input_hash === defs?.input_hash &&
        pkg?.compiler_output_id === defs?.compiler_output_id,
      'package graph metadata must match source-definitions',
    ),
  )

  if (approval?.graph_id) {
    results.push(check('approval_graph_id', pkg?.graph_id === approval.graph_id, `${pkg?.graph_id} vs ${approval.graph_id}`))
  }

  const pkgErrors = pkg?.validation_snapshot?.errors ?? []
  const defErrors = defs?.validation_report?.errors ?? []
  results.push(check('package.validation_snapshot.errors', Array.isArray(pkgErrors) && pkgErrors.length === 0, `count=${pkgErrors?.length ?? 'n/a'}`))
  results.push(check('defs.validation_report.errors', Array.isArray(defErrors) && defErrors.length === 0, `count=${defErrors?.length ?? 'n/a'}`))
  results.push(check('defs.validation_report.passed', defs?.validation_report?.passed === true, String(defs?.validation_report?.passed)))

  const status = defs?.validation_report?.validation_status ?? pkg?.validation_snapshot?.validation_status
  results.push(check('validation_status', status === 'valid' || status === 'warning', String(status)))

  for (const key of COUNT_KEYS) {
    const expected = pkg?.counts?.[key]
    const actual = arrayLen(defs, key)
    if (expected == null) {
      results.push(check(`counts.${key}`, false, 'missing in package.counts'))
    } else {
      results.push(check(`counts.${key}`, Number(expected) === actual, `expected=${expected} actual=${actual}`))
    }
  }

  for (const key of SOURCE_ARRAY_KEYS) {
    results.push(check(`defs.${key}`, Array.isArray(defs?.[key]), `len=${arrayLen(defs, key)}`))
  }

  return results
}

function pickDatabaseUrl() {
  loadEnvFiles()
  const direct = process.env.DATABASE_URL_DIRECT?.trim()
  const pooled = process.env.DATABASE_URL?.trim()
  return direct || pooled || null
}

async function callRpc(args, pkg, defs, approval) {
  const url = pickDatabaseUrl()
  if (!url) {
    console.log('\n--call-rpc skipped: set DATABASE_URL_DIRECT or DATABASE_URL in .env.local')
    return { skipped: true }
  }

  for (const [label, value] of [
    ['organization-id', args.organizationId],
    ['study-id', args.studyId],
    ['study-version-id', args.studyVersionId],
    ['actor-user-id', args.actorUserId],
  ]) {
    if (!isUuid(value)) {
      throw new Error(`--call-rpc requires --${label} <uuid>`)
    }
  }

  const sql = postgres(url, {
    prepare: url.includes('pooler.supabase.com') ? false : undefined,
    max: 1,
  })

  try {
    await sql`select set_config('role', 'authenticated', true)`
    await sql`select set_config('request.jwt.claim.sub', ${args.actorUserId}, true)`

    const rows = await sql`
      select public.publish_source_package(
        ${args.organizationId}::uuid,
        ${args.studyId}::uuid,
        ${args.studyVersionId}::uuid,
        ${sql.json(pkg)}::jsonb,
        ${sql.json(defs)}::jsonb,
        ${sql.json(approval)}::jsonb
      ) as result
    `

    return { skipped: false, result: rows[0]?.result }
  } finally {
    await sql.end({ timeout: 5 })
  }
}

async function main() {
  const args = parseArgs(process.argv)
  const pkg = loadJson(args.packagePath, 'publish package')
  const defs = loadJson(args.sourceDefinitionsPath, 'source definitions')
  const approval = loadJson(args.approvalPath, 'approval')

  const results = validateArtifacts(pkg, defs, approval)
  const failed = results.filter((r) => !r.pass)

  console.log('Phase 4C.13 dry-run — publish_source_package artifacts')
  console.log('  package:', args.packagePath)
  console.log('  source_definitions:', args.sourceDefinitionsPath)
  console.log('  approval:', args.approvalPath)
  console.log('')

  for (const r of results) {
    console.log(`${r.pass ? 'PASS' : 'FAIL'}  ${r.name}${r.detail ? ` — ${r.detail}` : ''}`)
  }

  console.log('')
  console.log(`Summary: ${results.length - failed.length}/${results.length} checks passed`)

  if (failed.length) {
    process.exit(1)
  }

  if (args.callRpc) {
    const rpc = await callRpc(args, pkg, defs, approval)
    if (!rpc.skipped) {
      console.log('\nRPC result:')
      console.log(JSON.stringify(rpc.result, null, 2))
    }
  } else {
    console.log('\nDB: not connected (default). Use --call-rpc with tenant UUIDs + DATABASE_URL_* for staging RPC test.')
  }
}

main().catch((err) => {
  console.error(err.message || err)
  process.exit(1)
})

