    callRpc(tx, 'sign_visit_investigator_closeout', [
      orgId,
      visitId,
      'principal_investigator',
      'Phase11B Proof Coordinator',
    ]),
  )
  const pi = await withActor(piId, (tx) =>
    callRpc(tx, 'sign_visit_investigator_closeout', [
      orgId,
      visitId,
      'principal_investigator',
      'Phase11B Proof PI',
