            ${study.organization_id}, ${studyId}, ${'P11D-ARMB-' + suffix}, 'Arm B only', 9903, 3,
            array['Arm B']::text[]
          ) returning id
        `
        const [vdIndex] = await tx`
          insert into visit_definitions (
            organization_id, study_id, code, label, sort_order, target_day,
