        }

        const rowsArmA = await codes(subjArmA.id, 'P11E-PARA-')
        const rowsArmB = await codes(subjArmB.id, 'P11E-PARA-')
        const codesArmA = rowsArmA.map((r) => r.code)
        const codesArmB = rowsArmB.map((r) => r.code)
        const codesIndex = (await codes(mv.subjIndex.id, 'P11E-MV-')).map((r) => r.code)
        const codesContact = (await codes(mv.subjContact.id, 'P11E-MV-')).map((r) => r.code)
        const modalityArmAVisit = rowsArmA.find((r) => r.code.includes('PARA-ARMA-'))?.modality
        const [defModArmA] = await tx`
          select modality from visit_definitions
          where study_id = ${studyId} and code = ${'P11E-PARA-ARMA-' + suffix}
        `
        const modalityArmA = modalityArmAVisit ?? defModArmA?.modality

        const peBefore = async (subjectId, code) => {
          const [row] = await tx`
            select count(*)::int as c
            from procedure_executions pe
            join visits v on v.id = pe.visit_id
            join visit_definitions vd on vd.id = v.visit_definition_id
            where v.study_subject_id = ${subjectId} and vd.code = ${code}
          `
          return row.c
        }

        const condBefore = await peBefore(participant.id, `P11E-PARA-COND-${suffix}`)
        const [visitCond] = await tx`
          select v.id from visits v
          join visit_definitions vd on vd.id = v.visit_definition_id
          where v.study_subject_id = ${participant.id}
            and vd.code = ${'P11E-PARA-COND-' + suffix}
          limit 1
        `
        let instantiate = null
        if (visitCond) {
          await tx`select set_config('role', 'authenticated', true)`
          await tx`select set_config('request.jwt.claim.sub', ${coord.id}, true)`
          instantiate = await callRpc(tx, 'instantiate_conditional_procedure_execution', [
            orgId,
            visitCond.id,
            para.mapCond.id,
          ])
        }
        const condAfter = await peBefore(participant.id, `P11E-PARA-COND-${suffix}`)
        const events = visitCond
          ? await tx`
              select event_type from operational_events
              where visit_id = ${visitCond.id}
                and event_type = 'CONDITIONAL_PROCEDURE_INSTANTIATED'
            `
          : []

        const pilotAfter = (
          await tx`select count(*)::int as c from visits where study_subject_id = ${pilot.id}`
        )[0].c

        const dupes = await tx`
          select study_subject_id, visit_definition_id, count(*)::int as c
          from visits
          where study_subject_id in (
            ${participant.id}, ${subjArmA.id}, ${subjArmB.id},
            ${mv.subjIndex.id}, ${mv.subjContact.id}
          )
            and visit_status not in ('cancelled', 'missed', 'no_show')
          group by 1, 2
          having count(*) > 1
        `

        const contactHousehold = (
          await tx`select household_id from study_subjects where id = ${mv.subjContact.id}`
        )[0].household_id
        const contactAnchor = (
          await tx`select anchor_subject_id from study_subjects where id = ${mv.subjContact.id}`
        )[0].anchor_subject_id
        const mvHouseholdMatch =
          mv.householdId != null && mv.householdId === contactHousehold
        const mvAnchor = contactAnchor === mv.subjIndex.id

        captured = {
          suffix,
          participant_role: participant.subject_role,
          mv_household_match: mvHouseholdMatch,
          mv_anchor: mvAnchor,
          codesArmA,
          codesArmB,
          codesIndex,
          codesContact,
          modalityArmA,
          condBefore,
          condAfter,
          instantiate,
          eventCount: events.length,
          pilotVisitDelta: pilotAfter - pilotVisitCountBefore,
          duplicate_active_visits: dupes.length,
          gates: {
            participant_default: { pass: participant.subject_role === 'participant' },
            pilot_regression: { pass: pilotVisitCountBefore === pilotAfter },
            role_index_vs_contact: {
              pass:
                codesIndex.includes(`P11E-MV-IDX-${suffix}`)
                && !codesIndex.includes(`P11E-MV-CNT-${suffix}`)
                && codesContact.includes(`P11E-MV-CNT-${suffix}`)
                && !codesContact.includes(`P11E-MV-IDX-${suffix}`),
            },
            arm_split: {
              pass:
                codesArmA.includes(`P11E-PARA-ARMA-${suffix}`)
                && codesArmA.includes(`P11E-PARA-COMMON-${suffix}`)
                && !codesArmA.includes(`P11E-PARA-ARMB-${suffix}`)
                && codesArmB.includes(`P11E-PARA-ARMB-${suffix}`)
                && codesArmB.includes(`P11E-PARA-COMMON-${suffix}`)
                && !codesArmB.includes(`P11E-PARA-ARMA-${suffix}`),
            },
            modality: { pass: modalityArmA === 'phone' || defModArmA?.modality === 'phone' },
            conditional_not_auto: { pass: condBefore === 0 },
            conditional_instantiate: {
              pass: Boolean(instantiate?.ok) && condAfter === 1,
            },
            event_logged: { pass: events.length >= 1 },
            mv_household_anchor: {
              pass: mvHouseholdMatch && mvAnchor,
            },
            no_duplicates: { pass: dupes.length === 0 },
          },
        }

        throw new Error('ROLLBACK_PROBE')
      })
    } catch (err) {
      if (err.message !== 'ROLLBACK_PROBE') throw err
    }

    report.probe = captured
    report.gates = captured?.gates ?? {}
    console.log(JSON.stringify(report, null, 2))
  } catch (err) {
    report.error = err.message
    console.log(JSON.stringify(report, null, 2))
  } finally {
    await sql.end()
  }
}

main()

/**
 * Phase 11F-B — MV40618 operational buildout verification + PARA regression.
 */
import { readFileSync } from 'node:fs'
import { join } from 'node:path'
import postgres from 'postgres'
import { loadEnvFiles, projectRoot } from './lib/env.mjs'

loadEnvFiles()
const url = process.env.DATABASE_URL_DIRECT || process.env.DATABASE_URL
const sql = postgres(url, {
  ssl: 'require',
  max: 1,
  prepare: url.includes('pooler') ? false : undefined,
})

const mvManifest = JSON.parse(
  readFileSync(join(projectRoot, 'fixtures/mv40618/runtime-manifest.v1.json'), 'utf8'),
)
const paraManifest = JSON.parse(
  readFileSync(join(projectRoot, 'fixtures/para-oa-012/runtime-manifest.v1.json'), 'utf8'),
)

const QA_COORD = 'rbac.qa.research_coordinator@vilo-os.staging'
const STUDY_ID = mvManifest.study.host_study_id
const ORG_ID = mvManifest.study.organization_id

async function callRpc(tx, fnName, values) {
  const placeholders = values.map((_, i) => `$${i + 1}`).join(', ')
  const rows = await tx.unsafe(`select public.${fnName}(${placeholders}) as result`, values)
  return rows[0]?.result
}

function addDays(iso, offset) {
  const d = new Date(`${iso}T12:00:00`)
  d.setDate(d.getDate() + offset)
  return d.toISOString().slice(0, 10)
}

async function main() {
  const report = { phase: '11F-B-proof', gates: {} }
  try {
    const [coord] = await sql`select id from auth.users where email = ${QA_COORD}`
    if (!coord) {
      report.error = 'QA coordinator missing'
      console.log(JSON.stringify(report, null, 2))
      await sql.end()
      process.exit(1)
    }

    const mvVisitCount = (
      await sql`select count(*)::int as c from visit_definitions where study_id = ${STUDY_ID} and code like 'MV_%'`
    )[0].c
    const mvBindings = (
      await sql`
        select count(*)::int as c from procedure_source_bindings psb
        join procedure_definitions pd on pd.id = psb.procedure_definition_id
        where psb.study_id = ${STUDY_ID} and pd.code like 'PROC_MV_%'
      `
    )[0].c
    const ready = await callRpc(sql, 'phase11fa_study_runtime_ready_for_schedule', [STUDY_ID])

    report.mvVisitDefCount = mvVisitCount
    report.mvBindings = mvBindings
    report.readiness = ready

    let mvProbe = null
    let paraProbe = null
    try {
      await sql.begin(async (tx) => {
        const suffix = Date.now().toString().slice(-6)
        const anchor = addDays(new Date().toISOString().slice(0, 10), 0)
        const householdId = crypto.randomUUID()

        const [subjIndex] = await tx`
          insert into study_subjects (
            organization_id, study_id, subject_identifier, enrollment_status,
            subject_role, household_id, schedule_anchor_date
          ) values (
            ${ORG_ID}, ${STUDY_ID}, ${'11FB-IDX-' + suffix}, 'enrolled',
            'index_patient', ${householdId}, ${anchor}
          ) returning id, household_id
        `
        const [subjContact] = await tx`
          insert into study_subjects (
            organization_id, study_id, subject_identifier, enrollment_status,
            subject_role, household_id, anchor_subject_id, schedule_anchor_date
          ) values (
            ${ORG_ID}, ${STUDY_ID}, ${'11FB-CNT-' + suffix}, 'enrolled',
            'household_contact', ${householdId}, ${subjIndex.id}, ${anchor}
          ) returning id, household_id, anchor_subject_id
        `

        const gen = async (id) => {
          await tx`select set_config('role', 'authenticated', true)`
          await tx`select set_config('request.jwt.claim.sub', ${coord.id}, true)`
          return callRpc(tx, 'generate_subject_visit_schedule', [id, anchor, true])
        }

        const genIdx = await gen(subjIndex.id)
        const genCnt = await gen(subjContact.id)

        const rows = async (subjectId) =>
          tx`
            select vd.code, v.modality, v.id as visit_id
            from visits v
            join visit_definitions vd on vd.id = v.visit_definition_id
            where v.study_subject_id = ${subjectId}
              and vd.code like 'MV_%'
              and v.visit_status not in ('cancelled', 'missed', 'no_show')
            order by vd.sort_order
          `

        const listIdx = await rows(subjIndex.id)
        const listCnt = await rows(subjContact.id)
        const codesIdx = listIdx.map((r) => r.code)
        const codesCnt = listCnt.map((r) => r.code)

        const sickVisit = listIdx.find((r) => r.code === 'MV_SICK_UNSCHED')
        const remoteVisit = listIdx.find((r) => r.code === 'MV_REMOTE_SYMPTOM')

        const [mapSick] = sickVisit
          ? await tx`
              select m.id from visit_def_procedure_map m
              join visit_definitions vd on vd.id = m.visit_definition_id
              join procedure_definitions pd on pd.id = m.procedure_definition_id
              where vd.code = 'MV_SICK_UNSCHED' and pd.code = 'PROC_MV_SICK_ASSESS'
            `
          : [null]

        const peSickBefore = sickVisit
          ? (
              await tx`
                select count(*)::int as c from procedure_executions pe
                join procedure_definitions pd on pd.id = pe.procedure_definition_id
                where pe.visit_id = ${sickVisit.visit_id} and pd.code = 'PROC_MV_SICK_ASSESS'
              `
            )[0].c
          : 0

        const peExtraBefore = remoteVisit
          ? (
              await tx`
                select count(*)::int as c from procedure_executions pe
                join procedure_definitions pd on pd.id = pe.procedure_definition_id
                where pe.visit_id = ${remoteVisit.visit_id} and pd.code = 'PROC_MV_EXTRA_SWAB'
              `
            )[0].c
          : 0

        let instSick = null
        if (sickVisit && mapSick) {
          await tx`select set_config('role', 'authenticated', true)`
          await tx`select set_config('request.jwt.claim.sub', ${coord.id}, true)`
          instSick = await callRpc(tx, 'instantiate_conditional_procedure_execution', [
            ORG_ID,
            sickVisit.visit_id,
            mapSick.id,
          ])
        }

        const peSickAfter = sickVisit
          ? (
              await tx`
                select count(*)::int as c from procedure_executions pe
                join procedure_definitions pd on pd.id = pe.procedure_definition_id
                where pe.visit_id = ${sickVisit.visit_id} and pd.code = 'PROC_MV_SICK_ASSESS'
              `
            )[0].c
          : 0

        const capturePe = listIdx.find((r) => r.code === 'MV_SCR')
          ? (
              await tx`
                select pe.id, pe.source_definition_version_id
                from procedure_executions pe
                join visits v on v.id = pe.visit_id
                join visit_definitions vd on vd.id = v.visit_definition_id
                join procedure_definitions pd on pd.id = pe.procedure_definition_id
                where v.study_subject_id = ${subjIndex.id}
                  and vd.code = 'MV_SCR'
                  and pd.code = 'PROC_MV_CONSENT'
                limit 1
              `
            )[0]
          : null

        const dupes = await tx`
          select count(*)::int as c from (
            select study_subject_id, visit_definition_id
            from visits
            where study_subject_id in (${subjIndex.id}, ${subjContact.id})
              and visit_status not in ('cancelled', 'missed', 'no_show')
            group by 1, 2 having count(*) > 1
          ) d
        `

        const paraOnIndex = (
          await tx`
            select count(*)::int as c
            from visits v
            join visit_definitions vd on vd.id = v.visit_definition_id
            where v.study_subject_id = ${subjIndex.id} and vd.code like 'PARA_%'
          `
        )[0].c

        const [subjParaA] = await tx`
          insert into study_subjects (
            organization_id, study_id, subject_identifier, enrollment_status,
            subject_role, randomization_arm, schedule_anchor_date
          ) values (
            ${ORG_ID}, ${STUDY_ID}, ${'11FB-PARA-A-' + suffix}, 'enrolled',
            'participant', 'Arm A', ${anchor}
          ) returning id
        `
        const genParaA = await gen(subjParaA.id)
        const paraCodes = (
          await tx`
            select vd.code from visits v
            join visit_definitions vd on vd.id = v.visit_definition_id
            where v.study_subject_id = ${subjParaA.id} and vd.code like 'PARA_%'
          `
        ).map((r) => r.code)

        mvProbe = {
          genIdx,
          genCnt,
          codesIdx,
          codesCnt,
          householdMatch: subjContact.household_id === subjIndex.household_id,
          anchorMatch: subjContact.anchor_subject_id === subjIndex.id,
          modalityHomeIdx: listIdx.find((r) => r.code === 'MV_HOME_SWAB_IDX')?.modality,
          modalityRemote: listIdx.find((r) => r.code === 'MV_REMOTE_SYMPTOM')?.modality,
          peSickBefore,
          peExtraBefore,
          peSickAfter,
          instSick,
          captureReady: Boolean(capturePe?.source_definition_version_id),
          dupes: dupes[0].c,
          paraOnIndex,
        }

        paraProbe = {
          genParaA,
          paraCodes,
          armAOnly:
            paraCodes.includes('PARA_ARM_A_MON')
            && !paraCodes.includes('PARA_ARM_B_MON')
            && paraCodes.includes('PARA_SCR'),
        }

        throw new Error('ROLLBACK_PROBE')
      })
    } catch (err) {
      if (err.message !== 'ROLLBACK_PROBE') throw err
    }

    report.mvProbe = mvProbe
    report.paraProbe = paraProbe
    report.gates = {
      mv_defs_loaded: { pass: mvVisitCount >= 10 },
      mv_bindings: { pass: mvBindings >= 10 },
      readiness_rpc: { pass: ready?.ok === true },
      schedule_gen: {
        pass: mvProbe?.genIdx?.ok === true && mvProbe?.genCnt?.ok === true,
      },
      role_split_index: {
        pass:
          mvProbe?.codesIdx?.includes('MV_SCR')
          && mvProbe?.codesIdx?.includes('MV_HOME_SWAB_IDX')
          && !mvProbe?.codesIdx?.includes('MV_CNT_ENROLL')
          && !mvProbe?.codesIdx?.includes('MV_HOME_SWAB_CNT'),
      },
      role_split_contact: {
        pass:
          mvProbe?.codesCnt?.includes('MV_CNT_ENROLL')
          && mvProbe?.codesCnt?.includes('MV_HOME_SWAB_CNT')
          && !mvProbe?.codesCnt?.includes('MV_SCR')
          && !mvProbe?.codesCnt?.includes('MV_HOME_SWAB_IDX'),
      },
      shared_common_visits: {
        pass:
          mvProbe?.codesIdx?.includes('MV_PHONE_WK2')
          && mvProbe?.codesCnt?.includes('MV_PHONE_WK2')
          && mvProbe?.codesIdx?.includes('MV_EOS')
          && mvProbe?.codesCnt?.includes('MV_EOS'),
      },
      household_linkage: {
        pass: mvProbe?.householdMatch === true && mvProbe?.anchorMatch === true,
      },
      modalities: {
        pass: mvProbe?.modalityHomeIdx === 'home' && mvProbe?.modalityRemote === 'remote',
      },
      conditional_not_auto: {
        pass: mvProbe?.peSickBefore === 0 && mvProbe?.peExtraBefore === 0,
      },
      conditional_instantiate: {
        pass: mvProbe?.instSick?.ok === true && mvProbe?.peSickAfter === 1,
      },
      source_binding_on_pe: { pass: mvProbe?.captureReady === true },
      no_duplicate_visits: { pass: (mvProbe?.dupes ?? 1) === 0 },
      para_not_on_index: { pass: (mvProbe?.paraOnIndex ?? 1) === 0 },
      para_regression: {
        pass: paraProbe?.genParaA?.ok === true && paraProbe?.armAOnly === true,
      },
    }

    console.log(JSON.stringify(report, null, 2))
    const allPass = Object.values(report.gates).every((g) => g.pass)
    process.exit(allPass ? 0 : 1)
  } catch (err) {
    report.error = err.message
    console.log(JSON.stringify(report, null, 2))
    process.exit(1)
  } finally {
    await sql.end()
  }
}

main()

/**
 * Phase 12D — intake review workspace smoke (no browser).
 * Run: npx tsx scripts/phase12d-intake-review-smoke.ts
 */
import { existsSync, readFileSync, rmSync } from 'node:fs'
import { join } from 'node:path'
import { buildApprovedDraft, writeApprovedArtifacts } from '@/lib/protocol-intake-review/approve'
import { discoverIntakePackages, loadIntakePackage } from '@/lib/protocol-intake-review/load-package'
import { workspaceDir } from '@/lib/protocol-intake-review/paths'
import { createInitialWorkspace, loadWorkspace, saveWorkspace } from '@/lib/protocol-intake-review/workspace'

type Gate = { name: string; pass: boolean; detail?: string }

function gate(name: string, pass: boolean, detail?: string): Gate {
  return { name, pass, detail }
}

function main() {
  const gates: Gate[] = []
  const root = process.cwd()

  const packages = discoverIntakePackages(root)
  gates.push(gate('discovers intake package', packages.length > 0, String(packages.length)))

  const draftKey =
    packages.find((p) => p.draft_key.includes('para'))?.draft_key ?? packages[0]?.draft_key
  if (!draftKey) {
    console.log(JSON.stringify({ gates, error: 'no package' }, null, 2))
    process.exit(1)
  }

  const pkg = loadIntakePackage(draftKey, root)
  gates.push(gate('loads review package', Boolean(pkg)))
  if (!pkg) process.exit(1)

  gates.push(
    gate('study metadata items', pkg.items.some((i) => i.section === 'study_metadata')),
    gate(
      'visit items with evidence',
      pkg.items.some((i) => i.section === 'visits' && (i.fields[0]?.evidence_refs.length ?? 0) > 0),
    ),
  )

  const wsDir = workspaceDir(root, draftKey)
  if (existsSync(wsDir)) rmSync(wsDir, { recursive: true })
  const ws = createInitialWorkspace(pkg)

  const metaItem = pkg.items.find((i) => i.item_id === 'meta:protocol_title')
  gates.push(gate('metadata field present', Boolean(metaItem)))
  if (!metaItem) process.exit(1)

  const metaState = ws.items[metaItem.item_id]
  metaState.field_overrides.protocol_title = 'Edited Title for Smoke'
  metaState.reviewer_status = 'edited'
  metaState.edit_reason = 'Coordinator correction'
  ws.audit.push({
    item_id: metaItem.item_id,
    field_name: 'protocol_title',
    original_value: metaItem.fields[0].original_extracted_value,
    edited_value: 'Edited Title for Smoke',
    edit_reason: 'Coordinator correction',
    reviewer_status: 'edited',
    reviewer_id: 'smoke-reviewer',
    timestamp: '2026-05-22T12:00:00.000Z',
    evidence_refs: metaItem.fields[0].evidence_refs,
  })

  const visitItem = pkg.items.find((i) => i.section === 'visits')
  if (visitItem) ws.items[visitItem.item_id].reviewer_status = 'accepted'

  const procItems = pkg.items.filter((i) => i.section === 'procedures')
  const procItem = procItems[0]
  const lowItem = procItems.find((i) =>
    i.fields.some((f) => f.requires_human_review),
  )
  if (procItem) ws.items[procItem.item_id].reviewer_status = 'rejected'
  if (lowItem && lowItem.item_id !== procItem?.item_id) {
    ws.items[lowItem.item_id].evidence_insufficient = true
    ws.items[lowItem.item_id].reviewer_status = 'needs_clarification'
    gates.push(gate('mark evidence insufficient', ws.items[lowItem.item_id].evidence_insufficient))
  }

  for (const item of pkg.items) {
    if (
      item.section === 'study_metadata'
      || item.section === 'visits'
      || item.section === 'procedures'
      || item.section === 'source_composition'
      || item.section === 'eligibility'
    ) {
      const st = ws.items[item.item_id]
      if (st.reviewer_status === 'rejected') continue
      if (st.reviewer_status === 'pending' || st.reviewer_status === 'needs_clarification') {
        st.reviewer_status = 'accepted'
      }
    }
  }

  for (const section of [
    'study_metadata',
    'visits',
    'procedures',
    'source_composition',
    'eligibility',
  ] as const) {
    ws.sections[section].section_status = 'approved'
    ws.sections[section].approved_at = '2026-05-22T12:00:00.000Z'
    ws.sections[section].approved_by = 'smoke-reviewer'
  }

  saveWorkspace(ws, root)

  const approved = buildApprovedDraft(pkg, ws, 'smoke-reviewer')
  writeApprovedArtifacts(pkg, approved, ws, root)

  const approvedPath = join(wsDir, 'approved_intake_draft.json')
  const auditPath = join(wsDir, 'review_audit.json')
  gates.push(
    gate('approved_intake_draft.json exists', existsSync(approvedPath)),
    gate('review_audit.json exists', existsSync(auditPath)),
  )

  const approvedJson = JSON.parse(readFileSync(approvedPath, 'utf8')) as {
    safety: { auto_publish: boolean; auto_bind: boolean; runtime_mutation: boolean }
    rejected_items: unknown[]
    edit_history: unknown[]
    study_metadata: { protocol_title?: string }
    procedures: Array<{ item_id: string }>
  }

  gates.push(
    gate('safety auto_publish false', approvedJson.safety.auto_publish === false),
    gate('safety auto_bind false', approvedJson.safety.auto_bind === false),
    gate('safety runtime_mutation false', approvedJson.safety.runtime_mutation === false),
    gate('rejected items retained', Array.isArray(approvedJson.rejected_items)),
    gate('edit history retained', (approvedJson.edit_history?.length ?? 0) > 0),
    gate(
      'edited title in approved metadata',
      approvedJson.study_metadata?.protocol_title === 'Edited Title for Smoke',
    ),
    gate(
      'rejected procedure excluded from list',
      !approvedJson.procedures?.some((p) => p.item_id === procItem?.item_id),
    ),
  )

  const failed = gates.filter((g) => !g.pass)
  console.log(
    JSON.stringify(
      {
        phase: '12D-intake-review-smoke',
        draft_key: draftKey,
        gates,
        summary: { passed: gates.length - failed.length, failed: failed.length },
      },
      null,
      2,
    ),
  )
  process.exit(failed.length > 0 ? 1 : 0)
}

main()

/**
 * Validates DB RLS helpers respect organization_members.status.
 *
 * Usage: node scripts/validate-active-membership-rls.mjs
 *
 * Requires .env.local with Supabase URL, anon key, service role key.
 */
import { createClient } from '@supabase/supabase-js'
import { createBrowserClient } from '@supabase/ssr'
import { serializeCookieHeader } from '@supabase/ssr'
import { loadEnvFiles } from './lib/env.mjs'
import { SYNTHETIC } from './lib/source-api-e2e.mjs'

loadEnvFiles()

const url = process.env.NEXT_PUBLIC_SUPABASE_URL
const anon = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
