function parseArgs(argv) {
  const args = {
    live: false,
    baseUrl: process.env.E2E_API_BASE_URL?.trim() || 'http://localhost:3000',
    organizationId: null,
    studyId: null,
    studyVersionId: null,
    studySubjectId: null,
    visitId: null,
    procedureExecutionId: null,
    orgBId: null,
    fresh: false,
  }

  for (let i = 2; i < argv.length; i++) {
    const a = argv[i]
    const next = () => argv[++i]
    if (a === '--live') args.live = true
    else if (a === '--fresh') args.fresh = true
    else if (a === '--base-url') args.baseUrl = next()
    else if (a === '--organization-id') args.organizationId = next()
    else if (a === '--study-id') args.studyId = next()
    else if (a === '--study-version-id') args.studyVersionId = next()
    else if (a === '--study-subject-id') args.studySubjectId = next()
    else if (a === '--visit-id') args.visitId = next()
    else if (a === '--procedure-execution-id') args.procedureExecutionId = next()
    else if (a === '--org-b-id') args.orgBId = next()
    else if (a === '--help' || a === '-h') {
      printHelp()
      process.exit(0)
    } else {
      console.error('Unknown argument:', a)
      printHelp()
      process.exit(1)
    }
  }
  return args
}

function printHelp() {
  console.log(`Phase 5.2E Capture shell E2E

Options:
  --live                         HTTP capture flow (requires npm run dev)
  --base-url <url>
  --organization-id <uuid>
  --study-id / --study-version-id / --study-subject-id / --visit-id
  --procedure-execution-id <uuid>   Skip discovery when provided
  --org-b-id <uuid>                 Cross-tenant probe
  --fresh                           Insert new visit + procedure_execution (no prior response set)

Live discovers a mutable procedure_execution when IDs omitted; use --fresh for a clean capture path.
`)
}

async function connectPostgres() {
  const postgres = (await import('postgres')).default
  const url = process.env.DATABASE_URL_DIRECT || process.env.DATABASE_URL
  if (!url) return null
  return postgres(url, {
    ssl: 'require',
    max: 1,
    prepare: url.includes('pooler') ? false : undefined,
  })
}

function runUnitSuite(report) {
  const modules = loadCaptureModules()
  const results = runCaptureUnitValidations(modules)
  for (const r of results) {
    report.steps.push(
      stepRecord(`unit_${r.id}`, r.ok ? 'pass' : 'fail', {
        detail: r.ok ? 'ok' : r.issues.join('; '),
        errors: r.ok ? null : r.issues,
      }),
    )
    if (r.ok) report.summary.passed++
    else report.summary.failed++
  }
  return results.every((r) => r.ok)
}

async function discoverOrgB(sql) {
  const rows = await sql`
    select id from public.organizations
    where name ilike '%Synthetic Site Beta%'
    limit 1
  `
  return rows[0]?.id ?? null
}

async function liveRun(args, report, sql, cookieHeader) {
  const base = args.baseUrl
  const orgId = args.organizationId

  let fixture = null
  if (
    args.procedureExecutionId &&
    args.studyId &&
    args.studyVersionId &&
    args.studySubjectId &&
    args.visitId
  ) {
    fixture = {
      procedureExecutionId: args.procedureExecutionId,
      studyId: args.studyId,
      studyVersionId: args.studyVersionId,
      studySubjectId: args.studySubjectId,
      visitId: args.visitId,
      sourceDefinitionVersionId: null,
    }
    const pe = await sql`
      select source_definition_version_id from public.procedure_executions
      where id = ${args.procedureExecutionId}::uuid
    `
    fixture.sourceDefinitionVersionId = pe[0]?.source_definition_version_id
    if (!fixture.sourceDefinitionVersionId) {
      report.steps.push(
        stepRecord('fixture_discover', 'blocked', {
          detail: 'procedure_execution has no source_definition_version_id',
        }),
      )
      report.summary.blocked++
      report.ok = false
      return
    }
  } else {
    fixture = await prepareCaptureFixture(sql, orgId, { fresh: args.fresh })
  }

  if (!fixture?.procedureExecutionId || !fixture.studyVersionId) {
    report.steps.push(
      stepRecord('fixture_discover', 'blocked', {
        detail: 'no mutable procedure_execution with SDV — bind SDV or pass --procedure-execution-id',
      }),
    )
    report.summary.blocked++
    report.ok = false
    return
  }

  report.steps.push(
    stepRecord('fixture_discover', 'pass', {
      detail: `pe=${fixture.procedureExecutionId} sdv=${fixture.sourceDefinitionVersionId}`,
      key_ids: {
        procedure_execution_id: fixture.procedureExecutionId,
        source_definition_version_id: fixture.sourceDefinitionVersionId,
      },
    }),
  )
  report.summary.passed++

  const ctx = {
    responseSetId: fixture.existingResponseSetId,
    fieldId: null,
    widgetHint: 'text',
    savedValue: `e2e-52e-capture-${Date.now()}`,
    submittedSnapshot: null,
  }

  const modules = loadCaptureModules()
  const rc = loadReadContract()

  async function readBundle(responseSetId) {
    const detailPath = readRoutePath(responseSetId, 'detail', orgId)
    const manifestPath = readRoutePath(responseSetId, 'manifest', orgId)
    const historyPath = readRoutePath(responseSetId, 'history', orgId)
    const [detailRes, manifestRes, historyRes] = await Promise.all([
      apiFetch(base, detailPath, { cookieHeader }),
      apiFetch(base, manifestPath, { cookieHeader }),
      apiFetch(base, historyPath, { cookieHeader }),
    ])
    return {
      detail: { body: detailRes.json, httpStatus: detailRes.httpStatus },
      manifest: { body: manifestRes.json, httpStatus: manifestRes.httpStatus },
      history: { body: historyRes.json, httpStatus: historyRes.httpStatus },
    }
  }

  function buildShell(responseSetId, envelopes) {
    const detailPanel = modules.normalizeEnvelopeToPanelResult(
      envelopes.detail.body,
      modules.normalizeResponseSetDetail,
      'Detail',
    )
    const manifestPanel = modules.normalizeEnvelopeToPanelResult(
      envelopes.manifest.body,
      modules.normalizeManifest,
      'Manifest',
    )
    const captureFields = envelopes.detail.body.ok
      ? modules.normalizeCaptureFields(envelopes.detail.body.data, {})
      : []
    return buildCaptureShellViewModel({
      procedureExecutionId: fixture.procedureExecutionId,
      organizationId: orgId,
      responseSetId,
      detailData: envelopes.detail.body.data,
      manifestPanel,
      detailPanel,
      captureFields,
    })
  }

  // Unauthenticated
  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/open', {
      method: 'POST',
      body: {
        organization_id: orgId,
        study_id: fixture.studyId,
        study_version_id: fixture.studyVersionId,
        study_subject_id: fixture.studySubjectId,
        visit_id: fixture.visitId,
        procedure_execution_id: fixture.procedureExecutionId,
        source_definition_version_id: fixture.sourceDefinitionVersionId,
      },
    })
    const ok = httpStatus === 401 && json?.ok === false
    report.steps.push(
      stepRecord('auth_unauthenticated', ok ? 'pass' : 'fail', {
        detail: ok ? `HTTP ${httpStatus}` : `expected 401, got ${httpStatus}`,
        http_status: httpStatus,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  // Wrong org (user B)
  let orgB = args.orgBId
  if (!orgB) orgB = await discoverOrgB(sql)
  if (orgB && orgB !== orgId) {
    const cookieB = (await signInForCookieHeader(
      process.env.NEXT_PUBLIC_SUPABASE_URL,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
      SYNTHETIC.userB,
    )).cookieHeader
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/open', {
      method: 'POST',
      cookieHeader: cookieB,
      body: {
        organization_id: orgId,
        study_id: fixture.studyId,
        study_version_id: fixture.studyVersionId,
        study_subject_id: fixture.studySubjectId,
        visit_id: fixture.visitId,
        procedure_execution_id: fixture.procedureExecutionId,
        source_definition_version_id: fixture.sourceDefinitionVersionId,
      },
    })
    const ok = (httpStatus === 403 || httpStatus === 401) && json?.ok === false
    report.steps.push(
      stepRecord('auth_wrong_org', ok ? 'pass' : 'fail', {
        detail: ok ? `forbidden http=${httpStatus}` : `expected 403/401 got ${httpStatus}`,
        http_status: httpStatus,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  } else {
    report.steps.push(
      stepRecord('auth_wrong_org', 'skip', { detail: 'org B not available' }),
    )
    report.summary.skipped++
  }

  // Open
  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/open', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        study_id: fixture.studyId,
        study_version_id: fixture.studyVersionId,
        study_subject_id: fixture.studySubjectId,
        visit_id: fixture.visitId,
        procedure_execution_id: fixture.procedureExecutionId,
        source_definition_version_id: fixture.sourceDefinitionVersionId,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.OPEN_RPC, requireOk: true })
    ctx.responseSetId =
      json?.data?.source_response_set_id ??
      fixture.existingResponseSetId ??
      ctx.responseSetId
    const ok = env.ok && httpStatus === 200 && isUuid(ctx.responseSetId)
    report.steps.push(
      stepRecord('capture_open', ok ? 'pass' : 'fail', {
        detail: ok ? `response_set_id=${ctx.responseSetId}` : env.issues.join('; '),
        http_status: httpStatus,
        rpc: WRITE_RPC.OPEN_RPC,
        key_ids: { response_set_id: ctx.responseSetId },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  let envelopes = await readBundle(ctx.responseSetId)

  const assertMutable = (stepId) => {
    const rsStatus = envelopes.detail.body?.data?.response_set?.status
    if (rsStatus === 'submitted' || rsStatus === 'locked') {
      report.steps.push(
        stepRecord(stepId, 'blocked', {
          detail: `response set ${ctx.responseSetId} already ${rsStatus} — use --fresh or another procedure_execution_id`,
        }),
      )
      report.summary.blocked++
      report.ok = false
      return false
    }
    return true
  }

  // Shell before submit
  {
    if (!assertMutable('capture_shell_before_submit')) return

    const shell = buildShell(ctx.responseSetId, envelopes)
    const primary = pickPrimaryField(envelopes.detail.body.data)
    ctx.fieldId = primary?.source_field_id
    ctx.widgetHint = primary?.widget_hint ?? 'text'
    const issues = assertCaptureShellViewModel(shell, {
      canEdit: true,
      isSubmitted: false,
      minFields: 1,
    })
    report.steps.push(
      stepRecord('capture_shell_before_submit', issues.length === 0 ? 'pass' : 'fail', {
        detail: issues.length ? issues.join('; ') : `fields=${shell.fields.length} canEdit=true`,
        errors: issues.length ? issues : null,
      }),
    )
    issues.length === 0 ? report.summary.passed++ : report.summary.failed++
  }

  // Save draft (all required fields + primary field override for traceability)
  {
    const detailData = envelopes.detail.body.data
    const payload = []
    for (const field of detailData.fields ?? []) {
      if (!field.is_required) continue
      const hint = field.widget_hint ?? 'text'
      if (field.source_field_id === ctx.fieldId) {
        payload.push({
          source_field_id: field.source_field_id,
          ...valueForWidgetWithOverride(hint, ctx.savedValue),
        })
      } else {
        payload.push({
          source_field_id: field.source_field_id,
          ...valueForWidget(hint),
        })
      }
    }
    if (payload.length === 0 && ctx.fieldId) {
      payload.push({
        source_field_id: ctx.fieldId,
        ...valueForWidgetWithOverride(ctx.widgetHint, ctx.savedValue),
      })
    }
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/save-draft', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        responses: payload,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.SAVE_RPC, requireOk: true })
    const ok = env.ok && httpStatus === 200
    report.steps.push(
      stepRecord('capture_save_draft', ok ? 'pass' : 'fail', {
        detail: ok ? 'draft saved' : env.issues.join('; '),
        http_status: httpStatus,
        rpc: WRITE_RPC.SAVE_RPC,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  envelopes = await readBundle(ctx.responseSetId)

  // Read after save
  {
    const display = ctx.fieldId
      ? detailFieldDisplayValue(envelopes.detail.body.data, ctx.fieldId)
      : null
    const expected = expectedDisplayForSavedValue(ctx.widgetHint, ctx.savedValue)
    const ok =
      assertReadApiEnvelope(envelopes.detail.body, 'detail', { requireOk: true }).ok &&
      display === expected
    report.steps.push(
      stepRecord('capture_read_after_save', ok ? 'pass' : 'fail', {
        detail: ok ? `value=${display}` : `expected ${expected}, got ${display}`,
        actual: display,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  // Snapshot current rows after save (pre-submit)
  const afterSaveRows = await sql`
    select id, source_field_id, is_submitted, value_text, value_number, value_boolean, value_date
    from public.source_responses
    where response_set_id = ${ctx.responseSetId}::uuid and is_current = true
  `
  ctx.afterSaveSnapshot = new Map(
    afterSaveRows.map((r) => [r.id, responseValueSnapshot(r)]),
  )

  // Submit
  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/submit', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        submit_reason: 'phase52e capture shell e2e',
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.SUBMIT_RPC, requireOk: true })
    const ok = env.ok && httpStatus === 200
    report.steps.push(
      stepRecord('capture_submit', ok ? 'pass' : 'fail', {
        detail: ok ? 'submitted' : env.issues.join('; '),
        http_status: httpStatus,
        rpc: WRITE_RPC.SUBMIT_RPC,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)

  // Shell after submit
  {
    const shell = buildShell(ctx.responseSetId, envelopes)
    const issues = assertCaptureShellViewModel(shell, {
      canEdit: false,
      isSubmitted: true,
    })
    report.steps.push(
      stepRecord('capture_shell_after_submit', issues.length === 0 ? 'pass' : 'fail', {
        detail: issues.length ? issues.join('; ') : 'canEdit=false isSubmitted=true',
        errors: issues.length ? issues : null,
      }),
    )
    issues.length === 0 ? report.summary.passed++ : report.summary.failed++
  }

  // Canonical read
  {
    const findingsPath = readRoutePath(ctx.responseSetId, 'findings', orgId)
    const findingsRes = await apiFetch(base, findingsPath, { cookieHeader })
    const liveResults = validateLivePayloads(
      rc,
      {
        detail: envelopes.detail,
        manifest: envelopes.manifest,
        history: envelopes.history,
        findings: { body: findingsRes.json, httpStatus: findingsRes.httpStatus },
      },
      ctx.responseSetId,
      orgId,
    )
    const manifestSubmitted =
      envelopes.manifest.body?.data?.completeness?.is_submitted === true ||
      envelopes.manifest.body?.data?.status === 'submitted'
    const contractOk =
      liveResults.every((r) => r.ok) &&
      manifestSubmitted &&
      envelopes.detail.body?.data?.response_set?.status === 'submitted'
    report.steps.push(
      stepRecord('capture_canonical_read', contractOk ? 'pass' : 'fail', {
        detail: contractOk
          ? 'detail/manifest submitted; read contract checks pass'
          : liveResults
              .filter((r) => !r.ok)
              .map((r) => r.id)
              .join(', '),
      }),
    )
    contractOk ? report.summary.passed++ : report.summary.failed++
  }

  // History submit
  {
    const ok =
      assertReadApiEnvelope(envelopes.history.body, 'history', { requireOk: true }).ok &&
      historyHasSubmitEvent(envelopes.history.body.data)
    report.steps.push(
      stepRecord('capture_history_submit', ok ? 'pass' : 'fail', {
        detail: ok ? 'submit event present' : 'missing submit chronology event',
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  // Immutable submitted rows (pre-submit current values frozen at submit)
  {
    const afterRows = await sql`
      select id, source_field_id, is_submitted, value_text, value_number, value_boolean, value_date
      from public.source_responses
      where response_set_id = ${ctx.responseSetId}::uuid and is_submitted = true
    `
    let valuesMatch = true
    for (const row of afterRows) {
      const prior = ctx.afterSaveSnapshot?.get(row.id)
      if (prior && prior !== responseValueSnapshot(row)) valuesMatch = false
    }
    const display = ctx.fieldId
      ? detailFieldDisplayValue(envelopes.detail.body.data, ctx.fieldId)
      : null
    const expected = expectedDisplayForSavedValue(ctx.widgetHint, ctx.savedValue)
    const ok =
      afterRows.length > 0 &&
      valuesMatch &&
      display === expected
    report.steps.push(
      stepRecord('capture_submitted_immutable', ok ? 'pass' : 'fail', {
        detail: ok
          ? `${afterRows.length} submitted rows; values match pre-submit snapshot`
          : 'submitted row values diverged or missing',
        actual: { display, submittedCount: afterRows.length },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  // Determinism
  {
    const a = await readBundle(ctx.responseSetId)
    const b = await readBundle(ctx.responseSetId)
    const fpA = stableFingerprint(
      modules.normalizeResponseSetDetail(a.detail.body.data),
    )
    const fpB = stableFingerprint(
      modules.normalizeResponseSetDetail(b.detail.body.data),
    )
    const openAgain = await apiFetch(base, '/api/source/response-set/open', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        study_id: fixture.studyId,
        study_version_id: fixture.studyVersionId,
        study_subject_id: fixture.studySubjectId,
        visit_id: fixture.visitId,
        procedure_execution_id: fixture.procedureExecutionId,
        source_definition_version_id: fixture.sourceDefinitionVersionId,
      },
    })
    const sameSet =
      openAgain.json?.data?.source_response_set_id === ctx.responseSetId
    const ok = fpA === fpB && sameSet
    report.steps.push(
      stepRecord('capture_determinism', ok ? 'pass' : 'fail', {
        detail: ok ? 'stable detail fingerprint; idempotent open' : 'fingerprint or open id mismatch',
        actual: { sameSet, fpMatch: fpA === fpB },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  // Save after submit denied
  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/save-draft', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        responses: ctx.fieldId
          ? [{ source_field_id: ctx.fieldId, value_text: 'should-not-save' }]
          : [],
      },
    })
    const ok = json?.ok === false && (httpStatus === 409 || httpStatus === 422)
    report.steps.push(
      stepRecord('capture_save_after_submit_denied', ok ? 'pass' : 'fail', {
        detail: ok ? `denied http=${httpStatus}` : `expected failure got ${httpStatus} ok=${json?.ok}`,
        http_status: httpStatus,
        actual: json?.code,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  // Review route
  {
    const shell = buildShell(ctx.responseSetId, envelopes)
    const { httpStatus } = await apiFetch(base, shell.reviewHref, {
      cookieHeader,
    })
    const ok = httpStatus === 200
    report.steps.push(
      stepRecord('capture_review_route', ok ? 'pass' : 'fail', {
        detail: ok ? `GET review HTTP ${httpStatus}` : `review route HTTP ${httpStatus}`,
        route: shell.reviewHref,
        http_status: httpStatus,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  report.ok = report.summary.failed === 0 && report.summary.blocked === 0
}

function valueForWidgetWithOverride(widgetHint, textOverride) {
  const base = valueForWidget(widgetHint)
  if (base.value_text !== undefined) return { value_text: textOverride }
  return base
}

async function main() {
  loadEnvFiles()
  const args = parseArgs(process.argv)

  const report = {
    phase: '5.2E',
    mode: args.live ? 'live' : 'planning',
    base_url: args.baseUrl,
    started_at: new Date().toISOString(),
    ok: true,
    summary: { passed: 0, failed: 0, skipped: 0, blocked: 0, planned: 0 },
    steps: [],
    gaps: [],
  }

  const unitOk = runUnitSuite(report)
  if (!unitOk) report.ok = false

  if (!args.live) {
    for (const s of LIVE_STEPS) {
      report.steps.push(
        stepRecord(s.id, 'planned', {
          detail: 'planning — run with --live (and staging IDs or discovery)',
        }),
      )
      report.summary.planned++
    }
    finish(report)
    return
  }

  requireEnv(['NEXT_PUBLIC_SUPABASE_URL', 'NEXT_PUBLIC_SUPABASE_ANON_KEY', 'DATABASE_URL'])

  if (!args.organizationId || !isUuid(args.organizationId)) {
    report.gaps.push('missing or invalid --organization-id for live mode')
    report.ok = false
    finish(report)
    return
  }

  const sql = await connectPostgres()
  if (!sql) {
    report.gaps.push('DATABASE_URL unavailable')
    report.ok = false
    finish(report)
    return
  }

  let cookieHeader
  try {
    cookieHeader = (
      await signInForCookieHeader(
        process.env.NEXT_PUBLIC_SUPABASE_URL,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
        SYNTHETIC.userA,
      )
    ).cookieHeader
  } catch (e) {
    report.gaps.push(`auth failed: ${e.message}`)
    report.ok = false
    finish(report)
    await sql.end()
    return
  }

  const health = await fetch(args.baseUrl, { redirect: 'manual' }).catch(() => null)
  if (!health) {
    report.gaps.push(`Next.js not reachable at ${args.baseUrl}`)
  }

  try {
    await liveRun(args, report, sql, cookieHeader)
  } finally {
    await sql.end()
  }

  if (!unitOk) report.ok = false
  finish(report)
}

function finish(report) {
  report.finished_at = new Date().toISOString()
  mkdirSync(REPORT_DIR, { recursive: true })
  writeFileSync(REPORT_PATH, JSON.stringify(report, null, 2))
  const { passed, failed, skipped, blocked, planned } = report.summary
  console.log(
    `Phase 5.2E capture shell E2E [${report.mode}]: pass=${passed} fail=${failed} skip=${skipped} blocked=${blocked} planned=${planned}`,
  )
  console.log(`Report: ${REPORT_PATH}`)
  if (report.gaps.length) console.log('Gaps:', report.gaps.join('; '))
  process.exit(report.ok ? 0 : 1)
}

main().catch((e) => {
  console.error(e)
  process.exit(1)
})

/**
 * Phase 5.3B — Post-submit correction shell E2E.
 *
 *   npm run db:validate-phase53b-correction-shell-e2e
 *   npm run db:validate-phase53b-correction-shell-e2e:live -- --organization-id ...
 *
 * Report: tmp/runtime-e2e/phase53b-correction-shell-e2e-report.json
 */

import { mkdirSync, writeFileSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'
import { loadEnvFiles, requireEnv } from './lib/env.mjs'
import {
  apiFetch,
  assertApiEnvelope,
  correctionValueForWidget,
  isUuid,
  responseValueSnapshot,
  signInForCookieHeader,
  SYNTHETIC,
  stepRecord,
  valueForWidget,
} from './lib/source-api-e2e.mjs'
import {
  prepareCaptureFixture,
  WRITE_RPC,
  detailFieldDisplayValue,
  expectedDisplayForSavedValue,
  pickPrimaryField,
} from './lib/capture-shell-e2e.mjs'
import { loadCorrectionModules } from './lib/correction-shell-import.mjs'
import { assertReadApiEnvelope, readRoutePath, stableFingerprint } from './lib/read-contract-e2e.mjs'
import {
  CORRECT_RPC,
  assertPostCorrectionReadState,
  countCorrectionEligibleFields,
  expectedDisplayForCorrection,
  historyHasCorrectionEvent,
  historyHasSubmitEvent,
  manifestCorrectionCount,
  resolveAllowCorrections,
  runCorrectionUnitValidations,
} from './lib/correction-shell-e2e.mjs'

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..')
const REPORT_DIR = join(ROOT, 'tmp/runtime-e2e')
const REPORT_PATH = join(REPORT_DIR, 'phase53b-correction-shell-e2e-report.json')

const LIVE_STEPS = [
  { id: 'fixture_discover', title: 'Discover fresh procedure_execution for capture' },
  { id: 'fixture_submit', title: 'Open, save required fields, submit response set' },
  { id: 'fixture_submitted_confirm', title: 'Confirm submitted state and correction eligibility' },
  { id: 'auth_unauthenticated_correct', title: 'Unauthenticated POST /correct rejected' },
  { id: 'auth_wrong_org_correct', title: 'Cross-org POST /correct rejected' },
  { id: 'neg_correction_wrong_org_id', title: 'Wrong organization_id in body rejected' },
  { id: 'neg_correction_no_reason', title: 'Correction without reason rejected' },
  { id: 'neg_correction_missing_response', title: 'Missing source_response_id rejected' },
  { id: 'correction_baseline_read', title: 'Baseline manifest correction count' },
  { id: 'correction_post', title: 'POST /api/source/response/correct' },
  { id: 'correction_canonical_read', title: 'Canonical read assertions after correction' },
  { id: 'correction_lineage_immutable', title: 'Prior source_response row not overwritten' },
  { id: 'correction_determinism', title: 'Repeated read bundle stable; GET does not mutate counts' },
  { id: 'correction_review_route', title: 'Review page route returns 200' },
]

function parseArgs(argv) {
  const args = {
    live: false,
    baseUrl: process.env.E2E_API_BASE_URL?.trim() || 'http://localhost:3000',
    organizationId: null,
    orgBId: null,
    fresh: true,
  }

  for (let i = 2; i < argv.length; i++) {
    const a = argv[i]
    const next = () => argv[++i]
    if (a === '--live') args.live = true
    else if (a === '--fresh') args.fresh = true
    else if (a === '--no-fresh') args.fresh = false
    else if (a === '--base-url') args.baseUrl = next()
    else if (a === '--organization-id') args.organizationId = next()
    else if (a === '--org-b-id') args.orgBId = next()
    else if (a === '--help' || a === '-h') {
      printHelp()
      process.exit(0)
    } else {
      console.error('Unknown argument:', a)
      printHelp()
      process.exit(1)
    }
  }
  return args
}

function printHelp() {
  console.log(`Phase 5.3B Correction shell E2E

Options:
  --live                         HTTP flow (requires npm run dev)
  --base-url <url>
  --organization-id <uuid>       Required for live
  --org-b-id <uuid>              Cross-tenant probe
  --fresh                        Insert new visit + procedure_execution (default)
  --no-fresh                     Reuse discovered mutable PE when available
`)
}

async function connectPostgres() {
  const postgres = (await import('postgres')).default
  const url = process.env.DATABASE_URL_DIRECT || process.env.DATABASE_URL
  if (!url) return null
  return postgres(url, {
    ssl: 'require',
    max: 1,
    prepare: url.includes('pooler') ? false : undefined,
  })
}

async function discoverOrgB(sql) {
  const rows = await sql`
    select id from public.organizations
    where name ilike '%Synthetic Site Beta%'
    limit 1
  `
  return rows[0]?.id ?? null
}

function valueForWidgetWithOverride(widgetHint, textOverride) {
  const base = valueForWidget(widgetHint)
  if (base.value_text !== undefined) return { value_text: textOverride }
  return base
}

function runUnitSuite(report) {
  const loaded = loadCorrectionModules()
  const results = runCorrectionUnitValidations(loaded.capture, loaded)
  for (const r of results) {
    report.steps.push(
      stepRecord(`unit_${r.id}`, r.ok ? 'pass' : 'fail', {
        detail: r.ok ? 'ok' : r.issues.join('; '),
        errors: r.ok ? null : r.issues,
      }),
    )
    if (r.ok) report.summary.passed++
    else report.summary.failed++
  }
  return results.every((r) => r.ok)
}

async function liveRun(args, report, sql, cookieHeader) {
  const base = args.baseUrl
  const orgId = args.organizationId
  const modules = loadCorrectionModules().capture

  const fixture = await prepareCaptureFixture(sql, orgId, { fresh: args.fresh })
  if (!fixture?.procedureExecutionId || !fixture.studyVersionId) {
    report.steps.push(
      stepRecord('fixture_discover', 'blocked', {
        detail: 'no mutable procedure_execution — use --fresh or bind SDV',
      }),
    )
    report.summary.blocked++
    report.ok = false
    return
  }

  report.steps.push(
    stepRecord('fixture_discover', 'pass', {
      detail: `pe=${fixture.procedureExecutionId}`,
      key_ids: { procedure_execution_id: fixture.procedureExecutionId },
    }),
  )
  report.summary.passed++

  const ctx = {
    responseSetId: fixture.existingResponseSetId,
    fieldId: null,
    widgetHint: 'text',
    savedValue: `e2e-53b-${Date.now()}`,
    priorResponseId: null,
    priorSnapshot: null,
    submittedDisplay: null,
    correctionReason: 'phase53b correction shell e2e',
    baselineCorrectionCount: 0,
  }

  async function readBundle(responseSetId) {
    const [detailRes, manifestRes, historyRes] = await Promise.all([
      apiFetch(base, readRoutePath(responseSetId, 'detail', orgId), { cookieHeader }),
      apiFetch(base, readRoutePath(responseSetId, 'manifest', orgId), { cookieHeader }),
      apiFetch(base, readRoutePath(responseSetId, 'history', orgId), { cookieHeader }),
    ])
    return {
      detail: { body: detailRes.json, httpStatus: detailRes.httpStatus },
      manifest: { body: manifestRes.json, httpStatus: manifestRes.httpStatus },
      history: { body: historyRes.json, httpStatus: historyRes.httpStatus },
    }
  }

  // --- Submit fixture (open → save → submit) ---
  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/open', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        study_id: fixture.studyId,
        study_version_id: fixture.studyVersionId,
        study_subject_id: fixture.studySubjectId,
        visit_id: fixture.visitId,
        procedure_execution_id: fixture.procedureExecutionId,
        source_definition_version_id: fixture.sourceDefinitionVersionId,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.OPEN_RPC, requireOk: true })
    ctx.responseSetId = json?.data?.source_response_set_id ?? ctx.responseSetId
    const ok = env.ok && httpStatus === 200 && isUuid(ctx.responseSetId)
    if (!ok) {
      report.steps.push(
        stepRecord('fixture_submit', 'fail', { detail: env.issues.join('; '), http_status: httpStatus }),
      )
      report.summary.failed++
      report.ok = false
      return
    }
  }

  let envelopes = await readBundle(ctx.responseSetId)
  const primary = pickPrimaryField(envelopes.detail.body.data)
  ctx.fieldId = primary?.source_field_id
  ctx.widgetHint = primary?.widget_hint ?? 'text'

  const detailData = envelopes.detail.body.data
  const payload = []
  for (const field of detailData.fields ?? []) {
    if (!field.is_required) continue
    const hint = field.widget_hint ?? 'text'
    if (field.source_field_id === ctx.fieldId) {
      payload.push({
        source_field_id: field.source_field_id,
        ...valueForWidgetWithOverride(hint, ctx.savedValue),
      })
    } else {
      payload.push({ source_field_id: field.source_field_id, ...valueForWidget(hint) })
    }
  }
  if (payload.length === 0 && ctx.fieldId) {
    payload.push({
      source_field_id: ctx.fieldId,
      ...valueForWidgetWithOverride(ctx.widgetHint, ctx.savedValue),
    })
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/save-draft', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        responses: payload,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.SAVE_RPC, requireOk: true })
    if (!env.ok || httpStatus !== 200) {
      report.steps.push(
        stepRecord('fixture_submit', 'fail', { detail: 'save-draft failed', http_status: httpStatus }),
      )
      report.summary.failed++
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)
  const currentRow = envelopes.detail.body.data?.fields?.find(
    (f) => f.source_field_id === ctx.fieldId,
  )
  ctx.priorResponseId = currentRow?.current_effective?.response_id ?? null
  ctx.submittedDisplay = expectedDisplayForSavedValue(ctx.widgetHint, ctx.savedValue)

  if (ctx.priorResponseId) {
    const prior = await sql`
      select value_text, value_number, value_boolean, value_date, value_datetime, is_submitted
      from public.source_responses where id = ${ctx.priorResponseId}::uuid
    `
    ctx.priorSnapshot = responseValueSnapshot(prior[0])
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/submit', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        submit_reason: 'phase53b correction shell e2e',
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.SUBMIT_RPC, requireOk: true })
    const ok = env.ok && httpStatus === 200
    report.steps.push(
      stepRecord('fixture_submit', ok ? 'pass' : 'fail', {
        detail: ok ? `submitted response_set_id=${ctx.responseSetId}` : env.issues.join('; '),
        key_ids: { response_set_id: ctx.responseSetId, source_response_id: ctx.priorResponseId },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)

  // Confirm submitted + UI contract
  {
    const manifestPanel = modules.normalizeEnvelopeToPanelResult(
      envelopes.manifest.body,
      modules.normalizeManifest,
      'Manifest',
    )
    const detailPanel = modules.normalizeEnvelopeToPanelResult(
      envelopes.detail.body,
      modules.normalizeResponseSetDetail,
      'Detail',
    )
    const allow = resolveAllowCorrections(manifestPanel)
    const eligible = countCorrectionEligibleFields(detailPanel, allow)
    const display = detailFieldDisplayValue(envelopes.detail.body.data, ctx.fieldId)
    const ok =
      allow &&
      eligible >= 1 &&
      envelopes.detail.body?.data?.response_set?.status === 'submitted' &&
      historyHasSubmitEvent(envelopes.history.body?.data) &&
      display === ctx.submittedDisplay &&
      isUuid(ctx.priorResponseId)
    report.steps.push(
      stepRecord('fixture_submitted_confirm', ok ? 'pass' : 'fail', {
        detail: ok
          ? `isSubmitted=true eligibleFields=${eligible} display=${display}`
          : `allow=${allow} eligible=${eligible} status=${envelopes.detail.body?.data?.response_set?.status}`,
        actual: { display, priorResponseId: ctx.priorResponseId },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  const correctionPayload = correctionValueForWidget(ctx.widgetHint)

  // Unauthenticated correct
  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response/correct', {
      method: 'POST',
      body: {
        organization_id: orgId,
        source_response_id: ctx.priorResponseId,
        corrected_value: correctionPayload,
        correction_reason: 'no auth',
      },
    })
    const rejected = httpStatus === 401 && json?.ok === false
    report.steps.push(
      stepRecord('auth_unauthenticated_correct', rejected ? 'pass' : 'fail', {
        detail: rejected ? `HTTP ${httpStatus}` : `expected 401 got ${httpStatus}`,
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  // Wrong org
  let orgB = args.orgBId
  if (!orgB) orgB = await discoverOrgB(sql)
  if (orgB && orgB !== orgId) {
    const cookieB = (
      await signInForCookieHeader(
        process.env.NEXT_PUBLIC_SUPABASE_URL,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
        SYNTHETIC.userB,
      )
    ).cookieHeader
    const { json, httpStatus } = await apiFetch(base, '/api/source/response/correct', {
      method: 'POST',
      cookieHeader: cookieB,
      body: {
        organization_id: orgId,
        source_response_id: ctx.priorResponseId,
        corrected_value: correctionPayload,
        correction_reason: 'wrong org',
      },
    })
    const denied =
      (httpStatus === 403 || httpStatus === 401) && json?.ok === false
    report.steps.push(
      stepRecord('auth_wrong_org_correct', denied ? 'pass' : 'fail', {
        detail: denied ? `forbidden http=${httpStatus}` : `expected 403/401 got ${httpStatus}`,
        http_status: httpStatus,
      }),
    )
    denied ? report.summary.passed++ : report.summary.failed++
  } else {
    report.steps.push(stepRecord('auth_wrong_org_correct', 'skip', { detail: 'org B not available' }))
    report.summary.skipped++
  }

  if (orgB && orgB !== orgId) {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response/correct', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgB,
        source_response_id: ctx.priorResponseId,
        corrected_value: correctionPayload,
        correction_reason: 'wrong org id in body',
      },
    })
    const rejected =
      json?.ok === false &&
      (httpStatus === 403 || httpStatus === 404 || httpStatus === 400)
    report.steps.push(
      stepRecord('neg_correction_wrong_org_id', rejected ? 'pass' : 'fail', {
        detail: rejected ? `rejected http=${httpStatus} code=${json?.code}` : 'expected rejection',
        http_status: httpStatus,
        actual: json?.code,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  } else {
    report.steps.push(stepRecord('neg_correction_wrong_org_id', 'skip', { detail: 'org B not available' }))
    report.summary.skipped++
  }

  // No reason
  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response/correct', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_id: ctx.priorResponseId,
        corrected_value: correctionPayload,
        correction_reason: '   ',
      },
    })
    const rejected = httpStatus === 400 && json?.ok === false && json?.code === 'INVALID_REQUEST'
    report.steps.push(
      stepRecord('neg_correction_no_reason', rejected ? 'pass' : 'fail', {
        detail: rejected ? 'INVALID_REQUEST' : JSON.stringify(json?.code),
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  // Missing response id
  {
    const fakeId = '00000000-0000-4000-8000-000000000099'
    const { json, httpStatus } = await apiFetch(base, '/api/source/response/correct', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_id: fakeId,
        corrected_value: correctionPayload,
        correction_reason: 'missing row',
      },
    })
    const rejected = json?.ok === false && httpStatus >= 400
    report.steps.push(
      stepRecord('neg_correction_missing_response', rejected ? 'pass' : 'fail', {
        detail: rejected ? `rejected http=${httpStatus} code=${json?.code}` : 'expected failure',
        http_status: httpStatus,
        actual: json?.code,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  ctx.baselineCorrectionCount = manifestCorrectionCount(envelopes.manifest.body)
  report.steps.push(
    stepRecord('correction_baseline_read', 'pass', {
      detail: `baseline corrections=${ctx.baselineCorrectionCount}`,
      actual: { corrections: ctx.baselineCorrectionCount },
    }),
  )
  report.summary.passed++

  // POST correct
  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response/correct', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_id: ctx.priorResponseId,
        corrected_value: correctionPayload,
        correction_reason: ctx.correctionReason,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: CORRECT_RPC, requireOk: true })
    const newId = json?.data?.replacement_response_id ?? json?.data?.response_id
    const ok = env.ok && json.ok && httpStatus === 200
    if (newId) ctx.currentResponseId = newId
    report.steps.push(
      stepRecord('correction_post', ok ? 'pass' : 'fail', {
        detail: ok ? `corrected replacement=${newId ?? 'n/a'}` : env.issues.join('; '),
        route: 'POST /api/source/response/correct',
        rpc: CORRECT_RPC,
        http_status: httpStatus,
        key_ids: { prior_response_id: ctx.priorResponseId, replacement_response_id: newId },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  const afterEnvelopes = await readBundle(ctx.responseSetId)

  // Canonical read assertions
  {
    const result = assertPostCorrectionReadState({
      beforeManifestCount: ctx.baselineCorrectionCount,
      afterEnvelopes,
      modules,
      ctx,
      correctionReason: ctx.correctionReason,
    })
    report.steps.push(
      stepRecord('correction_canonical_read', result.ok ? 'pass' : 'fail', {
        detail: result.ok
          ? `corrections=${result.afterCount} effective=${result.actualDisplay}`
          : result.issues.join('; '),
        errors: result.ok ? null : result.issues,
        actual: {
          afterCount: result.afterCount,
          expectedDisplay: result.expectedDisplay,
          actualDisplay: result.actualDisplay,
          historyHasCorrection: historyHasCorrectionEvent(afterEnvelopes.history.body?.data),
        },
      }),
    )
    result.ok ? report.summary.passed++ : report.summary.failed++
  }

  // Lineage immutable
  {
    const afterPrior = await sql`
      select value_text, value_number, value_boolean, value_date, value_datetime, is_submitted
      from public.source_responses where id = ${ctx.priorResponseId}::uuid
    `
    const unchanged =
      responseValueSnapshot(afterPrior[0]) === ctx.priorSnapshot &&
      afterPrior[0]?.is_submitted === true
    const current = await sql`
      select id, is_current from public.source_responses
      where response_set_id = ${ctx.responseSetId}::uuid
        and source_field_id = ${ctx.fieldId}::uuid
        and is_current = true
    `
    const ok = unchanged && current[0]?.id !== ctx.priorResponseId
    report.steps.push(
      stepRecord('correction_lineage_immutable', ok ? 'pass' : 'fail', {
        detail: ok
          ? 'prior row immutable; new current response active'
          : 'lineage check failed',
        key_ids: {
          prior_response_id: ctx.priorResponseId,
          current_response_id: current[0]?.id,
        },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  // Determinism + read-only GET
  {
    const a = await readBundle(ctx.responseSetId)
    const b = await readBundle(ctx.responseSetId)
    const fpA = stableFingerprint(
      modules.normalizeResponseSetDetail(a.detail.body.data),
    )
    const fpB = stableFingerprint(
      modules.normalizeResponseSetDetail(b.detail.body.data),
    )
    const countA = manifestCorrectionCount(a.manifest.body)
    const countB = manifestCorrectionCount(b.manifest.body)
    const histA = a.history.body?.data?.event_count ?? a.history.body?.data?.events?.length
    const histB = b.history.body?.data?.event_count ?? b.history.body?.data?.events?.length
    const ok =
      fpA === fpB &&
      countA === countB &&
      histA === histB &&
      assertReadApiEnvelope(a.detail.body, 'detail', { requireOk: true }).ok
    report.steps.push(
      stepRecord('correction_determinism', ok ? 'pass' : 'fail', {
        detail: ok
          ? `stable fingerprint; corrections=${countA}; events=${histA}`
          : `fpMatch=${fpA === fpB} counts ${countA}/${countB} events ${histA}/${histB}`,
        actual: { fpMatch: fpA === fpB, countA, countB, histA, histB },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  // Review route
  {
    const href = `/source/response-set/${ctx.responseSetId}?organization_id=${orgId}`
    const { httpStatus } = await apiFetch(base, href, { cookieHeader })
    const ok = httpStatus === 200
    report.steps.push(
      stepRecord('correction_review_route', ok ? 'pass' : 'fail', {
        detail: ok ? `GET ${href} HTTP 200` : `HTTP ${httpStatus}`,
        route: href,
        http_status: httpStatus,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  report.ok = report.summary.failed === 0 && report.summary.blocked === 0
}

async function main() {
  loadEnvFiles()
  const args = parseArgs(process.argv)

  const report = {
    phase: '5.3B',
    mode: args.live ? 'live' : 'planning',
    base_url: args.baseUrl,
    started_at: new Date().toISOString(),
    ok: true,
    summary: { passed: 0, failed: 0, skipped: 0, blocked: 0, planned: 0 },
    steps: [],
    gaps: [],
  }

  const unitOk = runUnitSuite(report)
  if (!unitOk) report.ok = false

  if (!args.live) {
    for (const s of LIVE_STEPS) {
      report.steps.push(
        stepRecord(s.id, 'planned', {
          detail: 'planning — run with --live --organization-id <uuid>',
        }),
      )
      report.summary.planned++
    }
    finish(report)
    return
  }

  requireEnv(['NEXT_PUBLIC_SUPABASE_URL', 'NEXT_PUBLIC_SUPABASE_ANON_KEY', 'DATABASE_URL'])

  if (!args.organizationId || !isUuid(args.organizationId)) {
    report.gaps.push('missing or invalid --organization-id for live mode')
    report.ok = false
    finish(report)
    return
  }

  const sql = await connectPostgres()
  if (!sql) {
    report.gaps.push('DATABASE_URL unavailable')
    report.ok = false
    finish(report)
    return
  }

  let cookieHeader
  try {
    cookieHeader = (
      await signInForCookieHeader(
        process.env.NEXT_PUBLIC_SUPABASE_URL,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
        SYNTHETIC.userA,
      )
    ).cookieHeader
  } catch (e) {
    report.gaps.push(`auth failed: ${e.message}`)
    report.ok = false
    finish(report)
    await sql.end()
    return
  }

  const health = await fetch(args.baseUrl, { redirect: 'manual' }).catch(() => null)
  if (!health) {
    report.gaps.push(`Next.js not reachable at ${args.baseUrl}`)
  }

  try {
    await liveRun(args, report, sql, cookieHeader)
  } finally {
    await sql.end()
  }

  if (!unitOk) report.ok = false
  finish(report)
}

function finish(report) {
  report.finished_at = new Date().toISOString()
  mkdirSync(REPORT_DIR, { recursive: true })
  writeFileSync(REPORT_PATH, JSON.stringify(report, null, 2))
  const { passed, failed, skipped, blocked, planned } = report.summary
  console.log(
    `Phase 5.3B correction shell E2E [${report.mode}]: pass=${passed} fail=${failed} skip=${skipped} blocked=${blocked} planned=${planned}`,
  )
  console.log(`Report: ${REPORT_PATH}`)
  if (report.gaps.length) console.log('Gaps:', report.gaps.join('; '))
  process.exit(report.ok ? 0 : 1)
}

main().catch((e) => {
  console.error(e)
  process.exit(1)
})

/**
 * Phase 5.4B — Post-submit addendum shell E2E.
 *
 *   npm run db:validate-phase54b-addendum-shell-e2e
 *   npm run db:validate-phase54b-addendum-shell-e2e:live -- --organization-id ...
 *
 * Report: tmp/runtime-e2e/phase54b-addendum-shell-e2e-report.json
 */

import { mkdirSync, writeFileSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'
import { loadEnvFiles, requireEnv } from './lib/env.mjs'
import {
  apiFetch,
  assertApiEnvelope,
  isUuid,
  responseValueSnapshot,
  signInForCookieHeader,
  SYNTHETIC,
  stepRecord,
  valueForWidget,
} from './lib/source-api-e2e.mjs'
import { prepareCaptureFixture, WRITE_RPC } from './lib/capture-shell-e2e.mjs'
import { loadAddendumModules } from './lib/addendum-shell-import.mjs'
import { assertReadApiEnvelope, readRoutePath, stableFingerprint } from './lib/read-contract-e2e.mjs'
import {
  ADDENDUM_RPC,
  addendumValueForWidget,
  assertPostAddendumReadState,
  countAddendumEligibleFields,
  expectedDisplayForAddendum,
  historyHasAddendumEvent,
  historyHasSubmitEvent,
  isPostSubmitResponseSet,
  manifestAddendaCount,
  pickAddendumEligibleField,
  resolveAllowAddenda,
  runAddendumUnitValidations,
} from './lib/addendum-shell-e2e.mjs'

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..')
const REPORT_DIR = join(ROOT, 'tmp/runtime-e2e')
const REPORT_PATH = join(REPORT_DIR, 'phase54b-addendum-shell-e2e-report.json')

const LIVE_STEPS = [
  { id: 'fixture_discover', title: 'Discover fresh procedure_execution' },
  { id: 'fixture_submit', title: 'Open, save required-only fields, submit' },
  { id: 'fixture_post_submit_confirm', title: 'Confirm post-submit lane and addendum eligibility' },
  { id: 'auth_unauthenticated_addendum', title: 'Unauthenticated POST /addendum rejected' },
  { id: 'auth_wrong_org_addendum', title: 'Cross-org POST /addendum rejected' },
  { id: 'neg_addendum_wrong_org_id', title: 'Wrong organization_id in body rejected' },
  { id: 'neg_addendum_no_reason', title: 'Addendum without reason rejected' },
  { id: 'neg_addendum_no_field', title: 'Missing source_field_id rejected' },
  { id: 'addendum_baseline_read', title: 'Baseline manifest addenda count' },
  { id: 'addendum_post', title: 'POST /api/source/response-set/addendum' },
  { id: 'addendum_canonical_read', title: 'Canonical read assertions after addendum' },
  { id: 'addendum_submitted_immutable', title: 'Prior submitted response rows unchanged' },
  { id: 'addendum_determinism', title: 'Repeated read bundle stable; GET does not mutate counts' },
  { id: 'addendum_review_route', title: 'Review page route returns 200' },
]

function parseArgs(argv) {
  const args = {
    live: false,
    baseUrl: process.env.E2E_API_BASE_URL?.trim() || 'http://localhost:3000',
    organizationId: null,
    orgBId: null,
    fresh: true,
  }

  for (let i = 2; i < argv.length; i++) {
    const a = argv[i]
    const next = () => argv[++i]
    if (a === '--live') args.live = true
    else if (a === '--fresh') args.fresh = true
    else if (a === '--no-fresh') args.fresh = false
    else if (a === '--base-url') args.baseUrl = next()
    else if (a === '--organization-id') args.organizationId = next()
    else if (a === '--org-b-id') args.orgBId = next()
    else if (a === '--help' || a === '-h') {
      printHelp()
      process.exit(0)
    } else {
      console.error('Unknown argument:', a)
      printHelp()
      process.exit(1)
    }
  }
  return args
}

function printHelp() {
  console.log(`Phase 5.4B Addendum shell E2E

Options:
  --live                         HTTP flow (requires npm run dev)
  --base-url <url>
  --organization-id <uuid>       Required for live
  --org-b-id <uuid>              Cross-tenant probe
  --fresh                        Insert new visit + procedure_execution (default)
  --no-fresh                     Reuse discovered mutable PE when available
`)
}

async function connectPostgres() {
  const postgres = (await import('postgres')).default
  const url = process.env.DATABASE_URL_DIRECT || process.env.DATABASE_URL
  if (!url) return null
  return postgres(url, {
    ssl: 'require',
    max: 1,
    prepare: url.includes('pooler') ? false : undefined,
  })
}

async function discoverOrgB(sql) {
  const rows = await sql`
    select id from public.organizations
    where name ilike '%Synthetic Site Beta%'
    limit 1
  `
  return rows[0]?.id ?? null
}

function runUnitSuite(report) {
  const loaded = loadAddendumModules()
  const results = runAddendumUnitValidations(loaded.capture, loaded)
  for (const r of results) {
    report.steps.push(
      stepRecord(`unit_${r.id}`, r.ok ? 'pass' : 'fail', {
        detail: r.ok ? 'ok' : r.issues.join('; '),
        errors: r.ok ? null : r.issues,
      }),
    )
    if (r.ok) report.summary.passed++
    else report.summary.failed++
  }
  return results.every((r) => r.ok)
}

async function liveRun(args, report, sql, cookieHeader) {
  const base = args.baseUrl
  const orgId = args.organizationId
  const modules = loadAddendumModules().capture

  const fixture = await prepareCaptureFixture(sql, orgId, { fresh: args.fresh })
  if (!fixture?.procedureExecutionId || !fixture.studyVersionId) {
    report.steps.push(
      stepRecord('fixture_discover', 'blocked', {
        detail: 'no mutable procedure_execution — use --fresh or bind SDV',
      }),
    )
    report.summary.blocked++
    report.ok = false
    return
  }

  report.steps.push(
    stepRecord('fixture_discover', 'pass', {
      detail: `pe=${fixture.procedureExecutionId}`,
      key_ids: { procedure_execution_id: fixture.procedureExecutionId },
    }),
  )
  report.summary.passed++

  const addendumText = `e2e-54b-addendum-${Date.now()}`
  const ctx = {
    responseSetId: fixture.existingResponseSetId,
    addendumFieldId: null,
    addendumWidgetHint: 'text',
    addendumReason: 'phase54b addendum shell e2e',
    expectedAddendumDisplay: null,
    baselineAddendaCount: 0,
    eligibleBefore: 0,
    submittedSnapshots: null,
  }

  async function readBundle(responseSetId) {
    const [detailRes, manifestRes, historyRes] = await Promise.all([
      apiFetch(base, readRoutePath(responseSetId, 'detail', orgId), { cookieHeader }),
      apiFetch(base, readRoutePath(responseSetId, 'manifest', orgId), { cookieHeader }),
      apiFetch(base, readRoutePath(responseSetId, 'history', orgId), { cookieHeader }),
    ])
    return {
      detail: { body: detailRes.json, httpStatus: detailRes.httpStatus },
      manifest: { body: manifestRes.json, httpStatus: manifestRes.httpStatus },
      history: { body: historyRes.json, httpStatus: historyRes.httpStatus },
    }
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/open', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        study_id: fixture.studyId,
        study_version_id: fixture.studyVersionId,
        study_subject_id: fixture.studySubjectId,
        visit_id: fixture.visitId,
        procedure_execution_id: fixture.procedureExecutionId,
        source_definition_version_id: fixture.sourceDefinitionVersionId,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.OPEN_RPC, requireOk: true })
    ctx.responseSetId = json?.data?.source_response_set_id ?? ctx.responseSetId
    const ok = env.ok && httpStatus === 200 && isUuid(ctx.responseSetId)
    if (!ok) {
      report.steps.push(
        stepRecord('fixture_submit', 'fail', { detail: env.issues.join('; '), http_status: httpStatus }),
      )
      report.summary.failed++
      report.ok = false
      return
    }
  }

  let envelopes = await readBundle(ctx.responseSetId)
  const detailData = envelopes.detail.body.data

  const requiredOnlyPayload = (detailData.fields ?? [])
    .filter((f) => f.is_required)
    .map((f) => ({
      source_field_id: f.source_field_id,
      ...valueForWidget(f.widget_hint ?? 'text'),
    }))

  if (requiredOnlyPayload.length === 0) {
    report.steps.push(
      stepRecord('fixture_submit', 'blocked', {
        detail: 'no required fields in SDV — cannot leave optional field empty for addendum',
      }),
    )
    report.summary.blocked++
    report.ok = false
    return
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/save-draft', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        responses: requiredOnlyPayload,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.SAVE_RPC, requireOk: true })
    if (!env.ok || httpStatus !== 200) {
      report.steps.push(
        stepRecord('fixture_submit', 'fail', { detail: 'save-draft failed', http_status: httpStatus }),
      )
      report.summary.failed++
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)
  const addendumField = pickAddendumEligibleField(envelopes.detail.body.data)
  if (!addendumField) {
    report.steps.push(
      stepRecord('fixture_submit', 'blocked', {
        detail: 'no field without current_effective after required-only save',
      }),
    )
    report.summary.blocked++
    report.ok = false
    return
  }

  ctx.addendumFieldId = addendumField.source_field_id
  ctx.addendumWidgetHint = addendumField.widget_hint ?? 'text'
  ctx.expectedAddendumDisplay = expectedDisplayForAddendum(ctx.addendumWidgetHint, addendumText)

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/submit', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        submit_reason: 'phase54b addendum shell e2e',
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.SUBMIT_RPC, requireOk: true })
    const ok = env.ok && httpStatus === 200
    report.steps.push(
      stepRecord('fixture_submit', ok ? 'pass' : 'fail', {
        detail: ok
          ? `submitted; addendumField=${addendumField.field_key}; requiredSaved=${requiredOnlyPayload.length}`
          : env.issues.join('; '),
        key_ids: { response_set_id: ctx.responseSetId, addendum_field_id: ctx.addendumFieldId },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)

  const submittedRows = await sql`
    select id, value_text, value_number, value_boolean, value_date, value_datetime, is_submitted
    from public.source_responses
    where response_set_id = ${ctx.responseSetId}::uuid and is_submitted = true
  `
  ctx.submittedSnapshots = new Map(
    submittedRows.map((r) => [r.id, responseValueSnapshot(r)]),
  )

  {
    const manifestPanel = modules.normalizeEnvelopeToPanelResult(
      envelopes.manifest.body,
      modules.normalizeManifest,
      'Manifest',
    )
    const detailPanel = modules.normalizeEnvelopeToPanelResult(
      envelopes.detail.body,
      modules.normalizeResponseSetDetail,
      'Detail',
    )
    const allow = resolveAllowAddenda(manifestPanel)
    ctx.eligibleBefore = countAddendumEligibleFields(detailPanel, allow)
    const postSubmit = isPostSubmitResponseSet(
      envelopes.detail.body.data,
      envelopes.manifest.body,
    )
    const ok =
      allow &&
      postSubmit &&
      ctx.eligibleBefore >= 1 &&
      historyHasSubmitEvent(envelopes.history.body?.data) &&
      submittedRows.length > 0
    report.steps.push(
      stepRecord('fixture_post_submit_confirm', ok ? 'pass' : 'fail', {
        detail: ok
          ? `post-submit; addendumEligible=${ctx.eligibleBefore}; submittedRows=${submittedRows.length}`
          : `allow=${allow} eligible=${ctx.eligibleBefore} postSubmit=${postSubmit}`,
        actual: { status: envelopes.detail.body?.data?.response_set?.status },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  const addendumPayload = addendumValueForWidget(ctx.addendumWidgetHint, addendumText)

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/addendum', {
      method: 'POST',
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        source_field_id: ctx.addendumFieldId,
        ...addendumPayload,
        reason: 'no auth',
      },
    })
    const rejected = httpStatus === 401 && json?.ok === false
    report.steps.push(
      stepRecord('auth_unauthenticated_addendum', rejected ? 'pass' : 'fail', {
        detail: rejected ? `HTTP ${httpStatus}` : `expected 401 got ${httpStatus}`,
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  let orgB = args.orgBId
  if (!orgB) orgB = await discoverOrgB(sql)
  if (orgB && orgB !== orgId) {
    const cookieB = (
      await signInForCookieHeader(
        process.env.NEXT_PUBLIC_SUPABASE_URL,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
        SYNTHETIC.userB,
      )
    ).cookieHeader
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/addendum', {
      method: 'POST',
      cookieHeader: cookieB,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        source_field_id: ctx.addendumFieldId,
        addendum_text: addendumText,
        reason: 'wrong org cookie',
      },
    })
    const denied = (httpStatus === 403 || httpStatus === 401) && json?.ok === false
    report.steps.push(
      stepRecord('auth_wrong_org_addendum', denied ? 'pass' : 'fail', {
        detail: denied ? `forbidden http=${httpStatus}` : `expected 403/401 got ${httpStatus}`,
        http_status: httpStatus,
      }),
    )
    denied ? report.summary.passed++ : report.summary.failed++
  } else {
    report.steps.push(stepRecord('auth_wrong_org_addendum', 'skip', { detail: 'org B not available' }))
    report.summary.skipped++
  }

  if (orgB && orgB !== orgId) {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/addendum', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgB,
        source_response_set_id: ctx.responseSetId,
        source_field_id: ctx.addendumFieldId,
        addendum_text: addendumText,
        reason: 'wrong org id in body',
      },
    })
    const rejected =
      json?.ok === false && (httpStatus === 403 || httpStatus === 404 || httpStatus === 400)
    report.steps.push(
      stepRecord('neg_addendum_wrong_org_id', rejected ? 'pass' : 'fail', {
        detail: rejected ? `rejected http=${httpStatus} code=${json?.code}` : 'expected rejection',
        http_status: httpStatus,
        actual: json?.code,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  } else {
    report.steps.push(stepRecord('neg_addendum_wrong_org_id', 'skip', { detail: 'org B not available' }))
    report.summary.skipped++
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/addendum', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        source_field_id: ctx.addendumFieldId,
        addendum_text: addendumText,
        reason: '   ',
      },
    })
    const rejected = httpStatus === 400 && json?.ok === false && json?.code === 'INVALID_REQUEST'
    report.steps.push(
      stepRecord('neg_addendum_no_reason', rejected ? 'pass' : 'fail', {
        detail: rejected ? 'INVALID_REQUEST' : JSON.stringify(json?.code),
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/addendum', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        addendum_text: addendumText,
        reason: 'missing field',
      },
    })
    const rejected = httpStatus === 400 && json?.ok === false && json?.code === 'INVALID_REQUEST'
    report.steps.push(
      stepRecord('neg_addendum_no_field', rejected ? 'pass' : 'fail', {
        detail: rejected ? 'INVALID_REQUEST (source_field_id required)' : JSON.stringify(json?.code),
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  ctx.baselineAddendaCount = manifestAddendaCount(envelopes.manifest.body)
  report.steps.push(
    stepRecord('addendum_baseline_read', 'pass', {
      detail: `baseline addenda=${ctx.baselineAddendaCount}`,
      actual: { addenda: ctx.baselineAddendaCount },
    }),
  )
  report.summary.passed++

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/addendum', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        source_field_id: ctx.addendumFieldId,
        addendum_text: addendumText,
        reason: ctx.addendumReason,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: ADDENDUM_RPC, requireOk: true })
    const ok = env.ok && json.ok && httpStatus === 200
    report.steps.push(
      stepRecord('addendum_post', ok ? 'pass' : 'fail', {
        detail: ok ? `addendum field=${ctx.addendumFieldId}` : env.issues.join('; '),
        route: 'POST /api/source/response-set/addendum',
        rpc: ADDENDUM_RPC,
        http_status: httpStatus,
        key_ids: { addendum_field_id: ctx.addendumFieldId },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  const afterEnvelopes = await readBundle(ctx.responseSetId)

  {
    const result = assertPostAddendumReadState({
      beforeManifestCount: ctx.baselineAddendaCount,
      afterEnvelopes,
      modules,
      ctx,
    })
    report.steps.push(
      stepRecord('addendum_canonical_read', result.ok ? 'pass' : 'fail', {
        detail: result.ok
          ? `addenda=${result.afterCount} effective=${result.actualDisplay}`
          : result.issues.join('; '),
        errors: result.ok ? null : result.issues,
        actual: {
          afterCount: result.afterCount,
          historyHasAddendum: historyHasAddendumEvent(afterEnvelopes.history.body?.data),
        },
      }),
    )
    result.ok ? report.summary.passed++ : report.summary.failed++
  }

  {
    const afterRows = await sql`
      select id, value_text, value_number, value_boolean, value_date, value_datetime, is_submitted
      from public.source_responses
      where response_set_id = ${ctx.responseSetId}::uuid and is_submitted = true
    `
    let preserved = true
    for (const row of afterRows) {
      const prior = ctx.submittedSnapshots?.get(row.id)
      if (prior && prior !== responseValueSnapshot(row)) preserved = false
    }
    const priorCount = ctx.submittedSnapshots?.size ?? 0
    const ok = preserved && afterRows.length >= priorCount
    report.steps.push(
      stepRecord('addendum_submitted_immutable', ok ? 'pass' : 'fail', {
        detail: ok
          ? `${priorCount} prior submitted rows unchanged`
          : 'submitted row mutation detected',
        actual: { priorCount, afterSubmittedCount: afterRows.length },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  {
    const a = await readBundle(ctx.responseSetId)
    const b = await readBundle(ctx.responseSetId)
    const fpA = stableFingerprint(
      modules.normalizeResponseSetDetail(a.detail.body.data),
    )
    const fpB = stableFingerprint(
      modules.normalizeResponseSetDetail(b.detail.body.data),
    )
    const countA = manifestAddendaCount(a.manifest.body)
    const countB = manifestAddendaCount(b.manifest.body)
    const histA = a.history.body?.data?.event_count ?? a.history.body?.data?.events?.length
    const histB = b.history.body?.data?.event_count ?? b.history.body?.data?.events?.length
    const ok =
      fpA === fpB &&
      countA === countB &&
      histA === histB &&
      assertReadApiEnvelope(a.detail.body, 'detail', { requireOk: true }).ok
    report.steps.push(
      stepRecord('addendum_determinism', ok ? 'pass' : 'fail', {
        detail: ok
          ? `stable fingerprint; addenda=${countA}; events=${histA}`
          : `fpMatch=${fpA === fpB} addenda ${countA}/${countB} events ${histA}/${histB}`,
        actual: { fpMatch: fpA === fpB, countA, countB, histA, histB },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  {
    const href = `/source/response-set/${ctx.responseSetId}?organization_id=${orgId}`
    const { httpStatus } = await apiFetch(base, href, { cookieHeader })
    const ok = httpStatus === 200
    report.steps.push(
      stepRecord('addendum_review_route', ok ? 'pass' : 'fail', {
        detail: ok ? `GET ${href} HTTP 200` : `HTTP ${httpStatus}`,
        route: href,
        http_status: httpStatus,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  report.ok = report.summary.failed === 0 && report.summary.blocked === 0
}

async function main() {
  loadEnvFiles()
  const args = parseArgs(process.argv)

  const report = {
    phase: '5.4B',
    mode: args.live ? 'live' : 'planning',
    base_url: args.baseUrl,
    started_at: new Date().toISOString(),
    ok: true,
    summary: { passed: 0, failed: 0, skipped: 0, blocked: 0, planned: 0 },
    steps: [],
    gaps: [],
  }

  const unitOk = runUnitSuite(report)
  if (!unitOk) report.ok = false

  if (!args.live) {
    for (const s of LIVE_STEPS) {
      report.steps.push(
        stepRecord(s.id, 'planned', {
          detail: 'planning — run with --live --organization-id <uuid>',
        }),
      )
      report.summary.planned++
    }
    finish(report)
    return
  }

  requireEnv(['NEXT_PUBLIC_SUPABASE_URL', 'NEXT_PUBLIC_SUPABASE_ANON_KEY', 'DATABASE_URL'])

  if (!args.organizationId || !isUuid(args.organizationId)) {
    report.gaps.push('missing or invalid --organization-id for live mode')
    report.ok = false
    finish(report)
    return
  }

  const sql = await connectPostgres()
  if (!sql) {
    report.gaps.push('DATABASE_URL unavailable')
    report.ok = false
    finish(report)
    return
  }

  let cookieHeader
  try {
    cookieHeader = (
      await signInForCookieHeader(
        process.env.NEXT_PUBLIC_SUPABASE_URL,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
        SYNTHETIC.userA,
      )
    ).cookieHeader
  } catch (e) {
    report.gaps.push(`auth failed: ${e.message}`)
    report.ok = false
    finish(report)
    await sql.end()
    return
  }

  const health = await fetch(args.baseUrl, { redirect: 'manual' }).catch(() => null)
  if (!health) {
    report.gaps.push(`Next.js not reachable at ${args.baseUrl}`)
  }

  try {
    await liveRun(args, report, sql, cookieHeader)
  } finally {
    await sql.end()
  }

  if (!unitOk) report.ok = false
  finish(report)
}

function finish(report) {
  report.finished_at = new Date().toISOString()
  mkdirSync(REPORT_DIR, { recursive: true })
  writeFileSync(REPORT_PATH, JSON.stringify(report, null, 2))
  const { passed, failed, skipped, blocked, planned } = report.summary
  console.log(
    `Phase 5.4B addendum shell E2E [${report.mode}]: pass=${passed} fail=${failed} skip=${skipped} blocked=${blocked} planned=${planned}`,
  )
  console.log(`Report: ${REPORT_PATH}`)
  if (report.gaps.length) console.log('Gaps:', report.gaps.join('; '))
  process.exit(report.ok ? 0 : 1)
}

main().catch((e) => {
  console.error(e)
  process.exit(1)
})

/**
 * Phase 5.5B — Findings action UI E2E.
 *
 *   npm run db:validate-phase55b-findings-action-e2e
 *   npm run db:validate-phase55b-findings-action-e2e:live -- --organization-id ...
 *
 * Report: tmp/runtime-e2e/phase55b-findings-action-e2e-report.json
 */

import { mkdirSync, writeFileSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'
import { loadEnvFiles, requireEnv } from './lib/env.mjs'
import {
  apiFetch,
  assertApiEnvelope,
  isUuid,
  signInForCookieHeader,
  SYNTHETIC,
  stepRecord,
  valueForWidget,
} from './lib/source-api-e2e.mjs'
import { prepareCaptureFixture, WRITE_RPC, pickPrimaryField } from './lib/capture-shell-e2e.mjs'
import { loadFindingsActionModules } from './lib/findings-action-import.mjs'
import { assertReadApiEnvelope, readRoutePath, stableFingerprint } from './lib/read-contract-e2e.mjs'
import {
  ACK_FINDING_RPC,
  CREATE_FINDING_RPC,
  RESOLVE_FINDING_RPC,
  WAIVE_FINDING_RPC,
  assertPostFindingActionRead,
  historyHasSubmitEvent,
  isPostSubmitResponseSet,
  manifestFindingCounts,
  runFindingsActionUnitValidations,
} from './lib/findings-action-e2e.mjs'

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..')
const REPORT_DIR = join(ROOT, 'tmp/runtime-e2e')
const REPORT_PATH = join(REPORT_DIR, 'phase55b-findings-action-e2e-report.json')

const LIVE_STEPS = [
  { id: 'fixture_discover', title: 'Discover fresh procedure_execution' },
  { id: 'fixture_submit', title: 'Open, save required fields, submit' },
  { id: 'fixture_create_findings', title: 'Create findings A (resolve path) and B (waive path)' },
  { id: 'fixture_post_submit_confirm', title: 'Confirm post-submit lane' },
  { id: 'auth_unauthenticated_ack', title: 'Unauthenticated acknowledge rejected' },
  { id: 'auth_wrong_org_ack', title: 'Cross-org acknowledge rejected' },
  { id: 'neg_wrong_org_id', title: 'Wrong organization_id rejected' },
  { id: 'neg_resolve_no_text', title: 'Resolve without text rejected' },
  { id: 'neg_waive_no_reason', title: 'Waive without reason rejected' },
  { id: 'neg_fake_finding_id', title: 'Fake finding_id rejected' },
  { id: 'finding_acknowledge', title: 'Acknowledge finding A' },
  { id: 'finding_acknowledge_read', title: 'Canonical read after acknowledge' },
  { id: 'finding_resolve', title: 'Resolve finding A' },
  { id: 'finding_resolve_read', title: 'Canonical read after resolve' },
  { id: 'neg_invalid_transition', title: 'Acknowledge resolved finding rejected' },
  { id: 'finding_waive', title: 'Waive finding B' },
  { id: 'finding_waive_read', title: 'Canonical read after waive' },
  { id: 'findings_determinism', title: 'Stable findings fingerprint; GET does not mutate counts' },
  { id: 'findings_review_route', title: 'Review page route returns 200' },
]

function parseArgs(argv) {
  const args = {
    live: false,
    baseUrl: process.env.E2E_API_BASE_URL?.trim() || 'http://localhost:3000',
    organizationId: null,
    orgBId: null,
    fresh: true,
  }

  for (let i = 2; i < argv.length; i++) {
    const a = argv[i]
    const next = () => argv[++i]
    if (a === '--live') args.live = true
    else if (a === '--fresh') args.fresh = true
    else if (a === '--no-fresh') args.fresh = false
    else if (a === '--base-url') args.baseUrl = next()
    else if (a === '--organization-id') args.organizationId = next()
    else if (a === '--org-b-id') args.orgBId = next()
    else if (a === '--help' || a === '-h') {
      printHelp()
      process.exit(0)
    } else {
      console.error('Unknown argument:', a)
      printHelp()
      process.exit(1)
    }
  }
  return args
}

function printHelp() {
  console.log(`Phase 5.5B Findings action E2E

Options:
  --live                         HTTP flow (requires npm run dev)
  --base-url <url>
  --organization-id <uuid>       Required for live
  --org-b-id <uuid>              Cross-tenant probe
  --fresh                        Insert new visit + procedure_execution (default)
`)
}

async function connectPostgres() {
  const postgres = (await import('postgres')).default
  const url = process.env.DATABASE_URL_DIRECT || process.env.DATABASE_URL
  if (!url) return null
  return postgres(url, {
    ssl: 'require',
    max: 1,
    prepare: url.includes('pooler') ? false : undefined,
  })
}

async function discoverOrgB(sql) {
  const rows = await sql`
    select id from public.organizations
    where name ilike '%Synthetic Site Beta%'
    limit 1
  `
  return rows[0]?.id ?? null
}

function runUnitSuite(report) {
  const loaded = loadFindingsActionModules()
  const results = runFindingsActionUnitValidations(loaded.capture, loaded.findingActionEligibility)
  for (const r of results) {
    report.steps.push(
      stepRecord(`unit_${r.id}`, r.ok ? 'pass' : 'fail', {
        detail: r.ok ? 'ok' : r.issues.join('; '),
        errors: r.ok ? null : r.issues,
      }),
    )
    if (r.ok) report.summary.passed++
    else report.summary.failed++
  }
  return results.every((r) => r.ok)
}

async function liveRun(args, report, sql, cookieHeader) {
  const base = args.baseUrl
  const orgId = args.organizationId
  const modules = loadFindingsActionModules().capture

  const fixture = await prepareCaptureFixture(sql, orgId, { fresh: args.fresh })
  if (!fixture?.procedureExecutionId || !fixture.studyVersionId) {
    report.steps.push(
      stepRecord('fixture_discover', 'blocked', {
        detail: 'no mutable procedure_execution — use --fresh',
      }),
    )
    report.summary.blocked++
    report.ok = false
    return
  }

  report.steps.push(
    stepRecord('fixture_discover', 'pass', {
      detail: `pe=${fixture.procedureExecutionId}`,
      key_ids: { procedure_execution_id: fixture.procedureExecutionId },
    }),
  )
  report.summary.passed++

  const ctx = {
    responseSetId: fixture.existingResponseSetId,
    fieldId: null,
    responseId: null,
    findingAId: null,
    findingBId: null,
    baselineManifestCounts: null,
  }

  async function readBundle(responseSetId) {
    const [detailRes, manifestRes, historyRes, findingsRes] = await Promise.all([
      apiFetch(base, readRoutePath(responseSetId, 'detail', orgId), { cookieHeader }),
      apiFetch(base, readRoutePath(responseSetId, 'manifest', orgId), { cookieHeader }),
      apiFetch(base, readRoutePath(responseSetId, 'history', orgId), { cookieHeader }),
      apiFetch(base, readRoutePath(responseSetId, 'findings', orgId), { cookieHeader }),
    ])
    return {
      detail: { body: detailRes.json, httpStatus: detailRes.httpStatus },
      manifest: { body: manifestRes.json, httpStatus: manifestRes.httpStatus },
      history: { body: historyRes.json, httpStatus: historyRes.httpStatus },
      findings: { body: findingsRes.json, httpStatus: findingsRes.httpStatus },
    }
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/open', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        study_id: fixture.studyId,
        study_version_id: fixture.studyVersionId,
        study_subject_id: fixture.studySubjectId,
        visit_id: fixture.visitId,
        procedure_execution_id: fixture.procedureExecutionId,
        source_definition_version_id: fixture.sourceDefinitionVersionId,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.OPEN_RPC, requireOk: true })
    ctx.responseSetId = json?.data?.source_response_set_id ?? ctx.responseSetId
    if (!env.ok || httpStatus !== 200 || !isUuid(ctx.responseSetId)) {
      report.steps.push(stepRecord('fixture_submit', 'fail', { detail: 'open failed' }))
      report.summary.failed++
      report.ok = false
      return
    }
  }

  let envelopes = await readBundle(ctx.responseSetId)
  const primary = pickPrimaryField(envelopes.detail.body.data)
  ctx.fieldId = primary?.source_field_id

  const requiredPayload = (envelopes.detail.body.data.fields ?? [])
    .filter((f) => f.is_required)
    .map((f) => ({
      source_field_id: f.source_field_id,
      ...valueForWidget(f.widget_hint ?? 'text'),
    }))

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/save-draft', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        responses: requiredPayload,
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.SAVE_RPC, requireOk: true })
    if (!env.ok || httpStatus !== 200) {
      report.steps.push(stepRecord('fixture_submit', 'fail', { detail: 'save-draft failed' }))
      report.summary.failed++
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)
  const current = envelopes.detail.body.data?.fields?.find(
    (f) => f.source_field_id === ctx.fieldId,
  )
  ctx.responseId = current?.current_effective?.response_id ?? null

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/response-set/submit', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        submit_reason: 'phase55b findings action e2e',
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WRITE_RPC.SUBMIT_RPC, requireOk: true })
    const ok = env.ok && httpStatus === 200
    report.steps.push(
      stepRecord('fixture_submit', ok ? 'pass' : 'fail', {
        detail: ok ? `submitted set=${ctx.responseSetId}` : 'submit failed',
        key_ids: { response_set_id: ctx.responseSetId, response_id: ctx.responseId },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)

  {
    const createA = await apiFetch(base, '/api/source/findings/create', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        finding_type: 'required',
        severity: 'warning',
        finding_text: 'phase55b e2e finding A resolve path',
        rule_reference: 'E2E_55B_RESOLVE',
      },
    })
    const envA = assertApiEnvelope(createA.json, {
      expectedRpc: CREATE_FINDING_RPC,
      requireOk: true,
    })
    ctx.findingAId = createA.json?.data?.finding_id

    const createB = await apiFetch(base, '/api/source/findings/create', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        source_response_set_id: ctx.responseSetId,
        finding_type: 'range',
        severity: 'info',
        finding_text: 'phase55b e2e finding B waive path',
        rule_reference: 'E2E_55B_WAIVE',
      },
    })
    const envB = assertApiEnvelope(createB.json, {
      expectedRpc: CREATE_FINDING_RPC,
      requireOk: true,
    })
    ctx.findingBId = createB.json?.data?.finding_id

    const ok =
      envA.ok &&
      createA.json.ok &&
      envB.ok &&
      createB.json.ok &&
      isUuid(ctx.findingAId) &&
      isUuid(ctx.findingBId)
    report.steps.push(
      stepRecord('fixture_create_findings', ok ? 'pass' : 'fail', {
        detail: ok ? `A=${ctx.findingAId} B=${ctx.findingBId}` : 'create findings failed',
        key_ids: { finding_a_id: ctx.findingAId, finding_b_id: ctx.findingBId },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  const actor = await sql`
    select id from auth.users where email = ${SYNTHETIC.userA.email} limit 1
  `
  if (actor[0]?.id && fixture.studyId) {
    await sql`
      insert into public.study_members (study_id, user_id, role)
      values (${fixture.studyId}::uuid, ${actor[0].id}::uuid, 'coordinator')
      on conflict (study_id, user_id) do update set role = excluded.role
    `
  }

  envelopes = await readBundle(ctx.responseSetId)
  ctx.baselineManifestCounts = manifestFindingCounts(envelopes.manifest.body)

  {
    const postSubmit = isPostSubmitResponseSet(
      envelopes.detail.body.data,
      envelopes.manifest.body,
    )
    const ok =
      postSubmit &&
      historyHasSubmitEvent(envelopes.history.body?.data) &&
      ctx.baselineManifestCounts.total >= 2
    report.steps.push(
      stepRecord('fixture_post_submit_confirm', ok ? 'pass' : 'fail', {
        detail: ok
          ? `post-submit; findings_total=${ctx.baselineManifestCounts.total}`
          : 'post-submit or findings count check failed',
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/acknowledge', {
      method: 'POST',
      body: {
        organization_id: orgId,
        finding_id: ctx.findingAId,
        comment: 'no auth',
      },
    })
    const rejected = httpStatus === 401 && json?.ok === false
    report.steps.push(
      stepRecord('auth_unauthenticated_ack', rejected ? 'pass' : 'fail', {
        detail: rejected ? `HTTP ${httpStatus}` : `expected 401 got ${httpStatus}`,
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  let orgB = args.orgBId
  if (!orgB) orgB = await discoverOrgB(sql)
  if (orgB && orgB !== orgId) {
    const cookieB = (
      await signInForCookieHeader(
        process.env.NEXT_PUBLIC_SUPABASE_URL,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
        SYNTHETIC.userB,
      )
    ).cookieHeader
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/acknowledge', {
      method: 'POST',
      cookieHeader: cookieB,
      body: {
        organization_id: orgId,
        finding_id: ctx.findingAId,
        comment: 'wrong org cookie',
      },
    })
    const denied = (httpStatus === 403 || httpStatus === 401) && json?.ok === false
    report.steps.push(
      stepRecord('auth_wrong_org_ack', denied ? 'pass' : 'fail', {
        detail: denied ? `forbidden http=${httpStatus}` : `expected 403/401 got ${httpStatus}`,
        http_status: httpStatus,
      }),
    )
    denied ? report.summary.passed++ : report.summary.failed++
  } else {
    report.steps.push(stepRecord('auth_wrong_org_ack', 'skip', { detail: 'org B not available' }))
    report.summary.skipped++
  }

  if (orgB && orgB !== orgId) {
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/acknowledge', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgB,
        finding_id: ctx.findingAId,
        comment: 'wrong org in body',
      },
    })
    const rejected =
      json?.ok === false && (httpStatus === 403 || httpStatus === 404 || httpStatus === 400)
    report.steps.push(
      stepRecord('neg_wrong_org_id', rejected ? 'pass' : 'fail', {
        detail: rejected ? `rejected http=${httpStatus}` : 'expected rejection',
        http_status: httpStatus,
        actual: json?.code,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  } else {
    report.steps.push(stepRecord('neg_wrong_org_id', 'skip', { detail: 'org B not available' }))
    report.summary.skipped++
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/resolve', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        finding_id: ctx.findingAId,
        resolution_text: '   ',
      },
    })
    const rejected = httpStatus === 400 && json?.ok === false && json?.code === 'INVALID_REQUEST'
    report.steps.push(
      stepRecord('neg_resolve_no_text', rejected ? 'pass' : 'fail', {
        detail: rejected ? 'INVALID_REQUEST' : JSON.stringify(json?.code),
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/waive', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        finding_id: ctx.findingBId,
        waiver_reason: '   ',
      },
    })
    const rejected = httpStatus === 400 && json?.ok === false && json?.code === 'INVALID_REQUEST'
    report.steps.push(
      stepRecord('neg_waive_no_reason', rejected ? 'pass' : 'fail', {
        detail: rejected ? 'INVALID_REQUEST' : JSON.stringify(json?.code),
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  {
    const fakeId = '00000000-0000-4000-8000-000000000099'
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/acknowledge', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        finding_id: fakeId,
        comment: 'fake',
      },
    })
    const rejected = json?.ok === false && httpStatus >= 400
    report.steps.push(
      stepRecord('neg_fake_finding_id', rejected ? 'pass' : 'fail', {
        detail: rejected ? `rejected http=${httpStatus} code=${json?.code}` : 'expected failure',
        http_status: httpStatus,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/acknowledge', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        finding_id: ctx.findingAId,
        comment: 'phase55b e2e acknowledge',
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: ACK_FINDING_RPC, requireOk: true })
    const ok = env.ok && json.ok && httpStatus === 200
    report.steps.push(
      stepRecord('finding_acknowledge', ok ? 'pass' : 'fail', {
        detail: ok ? 'acknowledged finding A' : env.issues.join('; '),
        rpc: ACK_FINDING_RPC,
        http_status: httpStatus,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)
  {
    const result = assertPostFindingActionRead({
      envelopes,
      modules,
      findingId: ctx.findingAId,
      expectedStatus: 'acknowledged',
      expectedEligibility: { canAcknowledge: false, canResolve: true, canWaive: true },
    })
    report.steps.push(
      stepRecord('finding_acknowledge_read', result.ok ? 'pass' : 'fail', {
        detail: result.ok ? 'acknowledged read contract ok' : result.issues.join('; '),
        errors: result.ok ? null : result.issues,
      }),
    )
    result.ok ? report.summary.passed++ : report.summary.failed++
    if (!result.ok) {
      report.ok = false
      return
    }
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/resolve', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        finding_id: ctx.findingAId,
        resolution_text: 'phase55b e2e resolved',
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: RESOLVE_FINDING_RPC, requireOk: true })
    const ok = env.ok && json.ok && httpStatus === 200
    report.steps.push(
      stepRecord('finding_resolve', ok ? 'pass' : 'fail', {
        detail: ok
          ? 'resolved finding A'
          : `${env.issues.join('; ') || json?.code} ${json?.errors?.[0]?.message ?? ''}`.trim(),
        rpc: RESOLVE_FINDING_RPC,
        http_status: httpStatus,
        actual: json,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)
  {
    const result = assertPostFindingActionRead({
      envelopes,
      modules,
      findingId: ctx.findingAId,
      expectedStatus: 'resolved',
      expectedEligibility: { canAcknowledge: false, canResolve: false, canWaive: false },
    })
    report.steps.push(
      stepRecord('finding_resolve_read', result.ok ? 'pass' : 'fail', {
        detail: result.ok ? 'resolved read contract ok' : result.issues.join('; '),
        errors: result.ok ? null : result.issues,
      }),
    )
    result.ok ? report.summary.passed++ : report.summary.failed++
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/acknowledge', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        finding_id: ctx.findingAId,
        comment: 'should not ack resolved',
      },
    })
    const rejected = json?.ok === false && httpStatus >= 400
    report.steps.push(
      stepRecord('neg_invalid_transition', rejected ? 'pass' : 'fail', {
        detail: rejected
          ? `invalid transition rejected http=${httpStatus} code=${json?.code}`
          : 'expected RPC rejection on resolved finding',
        http_status: httpStatus,
        actual: json?.code,
      }),
    )
    rejected ? report.summary.passed++ : report.summary.failed++
  }

  {
    const { json, httpStatus } = await apiFetch(base, '/api/source/findings/waive', {
      method: 'POST',
      cookieHeader,
      body: {
        organization_id: orgId,
        finding_id: ctx.findingBId,
        waiver_reason: 'phase55b e2e waiver — documented exception',
      },
    })
    const env = assertApiEnvelope(json, { expectedRpc: WAIVE_FINDING_RPC, requireOk: true })
    const ok = env.ok && json.ok && httpStatus === 200
    report.steps.push(
      stepRecord('finding_waive', ok ? 'pass' : 'fail', {
        detail: ok ? 'waived finding B' : env.issues.join('; '),
        rpc: WAIVE_FINDING_RPC,
        http_status: httpStatus,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
    if (!ok) {
      report.ok = false
      return
    }
  }

  envelopes = await readBundle(ctx.responseSetId)
  {
    const result = assertPostFindingActionRead({
      envelopes,
      modules,
      findingId: ctx.findingBId,
      expectedStatus: 'waived',
      expectedEligibility: { canAcknowledge: false, canResolve: false, canWaive: false },
    })
    report.steps.push(
      stepRecord('finding_waive_read', result.ok ? 'pass' : 'fail', {
        detail: result.ok ? 'waived read contract ok' : result.issues.join('; '),
        errors: result.ok ? null : result.issues,
      }),
    )
    result.ok ? report.summary.passed++ : report.summary.failed++
  }

  {
    const a = await readBundle(ctx.responseSetId)
    const b = await readBundle(ctx.responseSetId)
    const fpA = stableFingerprint(
      modules.normalizeFindingsPanel(
        a.findings.body.data,
        ctx.responseSetId,
        orgId,
        a.findings.body.data?.filters_applied ?? {},
      ),
    )
    const fpB = stableFingerprint(
      modules.normalizeFindingsPanel(
        b.findings.body.data,
        ctx.responseSetId,
        orgId,
        b.findings.body.data?.filters_applied ?? {},
      ),
    )
    const countsA = manifestFindingCounts(a.manifest.body)
    const countsB = manifestFindingCounts(b.manifest.body)
    const histA = a.history.body?.data?.event_count ?? a.history.body?.data?.events?.length
    const histB = b.history.body?.data?.event_count ?? b.history.body?.data?.events?.length
    const ok =
      fpA === fpB &&
      countsA.total === countsB.total &&
      countsA.open === countsB.open &&
      histA === histB &&
      assertReadApiEnvelope(a.findings.body, 'findings', { requireOk: true }).ok
    report.steps.push(
      stepRecord('findings_determinism', ok ? 'pass' : 'fail', {
        detail: ok
          ? `stable findings fp; total=${countsA.total}; events=${histA}`
          : `fp=${fpA === fpB} counts/open ${countsA.total}/${countsB.total} events ${histA}/${histB}`,
        actual: { fpMatch: fpA === fpB, countsA, countsB, histA, histB },
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  {
    const href = `/source/response-set/${ctx.responseSetId}?organization_id=${orgId}`
    const { httpStatus } = await apiFetch(base, href, { cookieHeader })
    const ok = httpStatus === 200
    report.steps.push(
      stepRecord('findings_review_route', ok ? 'pass' : 'fail', {
        detail: ok ? `GET ${href} HTTP 200` : `HTTP ${httpStatus}`,
        route: href,
        http_status: httpStatus,
      }),
    )
    ok ? report.summary.passed++ : report.summary.failed++
  }

  report.ok = report.summary.failed === 0 && report.summary.blocked === 0
}

async function main() {
  loadEnvFiles()
  const args = parseArgs(process.argv)

  const report = {
    phase: '5.5B',
    mode: args.live ? 'live' : 'planning',
    base_url: args.baseUrl,
    started_at: new Date().toISOString(),
    ok: true,
    summary: { passed: 0, failed: 0, skipped: 0, blocked: 0, planned: 0 },
    steps: [],
    gaps: [],
  }

  const unitOk = runUnitSuite(report)
  if (!unitOk) report.ok = false

  if (!args.live) {
    for (const s of LIVE_STEPS) {
      report.steps.push(
        stepRecord(s.id, 'planned', {
          detail: 'planning — run with --live --organization-id <uuid>',
        }),
      )
      report.summary.planned++
    }
    finish(report)
    return
  }

  requireEnv(['NEXT_PUBLIC_SUPABASE_URL', 'NEXT_PUBLIC_SUPABASE_ANON_KEY', 'DATABASE_URL'])

  if (!args.organizationId || !isUuid(args.organizationId)) {
    report.gaps.push('missing or invalid --organization-id for live mode')
    report.ok = false
    finish(report)
    return
  }

  const sql = await connectPostgres()
  if (!sql) {
    report.gaps.push('DATABASE_URL unavailable')
    report.ok = false
    finish(report)
    return
  }

  let cookieHeader
  try {
    cookieHeader = (
      await signInForCookieHeader(
        process.env.NEXT_PUBLIC_SUPABASE_URL,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
        SYNTHETIC.userA,
      )
    ).cookieHeader
  } catch (e) {
    report.gaps.push(`auth failed: ${e.message}`)
    report.ok = false
    finish(report)
    await sql.end()
    return
  }

  const health = await fetch(args.baseUrl, { redirect: 'manual' }).catch(() => null)
  if (!health) {
    report.gaps.push(`Next.js not reachable at ${args.baseUrl}`)
  }

  try {
    await liveRun(args, report, sql, cookieHeader)
  } finally {
    await sql.end()
  }

  if (!unitOk) report.ok = false
  finish(report)
}

function finish(report) {
  report.finished_at = new Date().toISOString()
  mkdirSync(REPORT_DIR, { recursive: true })
  writeFileSync(REPORT_PATH, JSON.stringify(report, null, 2))
  const { passed, failed, skipped, blocked, planned } = report.summary
  console.log(
    `Phase 5.5B findings action E2E [${report.mode}]: pass=${passed} fail=${failed} skip=${skipped} blocked=${blocked} planned=${planned}`,
  )
  console.log(`Report: ${REPORT_PATH}`)
  if (report.gaps.length) console.log('Gaps:', report.gaps.join('; '))
  process.exit(report.ok ? 0 : 1)
}

main().catch((e) => {
  console.error(e)
  process.exit(1)
})

/**
 * Phase 5.6A — Combined post-submit writes regression runner.
 *
 * Orchestrates existing harnesses (no logic duplication):
 *   - 5.3B correction shell E2E
 *   - 5.4B addendum shell E2E
 *   - 5.5B findings action E2E
 *
 *   npm run db:validate-phase56a-post-submit-writes-e2e
 *   npm run db:validate-phase56a-post-submit-writes-e2e:live -- --organization-id ...
 *
 * Combined report: tmp/runtime-e2e/phase56a-post-submit-writes-e2e-report.json
 */

import { spawnSync } from 'node:child_process'
import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..')
const REPORT_DIR = join(ROOT, 'tmp/runtime-e2e')
const COMBINED_REPORT_PATH = join(REPORT_DIR, 'phase56a-post-submit-writes-e2e-report.json')

const PHASES = [
  {
    key: 'correction',
    phase: '5.3B',
    title: 'Post-submit correction shell',
    script: 'validate-phase53b-correction-shell-e2e.mjs',
    reportFile: 'phase53b-correction-shell-e2e-report.json',
  },
  {
    key: 'addendum',
    phase: '5.4B',
    title: 'Post-submit addendum shell',
    script: 'validate-phase54b-addendum-shell-e2e.mjs',
    reportFile: 'phase54b-addendum-shell-e2e-report.json',
  },
  {
    key: 'findings',
    phase: '5.5B',
    title: 'Findings lifecycle actions',
    script: 'validate-phase55b-findings-action-e2e.mjs',
    reportFile: 'phase55b-findings-action-e2e-report.json',
  },
]

function parseArgs(argv) {
  const args = {
    live: false,
    baseUrl: process.env.E2E_API_BASE_URL?.trim() || 'http://localhost:3000',
    organizationId: null,
    orgBId: null,
    fresh: true,
  }

  for (let i = 2; i < argv.length; i++) {
    const a = argv[i]
    const next = () => argv[++i]
    if (a === '--live') args.live = true
    else if (a === '--fresh') args.fresh = true
    else if (a === '--no-fresh') args.fresh = false
    else if (a === '--base-url') args.baseUrl = next()
    else if (a === '--organization-id') args.organizationId = next()
    else if (a === '--org-b-id') args.orgBId = next()
    else if (a === '--help' || a === '-h') {
      printHelp()
      process.exit(0)
    } else {
      console.error('Unknown argument:', a)
      printHelp()
      process.exit(1)
    }
  }
  return args
}

function printHelp() {
  console.log(`Phase 5.6A Post-submit writes regression runner

Runs correction (5.3B), addendum (5.4B), and findings (5.5B) harnesses sequentially.

Options:
  --live                         Pass --live to each child harness
  --base-url <url>               Forward to children (default http://localhost:3000)
  --organization-id <uuid>       Required for live mode
  --org-b-id <uuid>              Cross-tenant probe (forwarded)
  --fresh                        Fresh procedure_execution per harness (default)
  --no-fresh                     Reuse discovery semantics from child harnesses

Examples:
  npm run db:validate-phase56a-post-submit-writes-e2e
  npm run db:validate-phase56a-post-submit-writes-e2e:live -- \\
    --organization-id <uuid> --base-url http://localhost:3001
`)
}

function buildChildArgv(args) {
  const childArgv = []
  if (args.live) childArgv.push('--live')
  if (args.fresh) childArgv.push('--fresh')
  else childArgv.push('--no-fresh')
  if (args.baseUrl) childArgv.push('--base-url', args.baseUrl)
  if (args.organizationId) childArgv.push('--organization-id', args.organizationId)
  if (args.orgBId) childArgv.push('--org-b-id', args.orgBId)
  return childArgv
}

function readChildReport(reportPath) {
  if (!existsSync(reportPath)) return null
  try {
    return JSON.parse(readFileSync(reportPath, 'utf8'))
  } catch {
    return null
  }
}

function collectBlockingDefects(childReport, exitCode) {
  const defects = []
  if (exitCode !== 0) {
    defects.push({
      type: 'exit_code',
      detail: `child process exit code ${exitCode}`,
    })
  }
  for (const gap of childReport?.gaps ?? []) {
    defects.push({ type: 'gap', detail: gap })
  }
  for (const step of childReport?.steps ?? []) {
    if (step.status !== 'fail') continue
    defects.push({
      type: 'step',
      step: step.step ?? step.id,
      detail: step.detail ?? null,
      route: step.route ?? null,
      http_status: step.http_status ?? null,
      expected: step.expected ?? null,
      actual: step.actual ?? null,
      errors: step.errors ?? null,
    })
  }
  return defects
}

function sumSummary(target, source) {
  if (!source) return
  target.passed += source.passed ?? 0
  target.failed += source.failed ?? 0
  target.skipped += source.skipped ?? 0
  target.blocked += source.blocked ?? 0
  target.planned += source.planned ?? 0
}

function runChildHarness(phase, args) {
  const scriptPath = join(ROOT, 'scripts', phase.script)
  const reportPath = join(REPORT_DIR, phase.reportFile)
  const childArgv = buildChildArgv(args)

  console.log(`\n--- Phase ${phase.phase} ${phase.key}: ${phase.title} ---`)
  console.log(`> node scripts/${phase.script} ${childArgv.join(' ')}\n`)

  const result = spawnSync(process.execPath, [scriptPath, ...childArgv], {
    cwd: ROOT,
    stdio: 'inherit',
    env: process.env,
  })

  const childReport = readChildReport(reportPath)
  const exitCode = result.status ?? 1
  const blockingDefects = collectBlockingDefects(childReport, exitCode)
  const ok =
    exitCode === 0 &&
    blockingDefects.length === 0 &&
    (childReport?.ok !== false || childReport == null)

  return {
    phase: phase.phase,
    key: phase.key,
    title: phase.title,
    script: phase.script,
    ok,
    exit_code: exitCode,
    signal: result.signal ?? null,
    report_path: reportPath,
    report_exists: existsSync(reportPath),
    mode: childReport?.mode ?? (args.live ? 'live' : 'planning'),
    summary: childReport?.summary ?? null,
    gaps: childReport?.gaps ?? [],
    blocking_defects: blockingDefects,
    child_report: childReport
      ? {
          phase: childReport.phase,
          ok: childReport.ok,
          started_at: childReport.started_at,
          finished_at: childReport.finished_at,
        }
      : null,
  }
}

function finish(report) {
  report.finished_at = new Date().toISOString()
  mkdirSync(REPORT_DIR, { recursive: true })
  writeFileSync(COMBINED_REPORT_PATH, JSON.stringify(report, null, 2))

  const { passed, failed, skipped, blocked, planned, phases_ok, phases_failed } =
    report.summary

  console.log('\n=== Phase 5.6A post-submit writes regression ===')
  for (const p of report.phases) {
    const s = p.summary
    const counts = s
      ? `pass=${s.passed} fail=${s.failed} skip=${s.skipped} blocked=${s.blocked} planned=${s.planned}`
      : 'no child summary'
    console.log(
      `  ${p.phase} ${p.key}: ${p.ok ? 'PASS' : 'FAIL'} (${counts}) → ${p.report_path}`,
    )
  }
  console.log(
    `\nTotal: pass=${passed} fail=${failed} skip=${skipped} blocked=${blocked} planned=${planned} | phases ok=${phases_ok} failed=${phases_failed}`,
  )
  console.log(`Combined report: ${COMBINED_REPORT_PATH}`)

  if (report.blocking_defects.length) {
    console.log('\nBlocking defects:')
    for (const d of report.blocking_defects) {
      const loc = d.phase ? `[${d.phase} ${d.key}] ` : ''
      if (d.type === 'step') {
        console.log(`  - ${loc}${d.step}: ${d.detail ?? 'failed'}`)
      } else {
        console.log(`  - ${loc}${d.type}: ${d.detail}`)
      }
    }
  }
}

async function main() {
  const args = parseArgs(process.argv)
  const startedAt = new Date().toISOString()

  const report = {
    phase: '5.6A',
    mode: args.live ? 'live' : 'planning',
    base_url: args.baseUrl,
    organization_id: args.organizationId,
    fresh: args.fresh,
    started_at: startedAt,
    ok: true,
    summary: {
      passed: 0,
      failed: 0,
      skipped: 0,
      blocked: 0,
      planned: 0,
      phases_ok: 0,
      phases_failed: 0,
    },
    phases: [],
    blocking_defects: [],
    report_paths: {
      combined: COMBINED_REPORT_PATH,
      correction: join(REPORT_DIR, PHASES[0].reportFile),
      addendum: join(REPORT_DIR, PHASES[1].reportFile),
      findings: join(REPORT_DIR, PHASES[2].reportFile),
    },
  }

  for (const phase of PHASES) {
    const result = runChildHarness(phase, args)
    const { child_report: _omit, ...phaseEntry } = result
    report.phases.push(phaseEntry)

    sumSummary(report.summary, result.summary)
    if (result.ok) report.summary.phases_ok++
    else {
      report.summary.phases_failed++
      report.ok = false
      for (const defect of result.blocking_defects) {
        report.blocking_defects.push({
          phase: result.phase,
          key: result.key,
          ...defect,
        })
      }
    }
  }

  finish(report)
  process.exit(report.ok ? 0 : 1)
}

main().catch((e) => {
  console.error(e)
  process.exit(1)
})

