record('aggregator dual mode', aggregatorTs.includes("'rpc'") && aggregatorTs.includes("'fallback'") ? 'PASS' : 'FAIL')
record('VPI_USE_RPC flag', aggregatorTs.includes('VPI_USE_RPC') ? 'PASS' : 'FAIL')
