const FORBIDDEN_CHART_LIBS = ['recharts', 'chart.js', 'react-chartjs-2', 'victory', 'nivo', '@visx/', 'echarts', 'plotly.js']
const perfFiles = walkTsFiles(join(projectRoot, 'app/(ops)/performance'))
let chartHit = false
for (const file of perfFiles) {
